-- Poems batch 39
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('69d87b1e-7b47-4cb9-8522-68896e274626','牡丹','羅鄴','唐','唐诗','tang','','[]','落盡春紅始著花，花時比屋事豪奢。',64,'全唐诗/poet.tang.36000.json','["落盡春紅始著花，花時比屋事豪奢。", "買栽池館恐無地，看到子孫能幾家。", "門倚長衢攢繡轂，幄籠輕日護香霞。", "歌鐘滿座爭歡賞，肯信流年鬢有華。"]'),
('ab88c86d-b340-4c1f-9ae0-a788e0f52201','長城','羅鄴','唐','唐诗','tang','','[]','當時無德御乾坤，廣築徒勞萬古存。',64,'全唐诗/poet.tang.36000.json','["當時無德御乾坤，廣築徒勞萬古存。", "謾役生民防極塞，不知血刃起中原。", "珠璣旋見陪陵寢，社稷何曾保子孫。", "降虜至今猶自說，冤聲夜夜傍城根。"]'),
('47e46e33-41a7-4871-9ce9-9519ad774e58','秋夕寄友人','羅鄴','唐','唐诗','tang','','[]','秋夕蒼茫一雁過，西風白露滿宮莎。',64,'全唐诗/poet.tang.36000.json','["秋夕蒼茫一雁過，西風白露滿宮莎。", "昨來京洛逢歸客，猶說軒車未渡河。", "莫把少年空倚賴，須知孤立易蹉跎。", "想君懷抱哀吟夜，銅雀臺前皓月多。"]'),
('c1fc353c-ead2-4f94-9245-b8b58d4e4e5e','冬夕江上言事五首 一','羅鄴','唐','唐诗','tang','','[]','葉落纔悲草又生，看看少壯是衰形。',64,'全唐诗/poet.tang.36000.json','["葉落纔悲草又生，看看少壯是衰形。", "關中秋雨書難到，江上春寒酒易醒。", "多少繫心身未達，尋思舉目淚堪零。", "幾時拋得歸山去，松下看雲讀道經。"]'),
('5d8701fe-8420-4a91-8ad5-6fe35cc6bf60','冬夕江上言事五首 二','羅鄴','唐','唐诗','tang','','[]','喔喔晨雞滿樹霜，喧喧曉渡簇舟航。',64,'全唐诗/poet.tang.36000.json','["喔喔晨雞滿樹霜，喧喧曉渡簇舟航。", "數星昨夜寒爐火，一陣誰家臘甕香。", "久別羇孤成潦倒，迴看書劒更蒼黃。", "逢人舉止皆言命，至竟謀閑可勝忙。"]'),
('dfa27e22-0888-4a02-8764-e2bbb54cec79','冬夕江上言事五首 三','羅鄴','唐','唐诗','tang','','[]','野堂吟罷獨行行，點水微微凍不鳴。',64,'全唐诗/poet.tang.36000.json','["野堂吟罷獨行行，點水微微凍不鳴。", "十里溪山新雪後，千家襟袖曉寒生。", "只宜醉夢依華寢，可稱羸蹄赴宿程。", "日苦幾多心下見，那堪歲晏又無成。"]'),
('74d46eeb-c751-4981-a240-8972e4587f3f','冬夕江上言事五首 四','羅鄴','唐','唐诗','tang','','[]','僻居多與懶相宜，吟擁寒爐過臘時。',64,'全唐诗/poet.tang.36000.json','["僻居多與懶相宜，吟擁寒爐過臘時。", "風柳欲生陽面葉，凍梅先綻嶺頭枝。", "山川自小拋耕釣，骨肉無因免別離。", "賴有陶情一尊酒，愁中相向展愁眉。"]'),
('1c905516-4089-4fdd-accc-887af08a78e9','冬夕江上言事五首 五','羅鄴','唐','唐诗','tang','','[]','一帶長溪淥浸門，數聲幽鳥啄雲根。',32,'全唐诗/poet.tang.36000.json','["一帶長溪淥浸門，數聲幽鳥啄雲根。", "松亭盡日唯空坐，難得儒翁共討論。"]'),
('eb07ad37-32ab-4b4c-967d-0f990ef02e9e','春日宿崇賢里','羅鄴','唐','唐诗','tang','','[]','柳暗榆飛春日深，水邊門巷獨來尋。',64,'全唐诗/poet.tang.36000.json','["柳暗榆飛春日深，水邊門巷獨來尋。", "舊山共是經年別，新句相逢竟夕吟。", "枕近禁街聞曉鼓，月當高竹見棲禽。", "勞歌莫問秋風計，恐起江河垂釣心。"]'),
('3975bb78-6a18-4c1c-9809-bcc18ca99917','征人','羅鄴','唐','唐诗','tang','','[]','青樓一別戍金微，力盡秋來破虜圍。',64,'全唐诗/poet.tang.36000.json','["青樓一別戍金微，力盡秋來破虜圍。", "錦字莫辭連夜織，塞鴻常是到春歸。", "正憐漢月當空照，不奈胡沙滿眼飛。", "唯有夢魂南去日，故鄉山水路依稀。"]'),
('dd064c9b-59c3-4bc2-a97d-c1e2f0d298c3','鶯','羅鄴','唐','唐诗','tang','','[]','暖辭雲谷背殘陽，飛下東風翅漸長。',64,'全唐诗/poet.tang.36000.json','["暖辭雲谷背殘陽，飛下東風翅漸長。", "却笑金籠是羈絆，豈知瑤草正芬芳。", "曉逢溪雨投紅樹，晚囀宮樓泣舊妝。", "何事離人不堪聽，灞橋斜日褭垂楊。"]'),
('5d417588-0e6c-438c-93a5-5afab29e5bc4','槐花','羅鄴','唐','唐诗','tang','','[]','行宮門外陌銅駝，兩畔分栽此最多。',64,'全唐诗/poet.tang.36000.json','["行宮門外陌銅駝，兩畔分栽此最多。", "欲到清秋近時節，爭開金蘂向關河。", "層樓寄恨飄珠箔，駿馬憐香撼玉珂。", "愁殺江湖隨計者，年年爲爾剩奔波。"]'),
('4d8301fd-9f94-46d0-b981-2d2eb97b18e4','自蜀入關','羅鄴','唐','唐诗','tang','','[]','文戰連輸未息機，束書攜劒定前非。',64,'全唐诗/poet.tang.36000.json','["文戰連輸未息機，束書攜劒定前非。", "近來從聽事難得，休去且無山可歸。", "匹馬出門還悵望，孤雲何處是因依？", "斜陽驛路西風緊，遙指人煙宿翠微。"]'),
('e5c55939-4440-4283-b269-d17a834c9f7e','上陽宮','羅鄴','唐','唐诗','tang','','[]','春半上陽花滿樓，太平天子昔巡遊。',64,'全唐诗/poet.tang.36000.json','["春半上陽花滿樓，太平天子昔巡遊。", "千門雖對嵩山在，一笑還隨洛水流。", "深鎖笙歌巢燕聽，遙瞻金碧路人愁。", "翠華却自登仙去，腸斷宮娥望不休。"]'),
('91699541-4f7a-48a1-bcc9-ba778bac51c1','舊侯家','羅鄴','唐','唐诗','tang','','[]','臺閣層層倚半空，遶軒澄碧御溝通。',64,'全唐诗/poet.tang.36000.json','["臺閣層層倚半空，遶軒澄碧御溝通。", "金鈿座上歌春酒，畫蠟尊前滴曉風。", "歲月不知成隙地，子孫誰更繫殊功。", "人間若算無榮辱，却是扁舟一釣翁。"]'),
('fd5416bc-02e2-4964-aaf7-916f448a764a','宿武安山有懷','羅鄴','唐','唐诗','tang','','[]','野店暮來山畔逢，寒蕪漠漠露華濃。',64,'全唐诗/poet.tang.36000.json','["野店暮來山畔逢，寒蕪漠漠露華濃。", "窗間燈在犬驚吠，溪上月沈人罷舂。", "遠別只愁添雪鬢，此生何計隱雲峯。", "離心却羨南飛翼，獨過吳江更數重。"]'),
('31dde9b8-5b57-43d0-99d5-328625ccc1ee','謁寗祠','羅鄴','唐','唐诗','tang','','[]','春生溪嶺雪初開，下馬雲亭酹一杯。',64,'全唐诗/poet.tang.36000.json','["春生溪嶺雪初開，下馬雲亭酹一杯。", "好是精靈偏有感，能於鄉里不爲災。", "九江賈客應遙祝，五夜神兵數此來。", "盡室唯求多降福，新年歸去便風催。"]'),
('ca0d3ec6-2e3e-4554-a7e2-4fb0168230e6','經故洛城','羅鄴','唐','唐诗','tang','','[]','一片危牆勢恐人，牆邊日日走蹄輪。',64,'全唐诗/poet.tang.36000.json','["一片危牆勢恐人，牆邊日日走蹄輪。", "築時驅盡千夫力，崩處空爲數里塵。", "長恨往來經此地，每嗟興廢欲霑巾。", "那堪又向荒城過，錦雉驚飛麥隴春。"]'),
('8280e328-d21d-4c8c-bc12-36f1f6fa9aa5','老將','羅鄴','唐','唐诗','tang','','[]','百戰辛勤歸帝鄉，南班班裏最南行。',64,'全唐诗/poet.tang.36000.json','["百戰辛勤歸帝鄉，南班班裏最南行。", "弓欺猨臂秋無力，劒泣虯髯曉有霜。", "千古恥非書玉帛，一心猶自向河湟。", "年年宿衛天顏近，曾把功勳奏建章。"]'),
('bfecb565-4671-4fec-9252-3f368c06acbf','曲江春望','羅鄴','唐','唐诗','tang','','[]','故國東歸澤國遙，曲江晴望憶漁樵。',64,'全唐诗/poet.tang.36000.json','["故國東歸澤國遙，曲江晴望憶漁樵。", "都緣北闕春先到，不是南山雪易消。", "瑞影玉樓開組繡，歡聲丹禁奏雲韶。", "雖然未得陪鴛鷺，亦酹金觴祝帝堯。"]'),
('851a0abb-fb93-494a-9580-89193160bd7d','帝里','羅鄴','唐','唐诗','tang','','[]','喧喧蹄轂走紅塵，南北東西暮與晨。',64,'全唐诗/poet.tang.36000.json','["喧喧蹄轂走紅塵，南北東西暮與晨。", "謾道青雲難得路，何曾紫陌有閑人。", "杯傾竹葉侯門月，馬落桃花御水春。", "只合詠歌來大國，況逢文景化惟新。"]'),
('f8a386a2-41d0-424d-8a7d-700d771115a9','新安城','羅鄴','唐','唐诗','tang','','[]','若筭防邊久遠名，新安豈更勝長城。',64,'全唐诗/poet.tang.36000.json','["若筭防邊久遠名，新安豈更勝長城。", "謾興他役悲荒壘，何似從今實取兵。", "聖德便應同險固，人心自不向忠貞。", "但將死節酬堯禹，版築無勞寇已平。"]'),
('c5ed514b-2c25-4b04-9a1a-48fefddc930d','自遣','羅鄴','唐','唐诗','tang','','[]','四十年來詩酒徒，一生緣興滯江湖。',64,'全唐诗/poet.tang.36000.json','["四十年來詩酒徒，一生緣興滯江湖。", "不愁世上無人識，唯怕村中沒酒沽。", "春巷摘桑喧姹女，江船吹笛舞蠻奴。", "焚魚酌醴醉堯代，吟向席門聊自娛。"]'),
('5031e420-3ead-447a-aa5e-4997510d1168','流水','羅鄴','唐','唐诗','tang','','[]','漾漾悠悠幾派分，中浮短艇與鷗羣。',64,'全唐诗/poet.tang.36000.json','["漾漾悠悠幾派分，中浮短艇與鷗羣。", "天街帶雨淹芳草，玉洞飄花下白雲。", "靜稱一竿持處見，急宜孤館覺來聞。", "隋家柳畔偏堪恨，東入長淮日又曛。"]'),
('976b5330-60d9-4800-83f8-e5bf26a563f5','送張逸人','羅鄴','唐','唐诗','tang','','[]','自說歸山人事賒，素琴丹竈是生涯。',64,'全唐诗/poet.tang.36000.json','["自說歸山人事賒，素琴丹竈是生涯。", "牀頭殘藥鼠偷盡，溪上破門風擺斜。", "石井晴垂青葛葉，竹籬荒映白茅花。", "遙知此去應稀出，獨臥晴窗夢曉霞。"]'),
('12660670-9084-4177-9ede-75e8ebfdebd7','春晚渡河有懷','羅鄴','唐','唐诗','tang','','[]','煙收綠野遠連空，戍壘依稀入望中。',64,'全唐诗/poet.tang.36000.json','["煙收綠野遠連空，戍壘依稀入望中。", "萬里山河星拱北，百年人事水歸東。", "扁舟晚濟桃花浪，走馬晴嘶柳絮風。", "鄉思正多羈思苦，不須迴首問漁翁。"]'),
('6cb66e64-c34a-4ecf-8e44-917e7e72f660','春望梁石頭城','羅鄴','唐','唐诗','tang','','[]','柳碧桑黃破國春，殘陽微雨望歸人。',64,'全唐诗/poet.tang.36000.json','["柳碧桑黃破國春，殘陽微雨望歸人。", "江山不改興亡地，冠蓋自爲前後塵。", "帆勢掛風輕若翅，浪聲吹岸疊如鱗。", "六朝無限悲愁事，欲下荒城迴首頻。"]'),
('eb06b620-a3e1-45f3-a323-2c4bf4e22a4e','早發宜陵即事','羅鄴','唐','唐诗','tang','','[]','霜白山村月落時，一聲雞後又登岐。',64,'全唐诗/poet.tang.36000.json','["霜白山村月落時，一聲雞後又登岐。", "居人猶自掩關在，行客已愁驅馬遲。", "身事不堪空感激，鬢毛看著欲凋衰。", "青萍委匣休哮吼，未有恩讐擬報誰。"]'),
('508074ec-f7cc-4ee4-8c53-fc230ba9c316','鴛鴦','羅鄴','唐','唐诗','tang','','[]','紅閑碧霽瑞煙開，錦翅雙飛去又迴。',64,'全唐诗/poet.tang.36000.json','["紅閑碧霽瑞煙開，錦翅雙飛去又迴。", "一種鳥憐名字好，盡緣人恨別離來。", "暖依牛渚汀莎媚，夕宿龍池禁漏催。", "相對若教春女見，便須攜向鳳凰臺。"]'),
('52d23303-c4b1-4969-b788-89235b2b768f','春閨','羅鄴','唐','唐诗','tang','','[]','愁坐蘭閨日過遲，卷簾巢燕羨雙飛。',64,'全唐诗/poet.tang.36000.json','["愁坐蘭閨日過遲，卷簾巢燕羨雙飛。", "管弦樓上春應在，楊柳橋邊人未歸。", "玉笛豈能留舞態，金河猶自浣戎衣。", "梨花滿院東風急，惆悵無言倚錦機。"]'),
('051c3516-1de6-4771-8530-9de30d651a34','贈東川梓桐縣韋德孫長官','羅鄴','唐','唐诗','tang','','[]','前代高門今宰邑，懷才重義古來無。',64,'全唐诗/poet.tang.36000.json','["前代高門今宰邑，懷才重義古來無。", "笙歌厭聽吟清句，京洛思歸展畫圖。", "蜀醞天寒留容醉，隴禽山曉隔簾呼。", "何年期拜朱幡貴，馬上論詩在九衢。"]'),
('de3347f1-b279-4097-bc9c-4477e2a6b225','題水簾洞','羅鄴','唐','唐诗','tang','','[]','亂泉飛下翠屏中，名共真珠巧綴同。',64,'全唐诗/poet.tang.36000.json','["亂泉飛下翠屏中，名共真珠巧綴同。", "一片長垂今與古，半山遙聽水兼風。", "雖無舒卷隨人意，自有潺湲濟物功。", "每向暑天來往見，疑將仙子隔房櫳。"]'),
('a2beb0ae-77a2-4f57-a018-1e6a4f02a6ef','野花','羅鄴','唐','唐诗','tang','','[]','拂露叢開血色殷，枉無名字對空山。',64,'全唐诗/poet.tang.36000.json','["拂露叢開血色殷，枉無名字對空山。", "時逢舞蝶尋香至，少有行人輟櫂攀。", "若在侯門看不足，爲生江岸見如閑。", "結根畢竟輸桃李，長近都城紫陌間。"]'),
('7f18f909-a424-425e-9e2e-68e30efa8912','蘆花','羅鄴','唐','唐诗','tang','','[]','如練如霜乾復輕，西風處處拂江城。',64,'全唐诗/poet.tang.36000.json','["如練如霜乾復輕，西風處處拂江城。", "長垂釣叟看不足，暫泊王孫愁亦生。", "好傍翠樓裝月色，枉隨紅葉舞秋聲。", "最宜羣鷺斜陽裏，閑捕纖鱗傍爾行。"]'),
('a21e7d1b-c523-4074-b9b8-a6e347eabd15','山陽貽友人','羅鄴','唐','唐诗','tang','','[]','性僻多將雲水便，山陽酒病動經年。',64,'全唐诗/poet.tang.36000.json','["性僻多將雲水便，山陽酒病動經年。", "行遲暖陌花攔馬，睡重春江雨打船。", "閑弄玉琴雙鶴舞，靜窺庭樹一猱懸。", "結茅更莫期深隱，聲價如今滿日邊。"]'),
('ed22ab2e-f86e-4ff2-a378-f32ac8b86455','長安惜春','羅鄴','唐','唐诗','tang','','[]','千門共惜放春迴，半鎖樓臺半復開。',64,'全唐诗/poet.tang.36000.json','["千門共惜放春迴，半鎖樓臺半復開。", "公子不能留落日，南山遮莫倚高臺。", "殘紅似怨皇州雨，細綠猶藏畫蠟灰。", "畢竟思量何足歎，明年時節又還來。"]'),
('705f361b-a16a-4d3b-bd14-ef5850c5f895','謝友人遺華陽巾','羅鄴','唐','唐诗','tang','','[]','剪露[裁]煙勝角冠，來從玉洞五雲端。',66,'全唐诗/poet.tang.36000.json','["剪露[裁]煙勝角冠，來從玉洞五雲端。", "醉宜薤葉欹斜影，穩稱菱花子細看。", "野客愛留籠鶴髪，溪翁爭乞配漁竿。", "真仙首飾勞相寄，塵土飜慙戴去難。"]'),
('334bb3ba-bab6-4664-9807-8329e569c0fd','早梅','羅鄴','唐','唐诗','tang','','[]','綴雪枝條似有情，凌寒澹注笑妝成。',64,'全唐诗/poet.tang.36000.json','["綴雪枝條似有情，凌寒澹注笑妝成。", "凍香飄處宜春早，素豔開時混月明。", "遷客嶺頭悲褭褭，美人簾下妬盈盈。", "滿園桃李雖堪賞，要且東風晚始生。"]'),
('646ec3e5-eb75-4908-8b58-6c0ecf4939db','留題張逸人草堂','羅鄴','唐','唐诗','tang','','[]','長懸青紫與芳枝，塵路無因免別離。',64,'全唐诗/poet.tang.36000.json','["長懸青紫與芳枝，塵路無因免別離。", "馬上多於在家日，尊前堪惜少年時。", "關河客夢還鄉後，雨雪山程出店遲。", "却羨高人此中老，軒車過盡不知誰。"]'),
('d295b8e6-7a12-490d-b8a1-ead122132a81','鍾陵崔大夫罷鎮攀隨再經匡廬寺宿','羅鄴','唐','唐诗','tang','','["\u5e90\u5c71"]','一拋文戰學從公，兩逐旌旗宿梵宮。',64,'全唐诗/poet.tang.36000.json','["一拋文戰學從公，兩逐旌旗宿梵宮。", "酒醒月移窗影畔，夜涼身在水聲中。", "侯門聚散真如夢，花界登臨轉悟空。", "明發不堪山下路，幾程愁雨又愁風。"]'),
('0ab45f3c-d91a-4d66-893f-fa3b82009b9a','留獻彭門郭常侍','羅鄴','唐','唐诗','tang','','[]','受得彭門擁信旗，一家將謂免羈離。',64,'全唐诗/poet.tang.36000.json','["受得彭門擁信旗，一家將謂免羈離。", "到來門館空歸去，羞向交親說受知。", "層構尚無容足地，尺波寧有躍鱗時。", "到頭忍恥求名是，須向青雲覓路岐。"]'),
('0c24d2ba-ff1f-4ee7-884b-c055cbba1e9b','洛水','羅鄴','唐','唐诗','tang','','[]','一道潺湲濺暖莎，年年惆悵是春過。',66,'全唐诗/poet.tang.36000.json','["一道潺湲濺暖莎，年年惆悵是春過。", "莫言行路聽如此，流[入]深宮悵更多。", "橋畔月來清見底，柳邊風緊綠生波。", "縱然滿眼添歸思，未把漁竿奈爾何。"]'),
('005fcf66-fe23-4151-8082-b924a89a6f5a','聞杜鵑','羅鄴','唐','唐诗','tang','','[]','花時一宿碧山前，明月東風呌杜鵑。',64,'全唐诗/poet.tang.36000.json','["花時一宿碧山前，明月東風呌杜鵑。", "孤館覺來聽夜半，羸僮相對亦無眠。", "汝身哀怨猶如此，我淚縱橫豈偶然。", "爭得蒼蒼知有恨，汝身成鶴我成仙。"]'),
('9c2b0437-c081-4c69-a75c-76fb9108a26c','趂職單于留別闕下知己','羅鄴','唐','唐诗','tang','','[]','職忝翩翩逐建牙，笈隨征騎入胡沙。',64,'全唐诗/poet.tang.36000.json','["職忝翩翩逐建牙，笈隨征騎入胡沙。", "定將千里書憑雁，應看三春雪當花。", "年長有心終報國，時清到處便營家。", "逢秋不擬同張翰，爲憶鱸魚却歎嗟。"]'),
('7b52f4e3-1b6c-41d2-b6e0-31ce7cd4041b','落第書懷寄友人','羅鄴','唐','唐诗','tang','','[]','清世誰能便陸沈，相逢休作憶山吟。',64,'全唐诗/poet.tang.36000.json','["清世誰能便陸沈，相逢休作憶山吟。", "若教仙桂在平地，更有何人肯苦心。", "去國漢妃還似玉，亡家石氏豈無金。", "且安懷抱莫惆悵，瑤瑟調高尊酒深。"]'),
('1bccf5e6-9a50-4262-9fa2-253e7ba9b86c','鸚鵡詠','羅鄴','唐','唐诗','tang','','[]','玉檻瑤軒任所依，東風休憶嶺頭歸。',66,'全唐诗/poet.tang.36000.json','["玉檻瑤軒任所依，東風休憶嶺頭歸。", "金[籠]共惜好毛羽，紅觜莫教多是非。", "便向郄堂誇飲啄，還應禰筆發光輝。", "乘時得路何須貴，燕雀鸞鳳各有機。"]'),
('64b3229d-9fd9-4b15-8ade-81af9424ccdb','題滄浪峽','羅鄴','唐','唐诗','tang','','[]','門向紅塵日日開，入門襟袖遠塵埃。',64,'全唐诗/poet.tang.36000.json','["門向紅塵日日開，入門襟袖遠塵埃。", "暗香惹步澗花發，晚景逼簷溪鳥迴。", "不爲市朝行路近，有誰車馬看山來。", "可憐嚴子持竿處，雲水終年鎖綠苔。"]'),
('1f5c5d46-f2bc-4e38-867f-aef2a749b164','白角簟','羅鄴','唐','唐诗','tang','','[]','疊玉駢珪巧思長，露華煙魄讓清光。',64,'全唐诗/poet.tang.36000.json','["疊玉駢珪巧思長，露華煙魄讓清光。", "休搖雉尾當三伏，似展龍鱗在一牀。", "高價不唯標越絕，冷紋疑似臥瀟湘。", "杜陵他日重歸去，偏稱醉眠松桂堂。"]'),
('8cba2bb0-9c8d-46b5-a9aa-3cdd62e93638','秋日懷江上友人','羅鄴','唐','唐诗','tang','','[]','行子豈知煙水勞，西風獨自泛征艘。',64,'全唐诗/poet.tang.36000.json','["行子豈知煙水勞，西風獨自泛征艘。", "酒醒孤館秋簾卷，月滿寒江夜笛高。", "黃葉夢餘歸朔塞，青山家在極波濤。", "去年今日逢君處，雁下蘆花猨正號。"]'),
('96db5981-c596-4f11-b151-d5a989a4a391','題笙','羅鄴','唐','唐诗','tang','','[]','筠管參差排鳳翅，月堂淒切勝龍吟。',64,'全唐诗/poet.tang.36000.json','["筠管參差排鳳翅，月堂淒切勝龍吟。", "最宜輕動纖纖玉，醉送當觀灩灩金。", "緱嶺獨能徵妙曲，嬴臺相共吹清音。", "好將宮徵陪歌扇，莫遣新聲鄭衛侵。"]'),
('5f4d21dc-5107-4aef-a92b-281d5bb8bb5b','下第','羅鄴','唐','唐诗','tang','','[]','謾把青春酒一杯，愁襟未信酒能開。',64,'全唐诗/poet.tang.36000.json','["謾把青春酒一杯，愁襟未信酒能開。", "江邊依舊空歸去，帝里還如不到來。", "門掩殘陽鳴鳥雀，花飛何處好池臺。", "此時惆悵便堪老，何用人間歲月催。"]'),
('957e87f0-e303-4891-9c14-765e7a2dc7c4','秋晚','羅鄴','唐','唐诗','tang','','[]','殘星殘月一聲鐘，谷際巖隈爽氣濃。',64,'全唐诗/poet.tang.36000.json','["殘星殘月一聲鐘，谷際巖隈爽氣濃。", "不向碧臺驚醉夢，但來青鏡促愁容。", "繁金露潔黃籠菊，獨翠煙凝遠澗松。", "閑步幽林與苔徑，漸移栖鳥及鳴蛩。"]'),
('73948339-20a5-4f13-9bc7-8d1f600cb0e5','長安春夕旅懷','羅鄴','唐','唐诗','tang','','[]','幾年栖旅寄西秦，不識花枝醉過春。',64,'全唐诗/poet.tang.36000.json','["幾年栖旅寄西秦，不識花枝醉過春。", "短艇閑思五湖浪，羸蹄愁伴九衢塵。", "關河風雨迷歸夢，鐘鼓朝昏老此身。", "忽向太平時節過，一竿持去老遺民。"]'),
('09145935-0a91-4b06-bc8d-38b09303fb62','洛陽春望','羅鄴','唐','唐诗','tang','','[]','洛陽春霽絕塵埃，嵩少煙嵐畫障開。',64,'全唐诗/poet.tang.36000.json','["洛陽春霽絕塵埃，嵩少煙嵐畫障開。", "草色花光惹襟袖，簫聲歌響隔樓臺。", "人心便覺閑多少，馬足方知倦往來。", "愁上中橋橋上望，碧波東去夕陽催。"]'),
('5c87968f-becc-41e8-945a-59618dac60bb','惜春','羅鄴','唐','唐诗','tang','','[]','燕歸巢後即離羣，吟倚東風恨日曛。',64,'全唐诗/poet.tang.36000.json','["燕歸巢後即離羣，吟倚東風恨日曛。", "一別一年方見我，遊來遊去不禁君。", "鶯花御苑看將盡，絲竹侯家亦少聞。", "獨坐南樓正惆悵，柳塘花絮更紛紛。"]'),
('9c129911-f342-445c-8e8d-acbbee0cd5a6','冬日旅懷','羅鄴','唐','唐诗','tang','','[]','[烏]焰纔沈桂魄生，霜階擁褐暫吟行。',66,'全唐诗/poet.tang.36000.json','["[烏]焰纔沈桂魄生，霜階擁褐暫吟行。", "閑思江市白醪滿，靜憶僧窗綠綺橫。", "塵土自憐長失計，雲帆尤覺有歸情。", "幾多悵望無窮事，空畫爐灰坐到明。"]'),
('3e08b226-1b17-417b-96d8-e2d552b24efb','春夕寄友人時有與歌者南北','羅鄴','唐','唐诗','tang','','[]','芳徑春歸花半開，碧山波暖雁初迴。',64,'全唐诗/poet.tang.36000.json','["芳徑春歸花半開，碧山波暖雁初迴。", "滿樓月色還依舊，昨夜歌聲自不來。", "愁眼向誰零玉筯，征蹄何處駐紅埃？", "中宵吟罷正惆悵，從此蘭堂鎖綠苔。"]'),
('0da9bfac-e088-40d2-bec3-31c7948a0cba','春夜赤水驛旅懷','羅鄴','唐','唐诗','tang','','[]','一星殘燭照離堂，失計遊心歸渺茫。',64,'全唐诗/poet.tang.36000.json','["一星殘燭照離堂，失計遊心歸渺茫。", "不自尋思無道路，爲誰辛苦競時光。", "九衢春色休回首，半夜溪聲正夢鄉。", "却羨去年買山侶，月斜漁艇倚瀟湘。"]'),
('0242bab9-b70e-4a92-9c2b-9bdeb42d5c56','春山山館旅懷','羅鄴','唐','唐诗','tang','','[]','山館吟餘山月斜，東風搖曳拂窗花。',64,'全唐诗/poet.tang.36000.json','["山館吟餘山月斜，東風搖曳拂窗花。", "豈知驅馬無閑日，長在他人後到家。", "孤劒向誰開壯節，流年催我自堪嗟。", "燈前結束又前去，曉出石林啼亂鴉。"]'),
('4e6565e9-cbc3-46c8-9d6d-7e301a0369fa','秋夕旅懷','羅鄴','唐','唐诗','tang','','[]','階前月色與蛩聲，階上愁人坐復行。',64,'全唐诗/poet.tang.36000.json','["階前月色與蛩聲，階上愁人坐復行。", "秦谷入霜空有夢，越山無計可歸耕。", "窮途若遣長堪慟，華髪無因肯晚生。", "不似扁舟釣魚者，免將心事筭浮榮。"]'),
('2f2b0a52-7223-4099-b2cb-62a1e4a46af3','春過白遙嶺','羅鄴','唐','唐诗','tang','','[]','鳥道穿雲望峽遙，羸蹄經宿在岧嶤。',64,'全唐诗/poet.tang.36000.json','["鳥道穿雲望峽遙，羸蹄經宿在岧嶤。", "到來山下春將半，上得林端雪未消。", "返駕王尊何足歎，哭途阮籍謾無聊。", "未知遇此恓惶者，泣向東風鬢欲凋。"]'),
('2ca559ff-b536-4ed0-967d-7f4f4e7723dc','別夜','羅鄴','唐','唐诗','tang','','[]','秋入江天河漢清，迢迢鐘漏出孤城。',64,'全唐诗/poet.tang.36000.json','["秋入江天河漢清，迢迢鐘漏出孤城。", "金波千里別來夜，玉筯兩行流到明。", "若在人間須有恨，除非禪伴始無情。", "人間誰有□□□，聚散自然惆悵生。"]'),
('8dd8e601-a5a7-4b89-93d8-38e8823e2385','費拾遺書堂','羅鄴','唐','唐诗','tang','','[]','滿袖歸來天桂香，紫泥重降舊書堂。',64,'全唐诗/poet.tang.36000.json','["滿袖歸來天桂香，紫泥重降舊書堂。", "自憐葦帶同巢許，不駕蒲輪佐禹湯。", "怪石盡含千古秀，奇花多吐四時芳。", "何人更肯追高躅，唯有樵童戲蘚牀。"]'),
('80d9fadc-f398-48c0-8ce1-ff382746bdf5','溪上春望','羅鄴','唐','唐诗','tang','','[]','無端溪上看蘭橈，又是東風斷柳條。',64,'全唐诗/poet.tang.36000.json','["無端溪上看蘭橈，又是東風斷柳條。", "雙鬢多於愁裏鑷，四時須向醉中銷。", "行人駿馬嘶香陌，獨我殘陽倚野橋。", "吟水詠山心未已，可能終不勝漁樵。"]'),
('8af7baed-0611-45a6-97d6-af6ef63f2680','獻池州庾員外','羅鄴','唐','唐诗','tang','','[]','曾降瑤緘薦姓名，攀雲幾合到蓬瀛。',64,'全唐诗/poet.tang.36000.json','["曾降瑤緘薦姓名，攀雲幾合到蓬瀛。", "須存彭壽千年在，終見茅公九轉成。", "鯤海已知勞鶴使，螢窗不那夢霓旌。", "琪花玉蔓應相笑，未得歌吟從酒行。"]'),
('36c3ee47-4465-4ac4-bc0d-f6de06e6ad55','春風','羅鄴','唐','唐诗','tang','','[]','每歲東來助發生，舞空悠颺徧寰瀛。',64,'全唐诗/poet.tang.36000.json','["每歲東來助發生，舞空悠颺徧寰瀛。", "暗添芳草池塘色，遠遰高樓簫管聲。", "簾透驪宮偏帶恨，花催上苑剩多情。", "如何一瑞車書日，吹取青雲道路平。"]'),
('89341c14-9073-4972-a1b4-d5f3fb6fbdb4','冬日寄獻庾員外','羅鄴','唐','唐诗','tang','','[]','曾謁仙宮最上仙，西風許醉桂花前。',64,'全唐诗/poet.tang.36000.json','["曾謁仙宮最上仙，西風許醉桂花前。", "爭歡酒蟻浮金爵，從聽歌塵撲翠蟬。", "秋霽捲簾凝錦席，夜闌吹笛稱江天。", "却思紫陌觥籌地，兔缺烏沈欲半年。"]'),
('1af95f36-d4af-43a1-ac11-be247ce226c5','釣翁','羅鄴','唐','唐诗','tang','','[]','來往煙波非定居，生涯簑褐外無餘。',64,'全唐诗/poet.tang.36000.json','["來往煙波非定居，生涯簑褐外無餘。", "閑垂兩鬢任如鶴，只繫一竿時得魚。", "月浦扣船歌皎潔，雨蓬隈岸臥蕭疎。", "行人誤話金張貴，笑指北邙丘與墟。"]'),
('c27daaf8-489e-4fdb-8d82-85a074f8fd2e','聞友人入越幕因以詩贈','羅鄴','唐','唐诗','tang','','[]','稽嶺春生酒凍銷，煙鬟紅袖恃嬌饒。',64,'全唐诗/poet.tang.36000.json','["稽嶺春生酒凍銷，煙鬟紅袖恃嬌饒。", "岸邊叢雪晴香老，波上長虹晚影遙。", "正哭阮途歸未得，更聞江筆赴嘉招。", "人間榮瘁真堪恨，坐想征軒鬢欲凋。"]'),
('5e2f42f6-d672-416b-aca2-f19ec01f7c88','東歸','羅鄴','唐','唐诗','tang','','[]','日日唯憂行役遲，東歸可是有家歸。',64,'全唐诗/poet.tang.36000.json','["日日唯憂行役遲，東歸可是有家歸。", "都緣桂玉無門住，不算山川去路危。", "秦樹夢愁黃鳥囀，吳江釣憶錦鱗肥。", "桃夭李豔清明近，惆悵當年意盡違。"]'),
('fa0f7f6d-5791-4ef9-b33d-1ab0d0c1b526','入關','羅鄴','唐','唐诗','tang','','[]','古道槐花滿樹開，入關時節一蟬催。',64,'全唐诗/poet.tang.36000.json','["古道槐花滿樹開，入關時節一蟬催。", "出門唯恐不先到，當路有誰長待來。", "似箭年光還可惜，如蓬生計更堪哀。", "故園若有漁舟在，應掛雲帆早箇迴。"]'),
('8401c4e5-86da-40c8-9353-c55fcf4cbb0e','覽陳丕卷','羅鄴','唐','唐诗','tang','','[]','雪宮詞客燕宮遊，一軸煙花象外搜。',64,'全唐诗/poet.tang.36000.json','["雪宮詞客燕宮遊，一軸煙花象外搜。", "謾把蜀紋當晝展，徒誇湘碧帶春流。", "吟時致我寒侵骨，得處疑君白盡頭。", "從北南歸明月夜，嶺猨灘鳥更悠悠。"]'),
('b37dae24-1d6c-4f55-8862-1bfc0f2c0414','巴南旅舍言懷','羅鄴','唐','唐诗','tang','','[]','萬浪千巖首未回，無憀相倚上高臺。',64,'全唐诗/poet.tang.36000.json','["萬浪千巖首未回，無憀相倚上高臺。", "家山如畫不歸去，客舍似讐誰遣來。", "紅淚罷窺連曉燭，碧波休引向春盃。", "後時若有青雲望，何事偏教羽冀摧。"]'),
('f6b5bc84-561d-4080-b1a8-0a6595a4a676','登凌歊臺','羅鄴','唐','唐诗','tang','','[]','高臺今日竟長閑，因想興亡自慘顏。',64,'全唐诗/poet.tang.36000.json','["高臺今日竟長閑，因想興亡自慘顏。", "四海已歸新雨露，六朝空認舊江山。", "槎翹獨鳥沙汀畔，風遰連檣雪浪間。", "好是輪蹄來往便，誰人不向此躋攀。"]'),
('dedd5f45-dcab-46d9-8c14-0b29e5f19c2c','僕射陂晚望','羅鄴','唐','唐诗','tang','','[]','離人到此倍堪傷，陂水蘆花似故鄉。',64,'全唐诗/poet.tang.36000.json','["離人到此倍堪傷，陂水蘆花似故鄉。", "身事未知何日了，馬蹄唯覺到秋忙。", "田園牢落東歸晚，道路辛勤北去長。", "却羨無愁是沙鳥，雙雙相趂下斜陽。"]'),
('ebde1812-899f-4fa6-8345-ddf561e71e56','芳草','羅鄴','唐','唐诗','tang','','[]','廢苑牆南殘雨中，似袍顏色在蒙茸。',64,'全唐诗/poet.tang.36000.json','["廢苑牆南殘雨中，似袍顏色在蒙茸。", "微香暗惹遊人步，遠綠纔分鬬雉蹤。", "三楚渡頭長恨見，五侯門外却難逢。", "年年縱有春風便，馬跡車輪一萬重。"]'),
('2275de93-9ca8-4161-b871-382e33398f41','秋日留題蔣亭','羅鄴','唐','唐诗','tang','','[]','西風纔起一蟬鳴，便筭關河馬上程。',64,'全唐诗/poet.tang.36000.json','["西風纔起一蟬鳴，便筭關河馬上程。", "碧浪鷁舟從此別，丹霄鵠箭忍無成。", "二年芳思隨雲雨，幾日離歌戀斾旌。", "回首橫塘更東望，露荷煙菊倍傷情。"]'),
('d295299f-31e4-4da1-bb0a-f42829fd8503','早發','羅鄴','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b", "\u5199\u666f"]','一點燈殘魯酒醒，已攜孤劒事離程。',64,'全唐诗/poet.tang.36000.json','["一點燈殘魯酒醒，已攜孤劒事離程。", "愁看飛雪聞雞唱，獨向長空背雁行。", "白草近關微有路，濁河連底凍無聲。", "此中來往本迢遞，況是驅羸客塞城。"]'),
('0ed58ce0-6658-4aa2-aaa8-618541648884','雁二首 一','羅鄴','唐','唐诗','tang','','[]','暮天新鴈起汀洲，紅蓼花開水國愁。',32,'全唐诗/poet.tang.36000.json','["暮天新鴈起汀洲，紅蓼花開水國愁。", "想得故園今夜月，幾人相憶在江樓。"]'),
('e8252846-2511-4161-ba12-397de464c9d0','雁二首 二','羅鄴','唐','唐诗','tang','','[]','早背胡霜過戍樓，又隨寒日下汀洲。',32,'全唐诗/poet.tang.36000.json','["早背胡霜過戍樓，又隨寒日下汀洲。", "江南江北多離別，忍報年年兩地愁。"]'),
('9e9b0d61-33ac-463f-809e-66c9b47e75d1','螢二首 一','羅鄴','唐','唐诗','tang','','[]','水殿清風玉戶開，飛光千點去還來。',32,'全唐诗/poet.tang.36000.json','["水殿清風玉戶開，飛光千點去還來。", "無風無月長門夜，偏到階前點綠苔。"]'),
('ffa018d6-b04a-4331-9bd2-c15cef111fcc','螢二首 二','羅鄴','唐','唐诗','tang','','[]','裴回無燭冷無煙，秋逕莎庭入夜天。',32,'全唐诗/poet.tang.36000.json','["裴回無燭冷無煙，秋逕莎庭入夜天。", "休向書窗來照字，近來紅蠟滿歌筵。"]'),
('fb09f085-ca1f-412e-b42f-849fdc7aa583','看花','羅鄴','唐','唐诗','tang','','[]','花開只恐看來遲，及到愁如未看時。',32,'全唐诗/poet.tang.36000.json','["花開只恐看來遲，及到愁如未看時。", "家在楚鄉身在蜀，一年春色負歸期。"]'),
('96c6b703-07dc-4683-b51f-72ab5dbc65ae','柳絮','羅鄴','唐','唐诗','tang','','[]','處處東風撲晚陽，輕輕醉粉落無香。',32,'全唐诗/poet.tang.36000.json','["處處東風撲晚陽，輕輕醉粉落無香。", "就中堪恨隋堤上，曾惹龍舟舞鳳凰。"]'),
('21191040-9160-4209-9b71-8c3bc6d40ae7','雲','羅鄴','唐','唐诗','tang','','[]','紛紛靄靄遍江湖，得路爲霖豈合無。',32,'全唐诗/poet.tang.36000.json','["紛紛靄靄遍江湖，得路爲霖豈合無。", "莫使悠颺只如此，帝鄉還更暖蒼梧。"]'),
('bb6afac5-da67-4bf6-9d68-3e5ac0657981','芳草','羅鄴','唐','唐诗','tang','','[]','曲江岸上天街裏，兩地縱生車馬多。',32,'全唐诗/poet.tang.36000.json','["曲江岸上天街裏，兩地縱生車馬多。", "不似萋萋南浦見，晚來煙雨半相和。"]'),
('d373e8bf-69fb-4e7d-b813-ff4af3ea8eb2','出都門','羅鄴','唐','唐诗','tang','','[]','青門春色一花開，長到花時把酒杯。',32,'全唐诗/poet.tang.36000.json','["青門春色一花開，長到花時把酒杯。", "自覺無家似潮水，不知歸處去還來。"]'),
('bd31fa64-9db7-4b44-9eb6-7ab77f6c5730','宮中二首 一','羅鄴','唐','唐诗','tang','','[]','芳草長含玉輦塵，君王遊幸此中頻。',32,'全唐诗/poet.tang.36000.json','["芳草長含玉輦塵，君王遊幸此中頻。", "今朝別有承恩處，鸚鵡飛來說似人。"]'),
('e7a0a09f-5eb7-4058-a94e-6a97311e5bb0','宮中二首 二','羅鄴','唐','唐诗','tang','','[]','雖然自小屬梨園，不識先皇玉殿門。',16,'全唐诗/poet.tang.36000.json','["雖然自小屬梨園，不識先皇玉殿門。"]'),
('34595ff5-f069-470b-8b60-bb590bd30039','河湟','羅鄴','唐','唐诗','tang','','[]','河湟何計絕烽煙，免使征人更戍邊。',32,'全唐诗/poet.tang.36000.json','["河湟何計絕烽煙，免使征人更戍邊。", "盡放農桑無一事，遣教知有太平年。"]'),
('d7e5dfbb-f218-43ff-819b-802416b3ff11','聞子規','羅鄴','唐','唐诗','tang','','[]','蜀魄千年尚怨誰，聲聲啼血向花枝。',32,'全唐诗/poet.tang.36000.json','["蜀魄千年尚怨誰，聲聲啼血向花枝。", "滿山明月東風夜，正是愁人不寐時。"]'),
('fe0199b5-a409-41d8-9401-9f6dcb2c3510','望仙','羅鄴','唐','唐诗','tang','','[]','千山壘土望三山，雲鶴無蹤羽衛還。',32,'全唐诗/poet.tang.36000.json','["千山壘土望三山，雲鶴無蹤羽衛還。", "若說神仙求便得，茂陵何事在人間。"]'),
('2872cb01-a564-43af-8d21-0fec6cce7768','放鷓鴣','羅鄴','唐','唐诗','tang','','[]','好傍青山與碧溪，刺桐毛竹待雙栖。',32,'全唐诗/poet.tang.36000.json','["好傍青山與碧溪，刺桐毛竹待雙栖。", "花時遷客傷離別，莫向相思樹上啼。"]'),
('4b654b54-d1ab-4799-9a92-7eaf483749ad','驪山','羅鄴','唐','唐诗','tang','','[]','風搖巖桂露聞香，白鹿驚時出繞牆。',32,'全唐诗/poet.tang.36000.json','["風搖巖桂露聞香，白鹿驚時出繞牆。", "不向驪山鎖宮殿，可知仙去是明皇。"]'),
('546b15ae-fceb-40ec-8fc0-2120b3c7fa91','梅花','羅鄴','唐','唐诗','tang','','["\u6885\u82b1", "\u6292\u6000", "\u82b1", "\u5199\u82b1"]','繁如瑞雪壓枝開，越嶺吳溪免用栽。',32,'全唐诗/poet.tang.36000.json','["繁如瑞雪壓枝開，越嶺吳溪免用栽。", "却是五侯家未識，春風不放過江來。"]'),
('2359cbed-80f6-45fb-a961-d6f6b7106ac3','雞冠花','羅鄴','唐','唐诗','tang','','[]','一枝穠豔對秋光，露滴風搖倚砌傍。',32,'全唐诗/poet.tang.36000.json','["一枝穠豔對秋光，露滴風搖倚砌傍。", "曉景乍看何處似，謝家新染紫羅裳。"]'),
('616815d3-539f-4a58-ab6e-97dbe3b035e0','汴河','羅鄴','唐','唐诗','tang','','[]','煬帝開河鬼亦悲，生民不獨力空疲。',32,'全唐诗/poet.tang.36000.json','["煬帝開河鬼亦悲，生民不獨力空疲。", "至今嗚咽東流水，似向清平怨昔時。"]'),
('a9eb4c63-9fc7-4d91-85ea-d1bb4b6a8b99','渡江有感','羅鄴','唐','唐诗','tang','','[]','岸落殘紅錦雉飛，渡江船上夕陽微。',32,'全唐诗/poet.tang.36000.json','["岸落殘紅錦雉飛，渡江船上夕陽微。", "一枝猶負平生意，歸去何曾勝不歸。"]'),
('ef4fe546-b1eb-4315-8148-361756a12d45','題終南山僧堂','羅鄴','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','九衢終日見南山，名利何人肯掩關。',32,'全唐诗/poet.tang.36000.json','["九衢終日見南山，名利何人肯掩關。", "唯有吾師達真理，坐看霜樹老雲間。"]'),
('e15e43d4-98d6-46e7-a6c2-b004d2e0a7f1','大散嶺','羅鄴','唐','唐诗','tang','','[]','過往長逢日色稀，雪花如掌撲行衣。',32,'全唐诗/poet.tang.36000.json','["過往長逢日色稀，雪花如掌撲行衣。", "嶺頭却望人來處，特地身疑是鳥飛。"]'),
('12336ab5-cca7-444d-a3e3-3c6e4d81aca3','嘉陵江','羅鄴','唐','唐诗','tang','','[]','嘉陵南岸雨初收，江似秋嵐不煞流。',32,'全唐诗/poet.tang.36000.json','["嘉陵南岸雨初收，江似秋嵐不煞流。", "此地終朝有行客，無人一爲櫂扁舟。"]'),
('3aefd553-d1e5-447c-91bd-f6feedb603ec','早行','羅鄴','唐','唐诗','tang','','[]','雨灑江聲風又吹，扁舟正與睡相宜。',32,'全唐诗/poet.tang.36000.json','["雨灑江聲風又吹，扁舟正與睡相宜。", "無端戍鼓催前去，別却青山向曉時。"]'),
('08cccc1b-944b-4889-a93d-cfc9788b8837','黃河曉渡','羅鄴','唐','唐诗','tang','','["\u9ec4\u6cb3"]','大河平野正窮秋，羸馬羸僮古渡頭。',32,'全唐诗/poet.tang.36000.json','["大河平野正窮秋，羸馬羸僮古渡頭。", "昨夜蓮花峰下月，隔簾相伴到明愁。"]'),
('d3a0282a-9aec-4ea1-94cd-63497649c1d8','溫泉','羅鄴','唐','唐诗','tang','','[]','一條春水漱莓苔，幾繞玄宗浴殿回。',32,'全唐诗/poet.tang.36000.json','["一條春水漱莓苔，幾繞玄宗浴殿回。", "此水貴妃曾照影，不堪流入舊宮來。"]'),
('aa7033e7-70ad-449c-8ae8-40ea460f2604','秋怨','羅鄴','唐','唐诗','tang','','[]','夢斷南窗啼曉烏，新霜昨夜下庭梧。',32,'全唐诗/poet.tang.36000.json','["夢斷南窗啼曉烏，新霜昨夜下庭梧。", "不知簾外如珪月，還照邊城到曉無。"]'),
('fbf4b0a9-6704-4d07-90c8-9aea0b97ded8','歎別','羅鄴','唐','唐诗','tang','','[]','北來南去幾時休，人在光陰似箭流。',32,'全唐诗/poet.tang.36000.json','["北來南去幾時休，人在光陰似箭流。", "直待江山盡無路，始因拋得別離愁。"]'),
('dea41905-a68a-40c4-bd07-97a70c0342e3','送春','羅鄴','唐','唐诗','tang','','[]','欲別東風剩黯然，亦知春去有明年。',32,'全唐诗/poet.tang.36000.json','["欲別東風剩黯然，亦知春去有明年。", "世間爭那人先老，更對殘花一醉眠。"]'),
('f38b46c3-47b3-4530-ac4a-14e13252180c','蠟燭','羅鄴','唐','唐诗','tang','','[]','煖香紅焰一時燃，緹幕初垂月落天。',32,'全唐诗/poet.tang.36000.json','["煖香紅焰一時燃，緹幕初垂月落天。", "堪恨蘭堂別離夜，如珠似淚滴樽前。"]'),
('7cdc714c-bb13-4ea2-a894-cfcf3915d801','陳宮','羅鄴','唐','唐诗','tang','','[]','白玉尊前紫桂香，迎春閣上燕雙雙。',32,'全唐诗/poet.tang.36000.json','["白玉尊前紫桂香，迎春閣上燕雙雙。", "陳王半醉貴妃舞，不覺隋兵夜渡江。"]'),
('d52f4a69-8d07-4cfd-a112-85221c647b82','水簾','羅鄴','唐','唐诗','tang','','[]','萬點飛泉下白雲，似簾懸處望疑真。',32,'全唐诗/poet.tang.36000.json','["萬點飛泉下白雲，似簾懸處望疑真。", "若將此水爲霖雨，更勝長垂隔路塵。"]'),
('039fc803-bc22-4f29-9df2-716ca15339b5','賞春','羅鄴','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u8bbd\u55bb"]','芳草和煙暖更青，閑門要路一時生。',32,'全唐诗/poet.tang.36000.json','["芳草和煙暖更青，閑門要路一時生。", "年年點檢人間事，唯有春風不世情。"]'),
('bd0a0ea5-7bd0-4563-b3f8-f65055b175ac','歎平泉','羅鄴','唐','唐诗','tang','','[]','生前幾到此亭臺，尋歎投荒去不回。',32,'全唐诗/poet.tang.36000.json','["生前幾到此亭臺，尋歎投荒去不回。", "若遣春風會人意，花枝盡合向南開。"]'),
('727fc328-af80-49b6-80be-5bdd43ce0022','長安春雨','羅鄴','唐','唐诗','tang','','[]','兼風颯颯灑皇洲，能滯輕寒阻勝遊。',32,'全唐诗/poet.tang.36000.json','["兼風颯颯灑皇洲，能滯輕寒阻勝遊。", "半夜五侯池館裏，美人驚起爲花愁。"]'),
('b438d5cf-245c-4c69-bb24-55a4329fb033','駕蜀回','羅鄴','唐','唐诗','tang','','[]','上皇西幸却歸秦，花木依然滿禁春。',32,'全唐诗/poet.tang.36000.json','["上皇西幸却歸秦，花木依然滿禁春。", "唯有貴妃歌舞地，月明空殿鎖香塵。"]'),
('39b66aed-4942-4982-9ed6-4cd2e9829f26','吳王古宮井二首 一','羅鄴','唐','唐诗','tang','','[]','古宮荒井曾平後，見說耕人又鑿開。',32,'全唐诗/poet.tang.36000.json','["古宮荒井曾平後，見說耕人又鑿開。", "拾得玉衩鐫勅字，當時恩澤賜誰來。"]'),
('7a025954-025b-4537-995a-7ed68f4eb807','吳王古宮井二首 二','羅鄴','唐','唐诗','tang','','[]','含青薜荔隨金甃，碧砌磷磷生綠苔。',32,'全唐诗/poet.tang.36000.json','["含青薜荔隨金甃，碧砌磷磷生綠苔。", "莫言數尺無波水，曾與如花竝照來。"]'),
('ba9b0e8d-0e7c-4bdb-8f8b-72f3b664fc7f','江帆','羅鄴','唐','唐诗','tang','','[]','別離不獨恨蹄輪，渡口風帆發更頻。',32,'全唐诗/poet.tang.36000.json','["別離不獨恨蹄輪，渡口風帆發更頻。", "何處青樓方凭檻，半江斜日認歸人。"]'),
('81e08109-4137-4309-9a4b-87f12efc7655','爲人感贈','羅鄴','唐','唐诗','tang','','[]','歌舞從來最得名，如今老寄洛陽城。',32,'全唐诗/poet.tang.36000.json','["歌舞從來最得名，如今老寄洛陽城。", "當時醉送龍驤曲，留與誰家唱月明。"]'),
('4583c2b1-e065-4ea3-9dab-52382928c988','春江恨別','羅鄴','唐','唐诗','tang','','[]','望斷長川一葉舟，可堪歸路更沿流。',32,'全唐诗/poet.tang.36000.json','["望斷長川一葉舟，可堪歸路更沿流。", "垂來別處無人見，芳草斜陽滿渡頭。"]'),
('d500e8f1-7a41-4e87-82a2-b83454a93dee','歎流水二首 一','羅鄴','唐','唐诗','tang','','[]','人間莫謾惜花落，花落明年依舊開。',32,'全唐诗/poet.tang.36000.json','["人間莫謾惜花落，花落明年依舊開。", "却最堪悲是流水，便同人事去無迴。"]'),
('c8598df9-4e1d-4323-9c6d-bd4240c5538f','歎流水二首 二','羅鄴','唐','唐诗','tang','','[]','龍躍虬蟠旋作潭，繞紅濺綠下東南。',32,'全唐诗/poet.tang.36000.json','["龍躍虬蟠旋作潭，繞紅濺綠下東南。", "春風散入侯家去，漱齒花前酒半酣。"]'),
('b75978bd-2c37-4bbe-94e9-9fd37fa5b9af','落第東歸','羅鄴','唐','唐诗','tang','','[]','年年春色獨懷羞，彊向東歸懶舉頭。',32,'全唐诗/poet.tang.36000.json','["年年春色獨懷羞，彊向東歸懶舉頭。", "莫道還家便容易，人間多少事堪愁。"]'),
('7e9a8dc2-6ddb-4c78-9623-fff124b26ead','鏡','羅鄴','唐','唐诗','tang','','[]','昔歲相知別有情，幾迴磨拭始將行。',32,'全唐诗/poet.tang.36000.json','["昔歲相知別有情，幾迴磨拭始將行。", "如今老去愁無限，抱向閑窗却怕明。"]'),
('ee75c5e5-6718-4cee-9a1c-d3332c1fe273','南行','羅鄴','唐','唐诗','tang','','[]','臘晴江煖鸊鵜飛，梅雪香黏越女衣。',32,'全唐诗/poet.tang.36000.json','["臘晴江煖鸊鵜飛，梅雪香黏越女衣。", "魚市酒村相識徧，短船歌月醉方歸。"]'),
('26e413d4-b9da-476a-93a7-be2142753514','公子行','羅鄴','唐','唐诗','tang','','[]','金鞍玉勒照花明，過後春風特地生。',32,'全唐诗/poet.tang.36000.json','["金鞍玉勒照花明，過後春風特地生。", "半醉五侯門裏出，月高猶在禁街行。"]'),
('4581f7cd-3b3e-4efd-98d3-c9789d6e9dfc','春日偶題城南韋曲','羅鄴','唐','唐诗','tang','','[]','韋曲城南錦繡堆，千金不惜買花栽。',32,'全唐诗/poet.tang.36000.json','["韋曲城南錦繡堆，千金不惜買花栽。", "誰知豪貴多羈束，落盡春紅不見來。"]'),
('091a6064-01f8-4f8f-9317-2c1027077445','上東川顧尚書','羅鄴','唐','唐诗','tang','','[]','輕財重義真公子，長策沈機繼武侯。',32,'全唐诗/poet.tang.36000.json','["輕財重義真公子，長策沈機繼武侯。", "龍節坐持兵十萬，可憐三蜀盡無憂。"]'),
('6caee38d-ca1a-4198-afb9-d2d9e934ce5c','過王濬墓','羅鄴','唐','唐诗','tang','','[]','埋骨千年近路塵，路傍碑號晉將軍。',32,'全唐诗/poet.tang.36000.json','["埋骨千年近路塵，路傍碑號晉將軍。", "當時若使無功業，早箇耕桑到此墳。"]'),
('c97708b0-b794-46d4-a87a-817b7e1ea3bd','灞上感別','羅鄴','唐','唐诗','tang','','[]','灞水何人不別離，無家南北倚空悲。',32,'全唐诗/poet.tang.36000.json','["灞水何人不別離，無家南北倚空悲。", "十年此路花時節，立馬霑襟酒一巵。"]'),
('f887b920-28d5-410e-8407-5445318457fe','春日與友人話別','羅鄴','唐','唐诗','tang','','[]','酌坐對芳草，東風吹旅衣。',48,'全唐诗/poet.tang.36000.json','["酌坐對芳草，東風吹旅衣。", "最嫌驅馬倦，自未有山歸。", "華髪將時逼，青雲計又非。", "離襟一霑灑，迴首正殘暉。"]'),
('77b71ed9-470d-4c38-b24e-8462db41ff93','竹','羅鄴','唐','唐诗','tang','','[]','翠葉纔分細細枝，清陰猶未上階墀。',64,'全唐诗/poet.tang.36000.json','["翠葉纔分細細枝，清陰猶未上階墀。", "蕙蘭雖許相依日，桃李還應笑後時。", "抱節不爲霜霰改，成林終與鳳凰期。", "渭濱若更徵賢相，好作漁竿繫釣絲。"]'),
('e865eefa-a417-4315-b205-43e330d0fac6','邊將','羅鄴','唐','唐诗','tang','','[]','馬上乘秋欲建勳，飛狐夜鬬出師頻。',64,'全唐诗/poet.tang.36000.json','["馬上乘秋欲建勳，飛狐夜鬬出師頻。", "若無紫塞煙塵事，誰識青樓歌舞人。", "戰骨沙中金鏃在，賀筵花畔玉盤新。", "由來邊卒皆如此，只是君門合殺身。"]'),
('a6920acb-c13d-4e00-85ee-681ae2588559','巴南旅泊','羅鄴','唐','唐诗','tang','','[]','巴山慘別魂，巴水徹荆門。',48,'全唐诗/poet.tang.36000.json','["巴山慘別魂，巴水徹荆門。", "此地若重到，居人誰復存。", "落帆紅葉渡，駐馬白雲村。", "却羨南飛鴈，年年到故園。"]'),
('5666f391-cb86-4534-81b3-a14386484f5b','河上逢友人','羅鄴','唐','唐诗','tang','','["\u9ec4\u6cb3"]','知君意不淺，立馬問生涯。',48,'全唐诗/poet.tang.36000.json','["知君意不淺，立馬問生涯。", "薄業無歸地，他鄉便是家。", "宵吟憐桂魄，朝起怯菱花。", "語盡黃河上，西風日又斜。"]'),
('95e5b7b7-96a1-4bdb-ae8d-195c8b5e11db','偶題離亭','羅鄴','唐','唐诗','tang','','[]','萬般名利不關身，況待山平海變塵。',64,'全唐诗/poet.tang.36000.json','["萬般名利不關身，況待山平海變塵。", "五月波濤爭下峽，滿堂金玉爲何人。", "謾誇浮世青雲貴，未盡離杯白髮新。", "誰似雨篷篷底客，渚花汀鳥自相親。"]'),
('1aad938d-a1c0-4909-b186-737d62bb313a','夏晚望嵩亭有懷','羅鄴','唐','唐诗','tang','','[]','正憐雲水與心違，湖上亭高對翠微。',48,'全唐诗/poet.tang.36000.json','["正憐雲水與心違，湖上亭高對翠微。", "盡日不妨憑檻望，終年未必有家歸。", "青蟬漸傍幽叢噪，白鳥時穿返照飛。"]'),
('7d82b500-8e29-4eb6-bbb1-30cca024d3c4','途中寄友人','羅鄴','唐','唐诗','tang','','[]','秋庭悵望別君初，折柳分襟十載餘。',64,'全唐诗/poet.tang.36000.json','["秋庭悵望別君初，折柳分襟十載餘。", "相見或因中夜夢，寄來多是隔年書。", "攜樽座外花空老，垂釣江頭柳漸疎。", "裁得詩憑千里雁，吟來寧不憶吾廬。"]'),
('3a00fd47-50c4-454e-af86-b6e1a35ec3a7','傷侯弟','羅鄴','唐','唐诗','tang','','[]','世間榮辱半相和，昨日權門今雀羅。',64,'全唐诗/poet.tang.36000.json','["世間榮辱半相和，昨日權門今雀羅。", "萬古明君方納諫，九江遷客更應多。", "碧池草熟人偷釣，畫戟春閑鶯亂過。", "幾許樂僮無主後，不離隣巷教笙歌。"]'),
('52a46df5-f913-4649-b9c1-d1c47ac5eb88','春日過壽安山館','羅鄴','唐','唐诗','tang','','[]','舊國多將泉石親，西遊愛此拂行塵。',64,'全唐诗/poet.tang.36000.json','["舊國多將泉石親，西遊愛此拂行塵。", "簾開山色離亭午，步入松香別島春。", "誰肯暫安耕釣地，相逢謾歎路岐身。", "歸期不及桃花水，江上何曾鱠雪鱗。"]'),
('de2dbaa7-0dca-49c0-ba3f-533c1d66f362','吳門再逢方干處士','羅鄴','唐','唐诗','tang','','[]','天上高名世上身，垂綸何不駕蒲輪。',64,'全唐诗/poet.tang.36000.json','["天上高名世上身，垂綸何不駕蒲輪。", "一朝卿相俱前席，千古篇章冠後人。", "稽嶺不歸空挂夢，吳宮相值欲霑巾。", "吾王若致昇平化，可獨成周只渭濱。"]'),
('71f1ee93-63e4-4b31-8107-17ccef2d8c9b','蟬','羅鄴','唐','唐诗','tang','','[]','纔入新秋百感生，就中蟬噪最堪驚。',64,'全唐诗/poet.tang.36000.json','["纔入新秋百感生，就中蟬噪最堪驚。", "能催時節凋雙鬢，愁到江山聽一聲。", "不傍管弦拘醉態，偏依楊柳撓離情。", "故園聞處猶惆悵，況是經年萬里行。"]'),
('b7f28e86-f4dc-41cc-867c-651ba4bb4f57','秋日留別義初上人','羅鄴','唐','唐诗','tang','','[]','塞寺窮秋別還師，西風一雁倍傷悲。',64,'全唐诗/poet.tang.36000.json','["塞寺窮秋別還師，西風一雁倍傷悲。", "每嗟塵世長多事，重到禪齋是幾時。", "霜嶺自添紅葉恨，月溪休和碧雲詞。", "關河回首便千里，飛錫南歸詎可知。"]'),
('c37028d7-82b5-4d06-a9fe-38ea02e9a612','夏日宿靈巖寺宗公院','羅鄴','唐','唐诗','tang','','[]','寺入千巖石路長，孤吟一宿遠公房。',64,'全唐诗/poet.tang.36000.json','["寺入千巖石路長，孤吟一宿遠公房。", "臥聽半夜杉壇雨，轉覺中峰枕簟涼。", "花界已無悲喜念，塵襟自足是非妨。", "他年縱使重來此，息得心猨鬢已霜。"]'),
('6c000d87-47b6-4226-9f93-d21869f772dc','冬日廟中書事呈棲白上人','羅鄴','唐','唐诗','tang','','[]','日高荒廟掩雙扉，杉逕無人鳥雀悲。',64,'全唐诗/poet.tang.36000.json','["日高荒廟掩雙扉，杉逕無人鳥雀悲。", "昨日江潮起歸思，滿窗風雨覺來時。", "何堪身計長如此，閑盡爐灰却是疑。", "賴有碧雲吟句客，禪餘相訪說新詩。"]'),
('088834a6-8bcf-4562-b553-489c2a4ab7bb','夏日題遠公北閣','羅鄴','唐','唐诗','tang','','[]','危閣壓山岡，晴空疑鳥行。',72,'全唐诗/poet.tang.36000.json','["危閣壓山岡，晴空疑鳥行。", "勝搜花界盡，響益梵音長。", "有月堪先到，無風亦自涼。", "人煙紛繞繞，諸樹共蒼蒼。", "榻戀高樓語，甌憐晝茗香。", "此身閑未得，驅馬入殘陽。"]'),
('f71d784a-674e-481f-b08c-931b116330be','秋蝶二首 一','羅鄴','唐','唐诗','tang','','[]','秦樓花發時，秦女笑相隨。',24,'全唐诗/poet.tang.36000.json','["秦樓花發時，秦女笑相隨。", "及到秋風日，飛來欲問誰。"]'),
('6e97bc90-04df-4d50-9604-40a70a990e40','秋蝶二首 二','羅鄴','唐','唐诗','tang','','[]','似厭栖寒菊，翩翩占晚陽。',24,'全唐诗/poet.tang.36000.json','["似厭栖寒菊，翩翩占晚陽。", "愁人如見此，應下淚千行。"]'),
('fa73018c-c5be-4d65-ab0d-551a19049b56','秋別','羅鄴','唐','唐诗','tang','','["\u79bb\u522b", "\u79cb\u5929"]','別路垂[楊]柳，秋風淒管弦。',26,'全唐诗/poet.tang.36000.json','["別路垂[楊]柳，秋風淒管弦。", "青樓君去後，明月爲誰圓。"]'),
('80179f84-582b-46ce-8e64-60f5a3e83cbb','共友人看花','羅鄴','唐','唐诗','tang','','[]','愁將萬里身，來伴看花人。',24,'全唐诗/poet.tang.36000.json','["愁將萬里身，來伴看花人。", "何事獨惆悵，故園還又春。"]'),
('4149460e-a279-46c8-89d6-72433f2d02fa','行次','羅鄴','唐','唐诗','tang','','[]','終日長程復短程，一山行盡一山青。',32,'全唐诗/poet.tang.36000.json','["終日長程復短程，一山行盡一山青。", "路傍君子莫相笑，天上由來有客星。"]'),
('122d3a6f-4d3c-4989-82f7-84cad990ebc6','鳯州北樓','羅鄴','唐','唐诗','tang','','[]','城上層樓北望時，閑雲遠水自相宜。',32,'全唐诗/poet.tang.36000.json','["城上層樓北望時，閑雲遠水自相宜。", "人人盡道堪圖畫，枉遣山翁醉習池。"]'),
('b5c790d2-6e13-4faa-a2b2-28dbe6a27972','贈僧','羅鄴','唐','唐诗','tang','','[]','繁華舉世皆如夢，今古何人肯暫閑。',32,'全唐诗/poet.tang.36000.json','["繁華舉世皆如夢，今古何人肯暫閑。", "唯有東林學禪客，白頭閑坐對青山。"]'),
('f70cd0ff-ca1c-459d-abc7-6850d58b7629','曲江春感','羅隱','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','江頭日暖花又開，江東行客心悠哉。',64,'全唐诗/poet.tang.36000.json','["江頭日暖花又開，江東行客心悠哉。", "高陽酒徒半彫落，終南山色空崔嵬。", "聖代也知無棄物，侯門未必用非才。", "一船明月一竿竹，家住五湖歸去來。"]'),
('996562b6-5aa5-4798-9e29-8712dca22720','皇陂','羅隱','唐','唐诗','tang','','[]','皇陂瀲灩深復深，陂西下馬聊登臨。',64,'全唐诗/poet.tang.36000.json','["皇陂瀲灩深復深，陂西下馬聊登臨。", "垂楊風輕弄翠帶，鯉魚日暖跳黃金。", "三月窮途無勝事，十年流水見歸心。", "輸他谷口鄭夫子，偷得閑名說至今。"]'),
('deacbc5d-c662-420c-b733-145872752fae','寄鄭補闕','羅隱','唐','唐诗','tang','','[]','夫子門前數仞牆，每經過處憶遊梁。',64,'全唐诗/poet.tang.36000.json','["夫子門前數仞牆，每經過處憶遊梁。", "路從青瑣無因見，恩在丹心不可忘。", "未必便爲讒口隔，只應貪草諫書忙。", "別來愁悴知多少，兩度槐花馬上黃。"]'),
('db92063f-038f-4620-9990-3f7d697ad279','牡丹花','羅隱','唐','唐诗','tang','','[]','似共東風別有因，絳羅高卷不勝春。',64,'全唐诗/poet.tang.36000.json','["似共東風別有因，絳羅高卷不勝春。", "若教解語應傾國，任是無情亦動人。", "芍藥與君爲近侍，芙蓉何處避芳塵。", "可憐韓令功成後，辜負穠華過此身。"]'),
('8ea3421c-ab98-4fe8-96a5-b3e0328016e4','黃河','羅隱','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u5178\u6545", "\u8bbd\u523a"]','莫把阿膠向此傾，此中天意固難明。',64,'全唐诗/poet.tang.36000.json','["莫把阿膠向此傾，此中天意固難明。", "解通銀漢應須曲，纔出崑崙便不清。", "高祖誓功衣帶小，仙人占斗客槎輕。", "三千年後知誰在，何必勞君報太平。"]'),
('82431b04-6628-41bc-b038-7913b3fc2236','汴河','羅隱','唐','唐诗','tang','','[]','當時天子是閑遊，今日行人特地愁。',64,'全唐诗/poet.tang.36000.json','["當時天子是閑遊，今日行人特地愁。", "柳色縱饒妝故國，水聲何忍到揚州。", "乾坤有意終難會，黎庶無情豈自由。", "應笑秦皇用心錯，謾驅神鬼海東頭。"]'),
('a42cd3e9-6353-4d46-9caa-2a2b15a018ee','西京崇德里居','羅隱','唐','唐诗','tang','','[]','進乏梯媒退又難，強隨豪貴殢長安。',64,'全唐诗/poet.tang.36000.json','["進乏梯媒退又難，強隨豪貴殢長安。", "風從昨夜吹銀漢，淚擬何門落玉盤。", "拋擲紅塵應有恨，思量仙桂也無端。", "錦鱗赬尾平生事，却被閑人把釣竿。"]'),
('0f50862c-2d38-4905-ad42-aa051802c3ed','投所思','羅隱','唐','唐诗','tang','','[]','顦顇長安何所爲，旅魂窮命自相疑。',64,'全唐诗/poet.tang.36000.json','["顦顇長安何所爲，旅魂窮命自相疑。", "滿川碧嶂無歸日，一榻紅塵有淚時。", "雕琢只應勞郢匠，膏肓終恐誤秦醫。", "浮生七十今三十，從此悽惶未可知。"]'),
('6a39a519-2dbf-4459-899a-2d222df61449','經張舍人舊居','羅隱','唐','唐诗','tang','','[]','行塵不是昔時塵，謾向朱門憶侍臣。',64,'全唐诗/poet.tang.36000.json','["行塵不是昔時塵，謾向朱門憶侍臣。", "一榻已無開眼處，九泉應有愛才人。", "文餘吐鳳他年詔，樹想棲鸞舊日春。", "從此恩深轉難報，夕陽衰草淚沾巾。"]'),
('cb36b9b4-b939-41c9-8afb-c982600e826c','雒城作','羅隱','唐','唐诗','tang','','[]','大鹵旌旗出洛濱，此中煙月已埃塵。',64,'全唐诗/poet.tang.36000.json','["大鹵旌旗出洛濱，此中煙月已埃塵。", "更無樓閣尋行處，只有山川識野人。", "早得鑄金誇范蠡，旋聞垂釣哭平津。", "舊遊難得時難遇，迴首空城百草春。"]'),
('734ea579-0c9a-41ee-910c-f510551c2983','姑蘇城南湖陪曹使君遊','羅隱','唐','唐诗','tang','','[]','水蓼花紅稻穗黃，使君蘭棹汎迴塘。',64,'全唐诗/poet.tang.36000.json','["水蓼花紅稻穗黃，使君蘭棹汎迴塘。", "倚風荇藻先開路，迎斾鳧鷖盡著行。", "手裏兵符神與術，腰間金印綵爲囊。", "少年太守勳庸盛，應笑燕臺兩鬢霜。"]'),
('687b7b59-8e11-49a6-9019-27074b232f03','秋日有寄姑蘇曹使君','羅隱','唐','唐诗','tang','','[]','多病無因櫂小舟，闔閭城下謁名侯。',64,'全唐诗/poet.tang.36000.json','["多病無因櫂小舟，闔閭城下謁名侯。", "水寒不見雙魚信，風便唯聞五袴謳。", "早說用兵長暗合，近傳觀稼亦閑遊。", "須知謝奕依前醉，閒阻清談又一秋。"]'),
('b46bca13-2d00-4f0f-999c-61faafae2ef8','送章碣赴舉','羅隱','唐','唐诗','tang','','[]','苹鹿歌中別酒催，粉闈星彩動昭回。',64,'全唐诗/poet.tang.36000.json','["苹鹿歌中別酒催，粉闈星彩動昭回。", "久經罹亂心應破，乍覩昇平眼漸開。", "顧我昔年悲玉石，憐君今日蘊風雷。", "龍門盛事無因見，費盡黃金老隗臺。"]'),
('603ae201-ece8-4c04-bb3f-8516b304ef86','寄楊秘書','羅隱','唐','唐诗','tang','','[]','湖水平來見鯉魚，偶因烹處得瓊琚。',64,'全唐诗/poet.tang.36000.json','["湖水平來見鯉魚，偶因烹處得瓊琚。", "披尋藻思千重後，吟想冰光萬里餘。", "漳浦病來情轉薄，赤城吟苦意何如。", "錦衣公子憐君在，十載兵戈從板輿。"]'),
('eb880d90-cec0-490a-b68c-a7b1c29a470f','往年進士趙能卿嘗話金庭勝事見示敘','羅隱','唐','唐诗','tang','','[]','會稽詩客趙能卿，往歲相逢話石城。',64,'全唐诗/poet.tang.36000.json','["會稽詩客趙能卿，往歲相逢話石城。", "正恨故人無上壽，喜聞良宰有高情。", "山朝佐命層層聳，水接飛流步步清。", "兩火一刀罹亂後，會須乘興雪中行。"]'),
('d443dda0-9ffb-4f82-a6e1-8c58d1e4b708','得宣州竇尚書書因投寄二首 一','羅隱','唐','唐诗','tang','','[]','雙魚迢遞到江濱，傷感南陵舊主人。',64,'全唐诗/poet.tang.36000.json','["雙魚迢遞到江濱，傷感南陵舊主人。", "萬里朝臺勞寄夢，十年侯國阻趨塵。", "尋知亂後嘗辭祿，共喜閑來得養神。", "時見齊山敬亭客，不堪戎馬戰征頻。"]'),
('b85ef9f8-714c-4bee-9cd5-fddf6897f101','得宣州竇尚書書因投寄二首 二','羅隱','唐','唐诗','tang','','[]','曾逐旌旗過板橋，世途多難竟蓬飄。',64,'全唐诗/poet.tang.36000.json','["曾逐旌旗過板橋，世途多難竟蓬飄。", "步兵校尉辭公府，車騎將軍憶本朝。", "醉裏舊遊還歷歷，病中衰鬢奈蕭蕭。", "遺簪墮履應留念，門客如今只下僚。"]'),
('5c5a3223-b5ac-4be6-a085-c8a4abe9203c','雪','羅隱','唐','唐诗','tang','','[]','細玉羅紋下碧霄，杜門顏巷落偏饒。',64,'全唐诗/poet.tang.36000.json','["細玉羅紋下碧霄，杜門顏巷落偏饒。", "巢居只恐高柯折，旅客愁聞去路遙。", "撅凍野蔬和粉重，埽庭松葉帶酥燒。", "寒窗呵筆尋詩句，一片飛來紙上銷。"]'),
('ded6ea3d-bfbd-4037-a82f-f9f8e5846d4d','暇日有寄姑蘇曹使君兼呈張郎中郡中賓僚','羅隱','唐','唐诗','tang','','[]','嘉植陰陰覆劒池，此中能政動神祗。',64,'全唐诗/poet.tang.36000.json','["嘉植陰陰覆劒池，此中能政動神祗。", "湖邊觀稼雨迎馬，城外犒軍風滿旗。", "融酒徒誇無算爵，儉蓮還少最高枝。", "珊瑚筆架真珠履，曾和陳王幾首詩。"]'),
('2aa8873a-f6ad-438a-832c-4bfe412a90b1','寄右省王諫議','羅隱','唐','唐诗','tang','','[]','耳邊要靜不得靜，心裏欲閑終未閑。',64,'全唐诗/poet.tang.36000.json','["耳邊要靜不得靜，心裏欲閑終未閑。", "自是宿緣應有累，可能時事更相關。", "魚慙張翰辭東府，鶴怨周顒負北山。", "看却金庭芝朮老，又驅車入七人班。"]'),
('042ca878-b3bb-45b7-af5a-2719423b4ca1','焚書坑','羅隱','唐','唐诗','tang','','[]','千載遺蹤一窖塵，路傍耕者亦傷神。',32,'全唐诗/poet.tang.36000.json','["千載遺蹤一窖塵，路傍耕者亦傷神。", "祖龍算事渾乖角，將謂詩書活得人。"]'),
('c5d9a248-116f-4465-8f3b-411bd41324a5','始皇陵','羅隱','唐','唐诗','tang','','[]','荒堆無草樹無枝，嬾向行人問昔時。',32,'全唐诗/poet.tang.36000.json','["荒堆無草樹無枝，嬾向行人問昔時。", "六國英雄漫多事，到頭徐福是男兒。"]'),
('8b29ffdc-f28c-4e03-a2ee-96b99d8ac4f9','送沈先輩歸送上嘉禮','羅隱','唐','唐诗','tang','','[]','青青月桂觸人香，白苧衫輕稱沈郎。',64,'全唐诗/poet.tang.36000.json','["青青月桂觸人香，白苧衫輕稱沈郎。", "好繼馬卿歸故里，況聞山簡在襄陽。", "盃傾別岸應須醉，花傍征軍漸欲芳。", "擬把金錢贈嘉禮，不堪栖屑困名場。"]'),
('b298777c-4db6-424c-b441-e4051bf7ecc9','春日葉秀才曲江','羅隱','唐','唐诗','tang','','[]','江花江草暖相隈，也向江邊把酒杯。',64,'全唐诗/poet.tang.36000.json','["江花江草暖相隈，也向江邊把酒杯。", "春色惱人遮不得，別愁如瘧避還來。", "安排賤跡無良策，裨補明時望重才。", "一曲吳歌齊拍手，十年塵眼未曾開。"]'),
('35dc0c09-9b06-424e-88ad-744de4d6b4a7','西京道德里','羅隱','唐','唐诗','tang','','[]','秦樹團團夕結陰，此中莊舃動悲吟。',64,'全唐诗/poet.tang.36000.json','["秦樹團團夕結陰，此中莊舃動悲吟。", "一枝丹桂未入手，萬里蒼波長負心。", "老去漸知時態薄，愁來唯願酒杯深。", "七雄三傑今何在，休爲閑人淚滿襟。"]'),
('ddf26999-c33a-41aa-814a-32f7a4b1ef15','憶夏口','羅隱','唐','唐诗','tang','','[]','漢陽渡口蘭爲舟，漢陽城下多酒樓。',64,'全唐诗/poet.tang.36000.json','["漢陽渡口蘭爲舟，漢陽城下多酒樓。", "當年不得盡一醉，別夢有時還重遊。", "襟帶可憐吞楚塞，風煙只好狎江鷗。", "月明更想曾行處，吹笛橋邊木葉秋。"]'),
('9dd478b9-c0d3-4e6d-a3f7-625a1f31d2d7','武牢關','羅隱','唐','唐诗','tang','','[]','楚人曾此限封疆，不見清陰六里長。',64,'全唐诗/poet.tang.36000.json','["楚人曾此限封疆，不見清陰六里長。", "一壑暮聲何怨望，數峰秋勢自顛狂。", "由來四皓須神伏，大抵秦皇謾氣強。", "欲學雞鳴試關吏，太平時節嬾思量。"]'),
('170a3ec4-38b1-4e0b-947e-7bc6746ec822','途中獻晉州孟中丞','羅隱','唐','唐诗','tang','','[]','太平天子念蒲東，又委星郎養育功。',64,'全唐诗/poet.tang.36000.json','["太平天子念蒲東，又委星郎養育功。", "昨日隼旟辭闕下，今朝珠履在河中。", "樓移庾亮千山月，樹待袁宏一扇風。", "不及政成應入拜，晉州何足展清通。"]'),
('def3c98e-2235-49e0-a98a-c41df9d87858','長安秋夜','羅隱','唐','唐诗','tang','','[]','遠聞天子似羲皇，偶捨漁鄉入帝鄉。',64,'全唐诗/poet.tang.36000.json','["遠聞天子似羲皇，偶捨漁鄉入帝鄉。", "五等列侯無故舊，一枝仙桂有風霜。", "燈欹短焰燒離鬢，漏轉寒更滴旅腸。", "歸計未知身已老，九衢雙闕夜蒼蒼。"]'),
('a667d245-2c14-4386-8f2b-ad0977c21bc4','春晚寄鍾尚書','羅隱','唐','唐诗','tang','','[]','宰府初開忝末塵，四年談笑隔通津。',64,'全唐诗/poet.tang.36000.json','["宰府初開忝末塵，四年談笑隔通津。", "官資肯便矜中路，酒醆還應憶故人。", "江畔舊遊秦望月，檻前公事鏡湖春。", "如今莫問西禪塢，一炷寒香老病身。"]'),
('70a4bb22-0ec2-46ae-9519-0aca07aac67e','秋曉寄友人','羅隱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭霜落水雲秋，又汎輕漣任去留。',64,'全唐诗/poet.tang.36000.json','["洞庭霜落水雲秋，又汎輕漣任去留。", "世界高談今已得，宦途清貴舊曾遊。", "手中綵筆誇題鳳，天上泥封獎狎鷗。", "更見南來釣翁說，醉吟還上木蘭舟。"]'),
('52e62191-de6f-4132-9b42-3353b3552c83','秋日有酬','羅隱','唐','唐诗','tang','','[]','舊業傳家有寶刀，近聞餘力更揮毫。',64,'全唐诗/poet.tang.36000.json','["舊業傳家有寶刀，近聞餘力更揮毫。", "腰間印佩黃金重，卷裏詩裁白雪高。", "讌罷嘉賓迎鳳藻，獵歸諸將問龍韜。", "分茅列土纔三十，猶擬廻頭賭錦袍。"]'),
('5f0643db-fed7-482c-821d-339d292fbb2e','所思','羅隱','唐','唐诗','tang','','[]','梁王兔苑荆榛裏，煬帝雞臺夢想中。',64,'全唐诗/poet.tang.36000.json','["梁王兔苑荆榛裏，煬帝雞臺夢想中。", "只覺惘然悲謝傅，未知何以報文翁。", "生靈不幸台星拆，造化無情世界空。", "劃盡寒灰始堪歎，滿庭霜葉一窗風。"]'),
('15600055-696a-47f0-817c-79e837b79be8','送魏校書兼呈曹使君','羅隱','唐','唐诗','tang','','[]','亂離無計駐生涯，又事東遊惜歲華。',64,'全唐诗/poet.tang.36000.json','["亂離無計駐生涯，又事東遊惜歲華。", "村店酒旗沽竹葉，野橋梅雨泊蘆花。", "讐書發跡官雖屈，負米安親路不賒。", "應見使君論世舊，埽門重得向曹家。"]'),
('bdec1cbe-b0fe-4c00-b212-ed75035cd5aa','四皓廟','羅隱','唐','唐诗','tang','','[]','漢惠秦皇事已聞，廟前高木眼前雲。',32,'全唐诗/poet.tang.36000.json','["漢惠秦皇事已聞，廟前高木眼前雲。", "楚王謾費閑心力，六里青山盡屬君。"]'),
('6ad3cceb-e35a-4b5a-b362-cd6442348299','浮雲','羅隱','唐','唐诗','tang','','[]','溶溶曳曳自舒張，不向蒼梧即帝鄉。',32,'全唐诗/poet.tang.36000.json','["溶溶曳曳自舒張，不向蒼梧即帝鄉。", "莫道無心便無事，也曾愁殺楚襄王。"]'),
('92510ba1-d3e9-4758-986d-cbe94fa8664c','早發','羅隱','唐','唐诗','tang','','[]','北去南來無定居，此生生計竟何如。',32,'全唐诗/poet.tang.36000.json','["北去南來無定居，此生生計竟何如。", "酷憐一覺平明睡，長被雞聲惡破除。"]'),
('7811ce26-7387-43ff-bde2-4489d2d6a668','香','羅隱','唐','唐诗','tang','','[]','沈水良材食柏珍，博山煙煖玉樓春。',32,'全唐诗/poet.tang.36000.json','["沈水良材食柏珍，博山煙煖玉樓春。", "憐君亦是無端物，貪作馨香忘却身。"]'),
('19e0483a-7f2d-4d52-941b-26c22158b0f0','鄴城','羅隱','唐','唐诗','tang','','[]','臺上年年揜翠蛾，臺前高樹夾漳河。',32,'全唐诗/poet.tang.36000.json','["臺上年年揜翠蛾，臺前高樹夾漳河。", "英雄亦到分香處，能共常人較幾多。"]'),
('03dae603-233e-4110-b819-f1f4cdaa8e50','七夕','羅隱','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282"]','絡角星河菡萏天，一家懽笑設紅筵。',64,'全唐诗/poet.tang.36000.json','["絡角星河菡萏天，一家懽笑設紅筵。", "應傾謝女珠璣篋，盡寫檀郎錦繡篇。", "香帳簇成排窈窕，金鍼穿罷拜嬋娟。", "銅壺漏報天將曉，惆悵佳期又一年。"]'),
('6bb037d5-bfd7-4374-866b-b49a217ebd35','送臧濆下第謁竇鄜州','羅隱','唐','唐诗','tang','','[]','賦得長楊不直錢，却來京口看鶯遷。',64,'全唐诗/poet.tang.36000.json','["賦得長楊不直錢，却來京口看鶯遷。", "也知絳灌輕才子，好謁尤常醉少年。", "萬里故鄉雲縹緲，一春生計淚瀾汍。", "多情柱史應相問，與話歸心正浩然。"]'),
('952d21bd-f771-4e05-882d-55e26116b124','清明日曲江懷友','羅隱','唐','唐诗','tang','','[]','君與田蘇即舊遊，我於交分亦綢繆。',64,'全唐诗/poet.tang.36000.json','["君與田蘇即舊遊，我於交分亦綢繆。", "二年隔絕黃泉下，盡日悲涼曲水頭。", "鷗鳥似能齊物理，杏花疑欲伴人愁。", "寡妻稚子應寒食，遙望江陵一淚流。"]'),
('c639a190-62a3-4315-b1b8-ea68063c293e','送鄭州嚴員外','羅隱','唐','唐诗','tang','','[]','欲將刀筆潤王猷，東去先分聖主憂。',64,'全唐诗/poet.tang.36000.json','["欲將刀筆潤王猷，東去先分聖主憂。", "滿扇好風吹鄭圃，一車甘雨別皇州。", "尚書磧冷鴻聲晚，僕射陂寒樹影秋。", "從此文星在何處，武牢關外庾公樓。"]'),
('dcd43c18-526b-47fb-9c80-0864bf9010b0','孫員外赴闕後重到三衢','羅隱','唐','唐诗','tang','','[]','遠山高樹思悠哉，重倚危樓盡一杯。',64,'全唐诗/poet.tang.36000.json','["遠山高樹思悠哉，重倚危樓盡一杯。", "謝守已隨徵詔入，魯儒猶逐斷蓬來。", "地寒謾憶移暄手，時急方須濟世才。", "宣室夜闌如有問，可能全望未然灰。"]'),
('a4c2fb76-79ae-4a19-9023-779674fc00f4','衡陽泊木居士廟下作','羅隱','唐','唐诗','tang','','[]','烏噪殘陽草滿庭，此中枯木似人形。',64,'全唐诗/poet.tang.36000.json','["烏噪殘陽草滿庭，此中枯木似人形。", "只應神物長爲主，未必浮槎即有靈。", "八月風波飄不去，四時黍稷薦惟馨。", "南朝庾信無因賦，牢落祠前水氣腥。"]'),
('55c75a02-2c14-4e7b-abfe-0813bf416aeb','鍾陵見楊秀才','羅隱','唐','唐诗','tang','','[]','孺亭滕閣少踟躕，三度南遊一事無。',64,'全唐诗/poet.tang.36000.json','["孺亭滕閣少踟躕，三度南遊一事無。", "秪覺流年如鳥逝，不知何處有龍屠？", "雲歸洪井枝柯斂，水下漳江氣色麤。", "賴得與君同此醉，醒來愁被鬼揶揄。"]'),
('caa2eb55-7350-4be6-bf41-30b01d397fef','自湘川東下立春泊夏口阻風登孫權城','羅隱','唐','唐诗','tang','','[]','吳門此去逾千里，湘浦離來想數旬。',64,'全唐诗/poet.tang.36000.json','["吳門此去逾千里，湘浦離來想數旬。", "只見風師長占路，不知青帝已行春。", "危憐壞堞猶遮水，狂愛寒梅欲傍人。", "事往時移何足問，且憑村酒暖精神。"]'),
('92c67e23-6445-4765-af73-e8f2cd61c090','春日憶湖南舊遊寄盧校書','羅隱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','旅榜前年過洞庭，曾提刀筆事甘寧。',64,'全唐诗/poet.tang.36000.json','["旅榜前年過洞庭，曾提刀筆事甘寧。", "瑇筵離隔將軍幕，朱履頻窺處士星。", "恩重匣中孤劒在，夢餘江畔數峰青。", "金貂見服嘉賓散，回首昭丘一涕零。"]'),
('c04023e4-bd8a-46ae-9791-8564abfd1870','賀淮南節度盧員外賜緋','羅隱','唐','唐诗','tang','','[]','儉蓮高貴九霄聞，粲粲朱衣降五雲。',64,'全唐诗/poet.tang.36000.json','["儉蓮高貴九霄聞，粲粲朱衣降五雲。", "驄馬早年曾避路，銀魚今日且從軍。", "御題綵服垂天眷，袍展花心透縠紋。", "應笑當年老萊子，鮮華都自降明君。"]'),
('9076aaee-0789-49e6-98f2-c1e6ab75db1e','春日獨遊禪智寺','羅隱','唐','唐诗','tang','','[]','樹遠連天水接空，幾年行樂舊隋宮。',64,'全唐诗/poet.tang.36000.json','["樹遠連天水接空，幾年行樂舊隋宮。", "花開花謝還如此，人去人來自不同。", "鸞鳳調高何處酒，吳牛蹄健滿車風。", "思量只合騰騰醉，煮海平陳一夢中。"]'),
('f1b0e94c-2f46-4d7f-8678-dd9c2448afb0','和淮南李司空同轉運員外','羅隱','唐','唐诗','tang','','[]','層層高閣舊瀛洲，此地須徵第一流。',64,'全唐诗/poet.tang.36000.json','["層層高閣舊瀛洲，此地須徵第一流。", "丞相近年縈倚望，重才今日喜遨遊。", "榮持健筆金黃貴，恨咽離筵管吹秋。", "誰繼伊臯送行句，梁王詩好郢人愁。"]'),
('93c2a2d0-43e3-4dc8-8b04-701f6fe4ed25','后土廟','羅隱','唐','唐诗','tang','','[]','四海兵戈尚未寧，始於雲外學儀形。',64,'全唐诗/poet.tang.36000.json','["四海兵戈尚未寧，始於雲外學儀形。", "九天玄女猶無聖，后土夫人豈有靈。", "一帶好雲侵鬢綠，兩層危岫拂眉青。", "韋郎年少知何在，端坐思量太白經。"]'),
('88590f8c-7514-4583-89e3-048383edb9d9','金陵夜泊','羅隱','唐','唐诗','tang','','[]','冷煙輕澹傍衰叢，此夕秦淮駐斷蓬。',64,'全唐诗/poet.tang.36000.json','["冷煙輕澹傍衰叢，此夕秦淮駐斷蓬。", "棲鴈遠驚沽酒火，亂鵶高避落帆風。", "地銷王氣波聲急，山帶秋陰樹影空。", "六代精靈人不見，思量應在月明中。"]'),
('ba05ac2e-d158-43f4-94e4-3615d9957711','上江州陳員外','羅隱','唐','唐诗','tang','','[]','寒江九派轉城樓，東下鍾陵第一州。',64,'全唐诗/poet.tang.36000.json','["寒江九派轉城樓，東下鍾陵第一州。", "人自中臺方貴盛，地從西晉即風流。", "舊班久望鵷晴翥，餘力猶聞虎夜浮。", "應恨屬官無健令，異時佳節阻閑遊。"]'),
('100c6eef-0d63-4fa6-8fde-4ddab28bdb2b','廣陵開元寺閣上作','羅隱','唐','唐诗','tang','','[]','滿檻山川漾落暉，檻前前事去如飛。',64,'全唐诗/poet.tang.36000.json','["滿檻山川漾落暉，檻前前事去如飛。", "雲中雞犬劉安過，月裏笙歌煬帝歸。", "江蹙海門帆散去，地吞淮口樹相依。", "紅樓翠幕知多少，長向東風有是非。"]'),
('d7fc97e0-ced3-4dd4-a6bd-b13a4ffdc53c','上鄂州韋尚書','羅隱','唐','唐诗','tang','','[]','往歲先皇馭九州，侍臣才業最風流。',64,'全唐诗/poet.tang.36000.json','["往歲先皇馭九州，侍臣才業最風流。", "文窮典誥雖餘力，俗致雍熙盡密謀。", "蘭省換班青作綬，柏臺前引絳爲韝。", "都緣未負江山興，開濟生靈校一秋。"]'),
('5139f923-7a06-4ba7-9445-305ab4cbfd81','早春巴陵道中','羅隱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','遠雪亭亭望未銷，岳陽春淺似相饒。',64,'全唐诗/poet.tang.36000.json','["遠雪亭亭望未銷，岳陽春淺似相饒。", "短蘆冒土初生笋，高柳偷風已弄條。", "波汎洞庭㺍獺健，谷連荆楚鬼神妖。", "中流菱唱泊何處，一隻畫船蘭作橈。"]'),
('57834796-ca3b-48da-a2c4-479de7f577ac','廣陵秋日酬進士臧濆見寄','羅隱','唐','唐诗','tang','','[]','驛西斜日滿窗前，獨凭秋欄思渺綿。',64,'全唐诗/poet.tang.36000.json','["驛西斜日滿窗前，獨凭秋欄思渺綿。", "數尺斷蓬慚故國，一輪清鏡泣流年。", "已知世事真徒爾，縱有心期亦偶然。", "空媿荀家好兄弟，鴈來魚去是因緣。"]'),
('06ecfe6e-3519-4398-9c97-c88411d0c172','淮南送李司空朝覲','羅隱','唐','唐诗','tang','','[]','聖君宵旰望時雍，丹詔西來雨露濃。',64,'全唐诗/poet.tang.36000.json','["聖君宵旰望時雍，丹詔西來雨露濃。", "宣父道高休歎鳳，武侯才大本吟龍。", "九州似鼎終須負，萬物爲銅只待鎔。", "臘後春前更何事，便看經度奏東封。"]'),
('029aeaa0-04a3-44a0-acc3-9fde814364a1','秋日禪智寺見裴郎中題名寄韋瞻','羅隱','唐','唐诗','tang','','[]','野寺疎鐘萬木秋，偶尋題處認名侯。',64,'全唐诗/poet.tang.36000.json','["野寺疎鐘萬木秋，偶尋題處認名侯。", "官離南郡應閑暇，地勝東山想駐留。", "百醆濃醪成別夢，兩行垂露澣羈愁。", "心知只有韋公在，更對真蹤話舊遊。"]'),
('21648e35-1869-4ed9-b0ab-0164cbd5d350','廣陵春日憶池陽有寄','羅隱','唐','唐诗','tang','','[]','煙水濛濛接板橋，數年經歷駐征橈。',64,'全唐诗/poet.tang.36000.json','["煙水濛濛接板橋，數年經歷駐征橈。", "醉凭危檻波千頃，愁倚長亭柳萬條。", "別後故人冠獬豸，病來知己賞鷦鷯。", "清流夾宅千家住，會向閑乘一信潮。"]'),
('192c1e45-f73f-4022-bc3a-21c42d37f215','春中湘中題岳麓寺僧舍','羅隱','唐','唐诗','tang','','[]','蟾宮虎穴兩皆休，來凭危欄送遠愁。',64,'全唐诗/poet.tang.36000.json','["蟾宮虎穴兩皆休，來凭危欄送遠愁。", "多事林鶯還謾語，薄情邊鴈不迴頭。", "春融只待乾坤醉，水闊深知世界浮。", "欲共高僧話心迹，野花芳草奈相尤。"]'),
('7a0fcbfe-77cb-4467-b71f-c3bd224770cc','出試後投所知','羅隱','唐','唐诗','tang','','[]','此日蓬壺兩日程，當時消息甚分明。',64,'全唐诗/poet.tang.36000.json','["此日蓬壺兩日程，當時消息甚分明。", "桃須曼倩催方熟，橘待洪崖遣始行。", "島外音書應有意，眼前塵士漸無情。", "莫教更似山西鼠，嚙破愁腸恨一生。"]'),
('de174f95-3f82-4ae0-8a51-72ed1433a535','湘南春日懷古','羅隱','唐','唐诗','tang','','[]','晴江春暖蘭蕙薰，鳧鷖苒苒鷗著羣。',64,'全唐诗/poet.tang.36000.json','["晴江春暖蘭蕙薰，鳧鷖苒苒鷗著羣。", "洛陽賈誼自無命，少陵杜甫兼有文。", "空闊遠帆遮落日，蒼茫野樹礙歸雲。", "松醪酒好昭潭靜，閑過中流一弔君。"]'),
('6e968ec9-1a22-460a-868e-6837ca27bb0b','江州望廬山','羅隱','唐','唐诗','tang','','["\u5e90\u5c71"]','東南蒼翠何崔嵬，橫流一望幽抱開。',64,'全唐诗/poet.tang.36000.json','["東南蒼翠何崔嵬，橫流一望幽抱開。", "影寒已令水底去，脚闊欲過湖心來。", "深處不唯容鬼怪，暗中兼恐有風雷。", "仙人往往今誰在，紅杏花香重首迴。"]'),
('9d93cfde-5557-4ab8-b28f-808a3b59ebc3','金陵寄竇尚書','羅隱','唐','唐诗','tang','','[]','二年岐路有西東，長憶優游楚驛中。',64,'全唐诗/poet.tang.36000.json','["二年岐路有西東，長憶優游楚驛中。", "虎帳談高無客繼，馬卿官傲少人同。", "世危肯使依劉表，山好猶能憶謝公。", "此去此恩言不得，謾將閑淚對春風。"]'),
('a4e6c438-0ac0-466b-978f-55406614eb6f','清溪江令公宅','羅隱','唐','唐诗','tang','','[]','蠻牋象管夜深時，曾賦陳宮第一詩。',64,'全唐诗/poet.tang.36000.json','["蠻牋象管夜深時，曾賦陳宮第一詩。", "宴罷風流人不見，廢來蹤跡草應知。", "鶯憐勝事啼空巷，蜨戀餘香舞好枝。", "還有往年金甃井，牧童樵叟等閑窺。"]'),
('7b3a753f-67ba-4020-8826-2963274a0f01','鄭州獻盧舍人','羅隱','唐','唐诗','tang','','[]','海槎閑暇閬風輕，不是安流不肯行。',64,'全唐诗/poet.tang.36000.json','["海槎閑暇閬風輕，不是安流不肯行。", "雞省露濃湯餅熟，鳳池煙暖詔書成。", "漁籌已合光儒夢，堯印何妨且治兵。", "會將兩都收復後，右圖儀表左題名。"]'),
('63b55463-0bd6-4860-a98b-52ff237f651b','別池陽所居','羅隱','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','黃塵初起此留連，火耨刀耕六七年。',64,'全唐诗/poet.tang.36000.json','["黃塵初起此留連，火耨刀耕六七年。", "雨夜老農傷水旱，雪晴漁父共舟船。", "已悲世亂身須去，肯媿途危跡屢遷。", "却是九華山有意，列行相送到江邊。"]'),
('f9c642c7-9100-4a82-ad7c-6e6f60419114','送內使周大夫自杭州朝貢','羅隱','唐','唐诗','tang','','[]','八都上將近平戎，便附輶軒奏聖聰。',64,'全唐诗/poet.tang.36000.json','["八都上將近平戎，便附輶軒奏聖聰。", "三接駕前朝覲禮，一函江表戰征功。", "雲間閬苑何時見，水底瑤池觸處通。", "知有殿庭餘力在，莫辭消息寄西風。"]'),
('4a30f782-738e-4dde-9d80-f5a917996397','酬黃從事懷舊見寄','羅隱','唐','唐诗','tang','','[]','舊遊不合到心中，把得君詩意亦同。',64,'全唐诗/poet.tang.36000.json','["舊遊不合到心中，把得君詩意亦同。", "水館酒闌清夜月，香街人散白楊風。", "長繩繫日雖難絆，辨口談天不易窮。", "世事自隨蓬轉在，思量何處是飛蓬。"]'),
('c962f237-a2cc-4e62-a3a7-25b7417bf6dc','繡','羅隱','唐','唐诗','tang','','[]','一片絲羅□□□，洞房西室女工勞。',64,'全唐诗/poet.tang.36000.json','["一片絲羅□□□，洞房西室女工勞。", "花隨玉指添春色，鳥逐金鍼長羽毛。", "蜀綿謾誇聲自貴，越綾虛說價功高。", "可中用作鴛鴦被，紅葉枝枝不礙刀。"]'),
('cde7b687-57dd-4d31-9df6-54c0866898d0','西施','羅隱','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u54f2\u7406", "\u548f\u53f2\u6000\u53e4"]','家國興亡自有時，吳人何苦怨西施。',32,'全唐诗/poet.tang.36000.json','["家國興亡自有時，吳人何苦怨西施。", "西施若解傾吳國，越國亡來又是誰。"]'),
('e1f5f07c-296e-4cb6-96a8-5ffdedb281a7','自遣','羅隱','唐','唐诗','tang','','[]','得即高歌失即休，多愁多恨亦悠悠。',32,'全唐诗/poet.tang.36000.json','["得即高歌失即休，多愁多恨亦悠悠。", "今朝有酒今朝醉，明日愁來明日愁。"]'),
('e18496a5-bf1d-46ba-aa86-5665375e216b','白角箆','羅隱','唐','唐诗','tang','','[]','白似瓊瑤滑似苔，隨梳伴鏡拂塵埃。',32,'全唐诗/poet.tang.36000.json','["白似瓊瑤滑似苔，隨梳伴鏡拂塵埃。", "莫言此箇尖頭物，幾度撩人惡髪來。"]'),
('59f2348b-aa54-4e2a-8d38-bb7ff2915aa3','銅雀臺','羅隱','唐','唐诗','tang','','[]','強歌強舞竟難勝，花落花開淚滿膺。',32,'全唐诗/poet.tang.36000.json','["強歌強舞竟難勝，花落花開淚滿膺。", "秪合當年伴君死，免交憔悴望西陵。"]'),
('0e682aca-7b51-4956-acc8-d5a1ccae3e67','鸚鵡','羅隱','唐','唐诗','tang','','[]','莫恨雕籠翠羽殘，江南地暖隴西寒。',32,'全唐诗/poet.tang.36000.json','["莫恨雕籠翠羽殘，江南地暖隴西寒。", "勸君不用分明語，語得分明出轉難。"]'),
('456b097e-1668-4610-9bae-c293ac126bc0','金錢花','羅隱','唐','唐诗','tang','','[]','占得佳名繞樹芳，依依相伴向秋光。',32,'全唐诗/poet.tang.36000.json','["占得佳名繞樹芳，依依相伴向秋光。", "若教此物堪收貯，應被豪門盡劚將。"]'),
('1f204352-241f-417d-b73a-4343c4747bb3','梅','羅隱','唐','唐诗','tang','','[]','天賜胭脂一抹腮，盤中磊落笛中哀。',32,'全唐诗/poet.tang.36000.json','["天賜胭脂一抹腮，盤中磊落笛中哀。", "雖然未得和羹便，曾與將軍止渴來。"]'),
('e1b51918-4187-4fcb-8cc8-75fb9ec7ffd2','錢尚父生日','羅隱','唐','唐诗','tang','','[]','大昴分光降斗牛，興唐宗社作諸侯。',64,'全唐诗/poet.tang.36000.json','["大昴分光降斗牛，興唐宗社作諸侯。", "伊夔事業扶千載，韓白機謀冠九州。", "貴盛上持龍節鉞，延長應續鶴春秋。", "錦衣玉食將何報，更俟莊椿一舉頭。"]'),
('93f09284-25ae-4f76-b76a-fb673bb6ed77','寄前戶部陸郎中','羅隱','唐','唐诗','tang','','[]','出馴桑雉入朝簪，蕭灑清名映士林。',64,'全唐诗/poet.tang.36000.json','["出馴桑雉入朝簪，蕭灑清名映士林。", "近日篇章欺白雪，早年詞賦得黃金。", "桂堂縱道探龍頷，蘭省何曾駐鶴心。", "離亂事多人不會，酒濃花暖且閑吟。"]'),
('b198d059-b980-4ecc-8ed9-c38c7e184aa6','登瓦棺寺閣','羅隱','唐','唐诗','tang','','[]','下盤空跡上雲浮，偶逐僧行步步愁。',64,'全唐诗/poet.tang.36000.json','["下盤空跡上雲浮，偶逐僧行步步愁。", "暫憩已知須用意，漸來爭忍不回頭。", "煙中樹老重江晚，鐸外風輕四境秋。", "嬾指臺城更東望，鵲飛龍鬬盡荒丘。"]'),
('f24d9b8f-386d-4ecc-a4d3-55c0804d3835','九華山費徵君所居','羅隱','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','草堂何處試徘徊，見說遺蹤向此開。',64,'全唐诗/poet.tang.36000.json','["草堂何處試徘徊，見說遺蹤向此開。", "蟾桂自歸三徑後，鶴書曾降九天來。", "白雲事跡依前在，青瑣光陰竟不迴。", "盡夕爲君思曩日，野泉嗚咽路莓苔。"]'),
('0c75c844-f3a0-4c3d-ae1f-6b5705ac4c85','途中寄懷','羅隱','唐','唐诗','tang','','[]','不知何處是前程，合眼騰騰信馬行。',64,'全唐诗/poet.tang.36000.json','["不知何處是前程，合眼騰騰信馬行。", "兩鬢已衰時未遇，數峰雖在病相攖。", "塵埃鞏洛虛光景，詩酒江湖漫姓名。", "試哭軍門看誰問，舊來還似禰先生。"]'),
('09a804e8-62f9-4c47-80bb-3915f9121b7a','京口見李侍郎','羅隱','唐','唐诗','tang','','[]','傞傞江柳欲矜春，鐵甕城邊見故人。',64,'全唐诗/poet.tang.36000.json','["傞傞江柳欲矜春，鐵甕城邊見故人。", "屈指不堪言甲子，披風常記是庚申。", "別來且喜身俱健，亂後休悲業盡貧。", "還有杖頭沽酒物，待尋山寺話逡巡。"]'),
('e3ab19da-bdc0-4fbc-a75b-62ada09c72af','秋日酬張特玄','羅隱','唐','唐诗','tang','','[]','病寄南徐兩度秋，故人依約亦揚州。',64,'全唐诗/poet.tang.36000.json','["病寄南徐兩度秋，故人依約亦揚州。", "偶因鴈足思閑事，擬棹孤舟訪舊遊。", "風急幾聞江上笛，月高誰共酒家樓。", "平生意氣消磨盡，甘露軒前看水流。"]'),
('52f90da3-5fc8-4e09-b856-2c80a27a2f17','登高詠菊盡','羅隱','唐','唐诗','tang','','[]','籬畔霜前偶得存，苦教遲晚避蘭蓀。',64,'全唐诗/poet.tang.36000.json','["籬畔霜前偶得存，苦教遲晚避蘭蓀。", "能銷造化幾多力，不受陽和一點恩。", "生處豈容依玉砌，要時還許上金罇。", "陶公沒後無知己，露滴幽叢見淚痕。"]'),
('69e5e32c-8412-4701-9f07-b0cee0756dbe','登夏州城樓','羅隱','唐','唐诗','tang','','[]','寒城獵獵戍旗風，獨倚危樓悵望中。',64,'全唐诗/poet.tang.36000.json','["寒城獵獵戍旗風，獨倚危樓悵望中。", "萬里山河唐土地，千年魂魄晉英雄。", "離心不忍聽邊馬，往事應須問塞鴻。", "好脫儒冠從校尉，一枝長戟六鈞弓。"]'),
('e6a66f66-b1de-4b37-ae64-b92e6aaa5e69','水邊偶題','羅隱','唐','唐诗','tang','','[]','野水無情去不回，水邊花好爲誰開。',64,'全唐诗/poet.tang.36000.json','["野水無情去不回，水邊花好爲誰開。", "只知事逐眼前去，不覺老從頭上來。", "窮似丘軻休歎息，達如周召亦塵埃。", "思量此理何人會，蒙邑先生最有才。"]'),
('eef8f4a0-d61f-4ed9-b6a2-74f8dfb30a9b','故洛陽公鎮大梁時隱得遊門下今之經歷事往人非聊抒所懷以傷以謝','羅隱','唐','唐诗','tang','','[]','孤舟欲泊思何窮，曾憶西來值雪中。',64,'全唐诗/poet.tang.36000.json','["孤舟欲泊思何窮，曾憶西來值雪中。", "珠履少年初滿座，白衣遊子也從公。", "狂拋賦筆琉璃冷，醉倚歌筵瑇瑁紅。", "今日斯文向誰說，淚碑棠樹兩成空。"]'),
('46825354-bda0-48c1-86df-04d40b0233dc','杜陵秋思','羅隱','唐','唐诗','tang','','[]','南望商於北帝都，兩堪棲託兩無圖。',64,'全唐诗/poet.tang.36000.json','["南望商於北帝都，兩堪棲託兩無圖。", "只聞斥逐張公子，不覺悲同楚大夫。", "巖畔早涼生紫桂，井邊疎影落高梧。", "一杯淥酒他年憶，瀝向青波寄五湖。"]'),
('df5004da-4e92-4ea7-a130-3a62ad0cdc80','隱嘗在江陵忝故中令白公叨蒙知遇今復重過渚宮感事悲身遂成長句','羅隱','唐','唐诗','tang','','[]','往歲酇侯鎮渚宮，曾將清律暖孤蓬。',64,'全唐诗/poet.tang.36000.json','["往歲酇侯鎮渚宮，曾將清律暖孤蓬。", "才憐曼倩三冬後，藝許由基一箭中。", "言重不能輕薄命，地寒終是泣春風。", "鳳凰池涸台星拆，迴首岐山憶至公。"]'),
('e0a9b920-b9ed-460f-b7c3-0f12fbc61597','夜泊毘陵無錫縣有寄','羅隱','唐','唐诗','tang','','[]','草蟲幽咽樹初團，獨繫孤舟夜已闌。',64,'全唐诗/poet.tang.36000.json','["草蟲幽咽樹初團，獨繫孤舟夜已闌。", "濁浪勢奔吳苑急，疎鐘聲徹惠山寒。", "愁催鬢髪凋何易，貧戀家鄉別漸難。", "他日親朋應大笑，始知書劒是無端。"]'),
('8302c621-3c77-4308-9542-e2003c831a70','桃花','羅隱','唐','唐诗','tang','','[]','暖觸衣襟漠漠香，閒梅遮柳不勝芳。',64,'全唐诗/poet.tang.36000.json','["暖觸衣襟漠漠香，閒梅遮柳不勝芳。", "數枝豔拂文君酒，半里紅欹宋玉牆。", "盡日無人疑悵望，有時經雨乍淒涼。", "舊山山下還如此，廻首東風一斷腸。"]'),
('282a3626-fcad-43fc-81c3-7c6d616d7aca','籌筆驛','羅隱','唐','唐诗','tang','','["\u5199\u4eba", "\u6000\u53e4", "\u5199\u4eba\u8bd7"]','拋擲南陽爲主憂，北征東討盡良籌。',64,'全唐诗/poet.tang.36000.json','["拋擲南陽爲主憂，北征東討盡良籌。", "時來天地皆同力，運去英雄不自由。", "千里山河輕孺子，兩朝冠劒恨譙周。", "唯餘巖下多情水，猶解年年傍驛流。"]'),
('7463fb4d-0d38-446a-95ca-28b8b305efb7','重過隨州故兵部李侍郎恩知因抒長句','羅隱','唐','唐诗','tang','','[]','莊周高論伯牙琴，閑夜思量淚滿襟。',64,'全唐诗/poet.tang.36000.json','["莊周高論伯牙琴，閑夜思量淚滿襟。", "四海共誰言近事，九原從此負初心。", "鷗翻漢浦風波急，鴈下鄖溪霧雨深。", "慙媿蒼生還有意，解歌襦袴至如今。"]'),
('3b319d0c-9e24-401c-918e-90f328e78813','商於驛樓東望有感','羅隱','唐','唐诗','tang','','[]','山川去接漢江東，曾伴隋侯醉此中。',64,'全唐诗/poet.tang.36000.json','["山川去接漢江東，曾伴隋侯醉此中。", "歌繞夜梁珠宛轉，舞嬌春席雪朦朧。", "棠遺善政陰猶在，薤送哀聲事已空。", "惆悵知音竟難得，兩行清淚白楊風。"]'),
('ba643b30-19e2-4219-b0b5-00b41ca5fbe3','寄南城韋逸人','羅隱','唐','唐诗','tang','','[]','杜甫詩中韋曲花，至今無賴尚豪家。',64,'全唐诗/poet.tang.36000.json','["杜甫詩中韋曲花，至今無賴尚豪家。", "美人曉折露沾袖，公子醉時香滿車。", "萬里丹青傳不得，二年風雨恨無涯。", "羨他南澗高眠客，春去春來任物華。"]'),
('dcca7f52-22eb-4259-b9a7-86e6dd1b6938','梅花','羅隱','唐','唐诗','tang','','[]','吳王醉處十餘里，照野拂衣今正繁。',64,'全唐诗/poet.tang.36000.json','["吳王醉處十餘里，照野拂衣今正繁。", "經雨不隨山鳥散，倚風疑共路人言。", "愁憐粉豔飄歌席，靜愛寒香撲酒罇。", "欲寄所思無好信，爲人惆恨又黃昏。"]'),
('f345e4ae-4e49-4370-9a20-83dab7b30feb','淮南高駢所造迎仙樓','羅隱','唐','唐诗','tang','','[]','鸞音鶴信杳難迴，鳳駕龍車早晚來。',64,'全唐诗/poet.tang.36000.json','["鸞音鶴信杳難迴，鳳駕龍車早晚來。", "仙境是誰知處所，人間空自造樓臺。", "雲侵朱檻應難到，蟲網閑窗永不開。", "子細思量成底事，露凝風擺作塵埃。"]'),
('7eacb0e2-b501-4a74-9d95-7157411f3074','和禪月大師見贈','羅隱','唐','唐诗','tang','','[]','高僧惠我七言詩，頓豁塵心展白眉。',64,'全唐诗/poet.tang.36000.json','["高僧惠我七言詩，頓豁塵心展白眉。", "秀似谷中花媚日，清如潭底月圓時。", "應觀法界蓮千葉，肯折人間桂一枝。", "漂蕩秦吳十餘載，因循猶恨識師遲。"]'),
('84926f6f-bc31-4657-9eda-faa140b3a4a9','謁文宣王廟','羅隱','唐','唐诗','tang','','[]','晚來乘興謁先師，松柏淒淒人不知。',64,'全唐诗/poet.tang.36000.json','["晚來乘興謁先師，松柏淒淒人不知。", "九仭蕭牆堆瓦礫，三間茅殿走狐狸。", "雨淋狀似悲麟泣，露滴還同歎鳳悲。", "儻使小儒名稍立，豈教吾道受栖遲。"]'),
('57c0a387-0e79-4207-9e1f-0fa4f6c810e0','代文宣王答','羅隱','唐','唐诗','tang','','[]','三教之中儒最尊，止戈爲武武尊文。',64,'全唐诗/poet.tang.36000.json','["三教之中儒最尊，止戈爲武武尊文。", "吾今尚自披蓑笠，你等何須讀典墳。", "釋氏寶樓侵碧漢，道家宮殿拂青雲。", "若教顏閔英靈在，終不羞他李老君。"]'),
('d9c9e3b8-9873-498e-aafe-767730ad8e09','重送朗州張員外','羅隱','唐','唐诗','tang','','[]','朱輪此去正春風，且駐青雲聽斷蓬。',64,'全唐诗/poet.tang.36000.json','["朱輪此去正春風，且駐青雲聽斷蓬。", "一榻早年容孺子，雙旌今日別文翁。", "誠知汲善心長在，爭奈干時跡轉窮。", "酬德酬恩兩無路，謾勞惆悵鳳城東。"]'),
('d2f27ade-d6fc-4054-b48b-6d532251936a','廣陵秋夜讀進士常修三篇因題','羅隱','唐','唐诗','tang','','[]','入蜀歸吳三首詩，藏於笥篋重於師。',64,'全唐诗/poet.tang.36000.json','["入蜀歸吳三首詩，藏於笥篋重於師。", "劒關夜讀相如聽，瓜步秋吟煬帝悲。", "景物也知輸健筆，時情誰不許高枝。", "明年二月春風裏，江島閑人慰所思。"]'),
('b742aada-da27-4eac-a72e-525d247710b4','逼試投所知','羅隱','唐','唐诗','tang','','[]','桃在仙翁舊苑傍，暖煙輕靄撲人香。',64,'全唐诗/poet.tang.36000.json','["桃在仙翁舊苑傍，暖煙輕靄撲人香。", "十年此地頻偷眼，二月春風最斷腸。", "曾恨夢中無好事，也知囊裏有仙方。", "尋思仙骨終難得，始與回頭問玉皇。"]'),
('9e8709a4-746f-4baa-8ec2-ba4d8a33f0ed','漢江上作','羅隱','唐','唐诗','tang','','[]','漢江波浪淥於苔，每到江邊病眼開。',64,'全唐诗/poet.tang.36000.json','["漢江波浪淥於苔，每到江邊病眼開。", "半雨半風終日恨，無名無跡幾時迴。", "雲生岸谷秋陰合，樹接帆檣晚思來。", "對此空慚聖明代，忍教纓上有塵埃。"]'),
('63f2aab5-c61c-47c6-823d-8a3bee66a995','秋夜寄進士顧榮','羅隱','唐','唐诗','tang','','[]','秋河耿耿夜沈沈，往事三更盡到心。',64,'全唐诗/poet.tang.36000.json','["秋河耿耿夜沈沈，往事三更盡到心。", "多病謾勞窺聖代，薄才終是費知音。", "家山夢後帆千尺，塵土搔來髪一簪。", "空羨良朋盡高價，可憐東箭與南金。"]'),
('b9bae62a-2375-49dd-bc16-f87c56ff4bdf','寄渭北徐從事','羅隱','唐','唐诗','tang','','[]','暖雲慵墮柳垂條，驄馬徐郎過渭橋。',64,'全唐诗/poet.tang.36000.json','["暖雲慵墮柳垂條，驄馬徐郎過渭橋。", "官秩舊參荀祕監，罇罍今伴霍嫖姚。", "科隨鵠箭頻曾中，禮向侯弓以重招。", "莫恨東風促行李，不多時節却歸朝。"]'),
('1b9690d8-210e-4fd3-8d15-940cb667b67c','徐寇南逼感事獻江南知己次韻','羅隱','唐','唐诗','tang','','[]','酒闌離思浩無窮，西望維揚憶數公。',64,'全唐诗/poet.tang.36000.json','["酒闌離思浩無窮，西望維揚憶數公。", "萬里飄零身未了，一家知獎意曾同。", "雲橫晉國塵應暗，路轉吳江信不通。", "今日便成盧子諒，滿襟珠淚墮霜風。"]'),
('c652b9aa-0ac6-4540-8626-998427441552','寄三衢孫員外','羅隱','唐','唐诗','tang','','[]','小敷文伯見何時，南望三衢渴復飢。',64,'全唐诗/poet.tang.36000.json','["小敷文伯見何時，南望三衢渴復飢。", "天子未能崇典誥，諸生徒欲戀旌旗。", "風高綠野苗千頃，露冷平樓酒滿巵。", "盡是數旬陪奉處，使君爭肯不相思。"]'),
('00516f98-ea15-4848-8755-8c5cbd3e7bcf','淮南送盧端公歸臺','羅隱','唐','唐诗','tang','','[]','鳳鸞勢逸九霄寬，北去南來任羽翰。',64,'全唐诗/poet.tang.36000.json','["鳳鸞勢逸九霄寬，北去南來任羽翰。", "朱紱兩參王儉府，繡衣三領杜林官。", "道從上國曾匡濟，才向牢盆始重難。", "應笑張綱謾生事，埋輪不得在長安。"]'),
('109b216f-fc72-4d02-aae9-1830a8e50986','煬帝陵','羅隱','唐','唐诗','tang','','[]','入郭登橋出郭船，紅樓日日柳年年。',32,'全唐诗/poet.tang.36000.json','["入郭登橋出郭船，紅樓日日柳年年。", "君王忍把平陳業，只博雷塘數畝田。"]'),
('656306ec-e597-401b-bb9c-8967763151f5','馬嵬坡','羅隱','唐','唐诗','tang','','[]','佛屋前頭野草春，貴妃輕骨此爲塵。',32,'全唐诗/poet.tang.36000.json','["佛屋前頭野草春，貴妃輕骨此爲塵。", "從來絕色知難得，不破中原未是人。"]'),
('9a935c45-8f29-496b-a6c7-0362682c8c5d','柳','羅隱','唐','唐诗','tang','','[]','灞岸晴來送別頻，相偎相倚不勝春。',32,'全唐诗/poet.tang.36000.json','["灞岸晴來送別頻，相偎相倚不勝春。", "自家飛絮猶無定，爭解垂絲絆路人。"]'),
('1f0e0004-ed06-4c9b-966b-6b726215c8ea','隋堤柳','羅隱','唐','唐诗','tang','','[]','夾路依依千里遙，路人回首認隋朝。',32,'全唐诗/poet.tang.36000.json','["夾路依依千里遙，路人回首認隋朝。", "春風未借宣華意，猶費工夫長綠條。"]'),
('8a03df58-e9f4-4936-a6b5-a2ba5530cbf6','孟浩然墓','羅隱','唐','唐诗','tang','','[]','數步荒榛接舊蹊，寒江漠漠草淒淒。',32,'全唐诗/poet.tang.36000.json','["數步荒榛接舊蹊，寒江漠漠草淒淒。", "鹿門黃土無多少，恰到書生塚便低。"]'),
('adce9f9c-538c-45f2-938f-4d4143f4973c','秦紀','羅隱','唐','唐诗','tang','','[]','長策東鞭及海隅，黿鼉奔起鬼神趨。',32,'全唐诗/poet.tang.36000.json','["長策東鞭及海隅，黿鼉奔起鬼神趨。", "憐君未到沙丘日，肯信人間有死無。"]'),
('6729c05a-c777-4a24-8be6-bc9d469c5bd2','仙掌','羅隱','唐','唐诗','tang','','[]','掌前流水駐無塵，掌下軒車日日新。',32,'全唐诗/poet.tang.36000.json','["掌前流水駐無塵，掌下軒車日日新。", "謾向山頭高舉手，何曾招得路行人。"]'),
('e9e266c5-d56f-4ed0-8d24-f076150762cf','詠月','羅隱','唐','唐诗','tang','','[]','湖上風高動白蘋，暫延清景此逡巡。',64,'全唐诗/poet.tang.36000.json','["湖上風高動白蘋，暫延清景此逡巡。", "隔年違別成何事，半夜相看似故人。", "蟾向靜中矜爪距，兔隈明處弄精神。", "嫦娥老大應惆悵，倚泣蒼蒼桂一輪。"]'),
('47c8f00d-4417-4e61-93eb-203f19bdcb2c','宿荆州江陵驛','羅隱','唐','唐诗','tang','','[]','西遊象闕媿知音，東下荆溪稱越吟。',64,'全唐诗/poet.tang.36000.json','["西遊象闕媿知音，東下荆溪稱越吟。", "風動芰荷香四散，月明樓閣影相侵。", "閒欹別枕千般夢，醉送征帆萬里心。", "薜荔衣裳木蘭檝，異時煙雨好追尋。"]'),
('d0fbdee0-1149-4129-86f9-29414c55ba5c','撫州別阮兵曹','羅隱','唐','唐诗','tang','','[]','雪晴天外見諸峰，幽軋行輪有去蹤。',64,'全唐诗/poet.tang.36000.json','["雪晴天外見諸峰，幽軋行輪有去蹤。", "內史宅邊今獨恨，步兵廚畔舊相容。", "十年別鬢疑朝鏡，千里歸心著晚鐘。", "若不他時更青眼，未知誰肯薦臨邛。"]'),
('a9476a76-abc6-45b4-b36e-94847f866e9f','新安投所知','羅隱','唐','唐诗','tang','','[]','少年容易捨樵漁，曾辱明公薦子虛。',64,'全唐诗/poet.tang.36000.json','["少年容易捨樵漁，曾辱明公薦子虛。", "漢殿寒夜時不食，宋都風急命何疎。", "雲埋野艇吟歸去，草沒山田賦遂初。", "長劒一尋歌一奏，此心爭肯爲鱸魚。"]'),
('f6caa5b9-9b73-41eb-b973-68037062e935','江邊有寄','羅隱','唐','唐诗','tang','','[]','江邊舊業半彫殘，每軫歸心即萬端。',64,'全唐诗/poet.tang.36000.json','["江邊舊業半彫殘，每軫歸心即萬端。", "狂折野梅山店暖，醉吹村笛酒樓寒。", "只言聖代謀身易，爭奈貧儒得路難。", "同病同憂更何事，爲君提筆畫漁竿。"]'),
('2f54a309-e8ea-435c-a619-761d42169ff5','送友人歸夷門','羅隱','唐','唐诗','tang','','[]','二年流落大梁城，每送君歸即有情。',64,'全唐诗/poet.tang.36000.json','["二年流落大梁城，每送君歸即有情。", "別路算來成底事，舊遊言著似前生。", "苑荒嬾認詞人會，門在空憐烈士名。", "至竟男兒分應定，不須惆悵谷中鶯。"]'),
('f9292b45-fde7-41c4-a79d-6219186cd031','湘中見進士喬詡','羅隱','唐','唐诗','tang','','[]','吳公臺下別經秋，破虜城邊暫駐留。',64,'全唐诗/poet.tang.36000.json','["吳公臺下別經秋，破虜城邊暫駐留。", "一笑有情堪解夢，數年無故不同遊。", "雲牽楚思橫魚艇，柳送鄉心入酒樓。", "且酌松醪依舊醉，誰能相見向春愁。"]'),
('598adc93-bfca-4bf3-be85-a5048ec4bcca','上霅川裴郎中','羅隱','唐','唐诗','tang','','[]','貴提金印出咸秦，瀟灑江城兩度春。',64,'全唐诗/poet.tang.36000.json','["貴提金印出咸秦，瀟灑江城兩度春。", "一派水清疑見膽，數重山翠欲留人。", "望崇早合歸黃閣，詩好何妨戀白蘋。", "自是受恩心未足，却垂雙翅羨吳均。"]'),
('d703eb74-ba16-42cc-b86c-d7433fdfa7e8','錢塘江潮','羅隱','唐','唐诗','tang','','["\u94b1\u5858\u6c5f"]','怒聲洶洶勢悠悠，羅剎江邊地欲浮。',64,'全唐诗/poet.tang.36000.json','["怒聲洶洶勢悠悠，羅剎江邊地欲浮。", "漫道往來存大信，也知反覆向平流。", "任拋巨浸疑無底，猛過西陵只有頭。", "至竟朝昏誰主掌，好騎赬鯉問陽侯。"]'),
('a5ac046b-bd19-489b-919d-563595326370','送人赴職任褒中','羅隱','唐','唐诗','tang','','[]','物態時情難重陳，夫君此去莫傷春。',64,'全唐诗/poet.tang.36000.json','["物態時情難重陳，夫君此去莫傷春。", "男兒只要有知己，才子何堪更問津。", "萬轉江山通蜀國，兩行珠翠見褒人。", "海棠花謝東風老，應念京都共苦辛。"]'),
('e31d2a65-13f0-4242-81c3-0c205d2b9486','臨川投穆中丞','羅隱','唐','唐诗','tang','','[]','試將生計問蓬根，心委寒灰首戴盆。',64,'全唐诗/poet.tang.36000.json','["試將生計問蓬根，心委寒灰首戴盆。", "翅弱未知三島路，舌頑虛掉五侯門。", "嘯煙白狖沈高木，擣月清砧觸旅魂。", "家在碧江歸不得，十年魚艇長苔痕。"]'),
('d6640c0c-32b0-48f7-adbd-6709ec39ea77','早春送張坤歸大梁','羅隱','唐','唐诗','tang','','[]','蕭蕭羸馬正塵埃，又送輶軒向吹臺。',64,'全唐诗/poet.tang.36000.json','["蕭蕭羸馬正塵埃，又送輶軒向吹臺。", "別酒莫辭今夜醉，故人知是幾時回。", "泉經華岳猶應凍，花到梁園始合開。", "爲謝東門抱關吏，不堪惆悵滿離杯。"]'),
('08d59a44-af3e-40cc-ab1e-5baef4aa0737','東歸途中作','羅隱','唐','唐诗','tang','','[]','松橘蒼黃覆釣磯，早年生計近年違。',64,'全唐诗/poet.tang.36000.json','["松橘蒼黃覆釣磯，早年生計近年違。", "老知風月終堪恨，貧覺家山不易歸。", "別岸客帆和鴈落，晚程霜葉向人飛。", "買臣嚴助精靈在，應笑無成一布衣。"]'),
('2384ff33-19d4-4417-a53b-dd3640722046','送進士臧濆下第後歸池州','羅隱','唐','唐诗','tang','','[]','賦成無處換黃金，却向春風動越吟。',64,'全唐诗/poet.tang.36000.json','["賦成無處換黃金，却向春風動越吟。", "天子愛才雖仄席，諸生多病又沾襟。", "柳攀灞岸狂遮袂，水憶池陽淥滿心。", "珍重綵衣歸正好，莫將閑事繫升沈。"]'),
('e17df864-ff93-4234-8565-45dbab852beb','湘中贈范鄖','羅隱','唐','唐诗','tang','','[]','丹桂無心彼此諳，二年疎嬾共江潭。',64,'全唐诗/poet.tang.36000.json','["丹桂無心彼此諳，二年疎嬾共江潭。", "愁知酒醆終難捨，老覺人情轉不堪。", "雲外鴛鴦非故舊，眼前膠漆似煙嵐。", "勞歌一曲霜風暮，擊折湘妃白玉簪。"]'),
('d50b42bf-ebbc-4adb-8a5a-47db62eee71c','寄張侍郎','羅隱','唐','唐诗','tang','','[]','衰羸豈合話荆州，爭奈思多不自由。',64,'全唐诗/poet.tang.36000.json','["衰羸豈合話荆州，爭奈思多不自由。", "無路重趨桓典馬，有詩曾上仲宣樓。", "塵銷別跡堪垂淚，樹拂他門嬾舉頭。", "一種人間太平日，獨教零落憶滄州。"]'),
('1e2eb811-aed9-4712-ba96-a7ef06c0d4c3','渚宮秋思','羅隱','唐','唐诗','tang','','[]','楚城日暮煙靄深，楚人駐馬還登臨。',64,'全唐诗/poet.tang.36000.json','["楚城日暮煙靄深，楚人駐馬還登臨。", "襄王臺下水無賴，神女廟前雲有心。", "千載是非難重問，一江風雨好閑吟。", "欲招屈宋當時魄，蘭敗荷枯不可尋。"]'),
('3723f8d8-27d0-4aff-9df6-34c9430afec0','閑居早秋','羅隱','唐','唐诗','tang','','[]','槐杪清蟬煙雨餘，蕭蕭涼葉墮衣裾。',64,'全唐诗/poet.tang.36000.json','["槐杪清蟬煙雨餘，蕭蕭涼葉墮衣裾。", "噪槎烏散沈蒼嶺，弄杵風高上碧虛。", "百歲夢生悲蛺蜨，一朝香死泣芙蕖。", "六宮誰買相如賦，團扇恩情日日疎。"]'),
('37f23f6c-4575-4dbf-b621-392c22beef99','建康','羅隱','唐','唐诗','tang','','[]','潮平遠岸草侵沙，東晉衰來最可嗟。',64,'全唐诗/poet.tang.36000.json','["潮平遠岸草侵沙，東晉衰來最可嗟。", "庾舅已能窺帝室，王都還是預人家。", "山寒老樹啼風曲，泉暖枯骸動芷牙。", "欲起九原看一徧，秦淮聲急日西斜。"]'),
('0df6f1cf-96fc-4341-b1e7-09d703ea95a6','送舒州宿松縣傅少府','羅隱','唐','唐诗','tang','','[]','江蘺漠漠樹重重，東過清淮到宿松。',64,'全唐诗/poet.tang.36000.json','["江蘺漠漠樹重重，東過清淮到宿松。", "縣好也知臨浣水，官閑應得看灊峰。", "春風綠野吳歌怨，雪霽平郊楚酒濃。", "留取餘杯待張翰，明年歸棹一從容。"]'),
('943080c5-852b-47ea-a2b2-9cd2e194719d','經故洛陽城','羅隱','唐','唐诗','tang','','[]','敗垣危堞跡依稀，試駐羸驂弔落暉。',64,'全唐诗/poet.tang.36000.json','["敗垣危堞跡依稀，試駐羸驂弔落暉。", "跋扈以成梁冀在，簡書難問杜喬歸。", "由來世事須翻覆，未必餘才解是非。", "千載昆陽好功業，與君門下作恩威。"]'),
('6aab3187-1815-49eb-9072-3df6036c2988','夏州胡常侍','羅隱','唐','唐诗','tang','','[]','百尺高臺勃勃州，大刀長戟漢諸侯。',64,'全唐诗/poet.tang.36000.json','["百尺高臺勃勃州，大刀長戟漢諸侯。", "征鴻過盡邊雲闊，戰馬閑來塞草秋。", "國計已推肝膽許，家財不爲子孫謀。", "仍聞隴蜀由多事，深喜將軍未白頭。"]'),
('497b1b34-1b9e-47a8-a971-9ee55f53470c','寄進士盧休','羅隱','唐','唐诗','tang','','[]','半年池口恨萍蓬，今日思量已夢中。',64,'全唐诗/poet.tang.36000.json','["半年池口恨萍蓬，今日思量已夢中。", "遊子馬蹄難重到，故人尊酒與誰同。", "山橫翠後千重綠，蠟想歌時一燼紅。", "從此客程君不見，麥秋梅雨徧江東。"]'),
('59341040-7f21-497f-a7a5-bfbdcd1cd6e5','贈先輩令狐補闕','羅隱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','中間聲跡早薰然，阻避鈞衡過十年。',64,'全唐诗/poet.tang.36000.json','["中間聲跡早薰然，阻避鈞衡過十年。", "碧海浪高終濟物，蒼梧雲好已歸天。", "花迎綵服離鶯谷，柳傍東風觸馬鞭。", "應念淒涼洞庭客，夜深雙淚憶漁船。"]'),
('abe585c2-58ba-4dd7-ad20-f8f6df7805b2','送秦州從事','羅隱','唐','唐诗','tang','','[]','一枝何足解人愁，拋却還隨定遠侯。',64,'全唐诗/poet.tang.36000.json','["一枝何足解人愁，拋却還隨定遠侯。", "紫陌紅塵今別恨，九衢雙闕夜同遊。", "芳時易失勞行止，良會難期且駐留。", "若到邊庭有來使，試批書尾話梁州。"]'),
('dbb3c751-ed46-4634-bfaa-e07ccc696efe','湖州裴郎中赴闕後投簡寄友生','羅隱','唐','唐诗','tang','','[]','錦帳郎官塞詔年，汀州曾駐木蘭船。',64,'全唐诗/poet.tang.36000.json','["錦帳郎官塞詔年，汀州曾駐木蘭船。", "禰衡酒醒春瓶倒，柳惲詩成海月圓。", "歌蹙遠山珠滴滴，漏催香燭淚漣漣。", "使君入拜吾徒在，宣室他時豈偶然。"]'),
('3ca5a4eb-2ac8-4426-8e47-5d5681dcb9fc','秋日泊平望驛寄太常裴郎中','羅隱','唐','唐诗','tang','','[]','蘋洲重到杳難期，西倚郵亭憶往時。',64,'全唐诗/poet.tang.36000.json','["蘋洲重到杳難期，西倚郵亭憶往時。", "北海尊中常有酒，東陽樓上豈無詩。", "地清每負生靈望，官重方升禮樂司。", "聞說江南舊歌曲，至今猶自唱吳姬。"]'),
('6ce1451f-5e44-4ebb-80ea-6f0c6c91d5e9','西塞山','羅隱','唐','唐诗','tang','','[]','吳塞當時指此山，吳都亡後綠孱顏。',64,'全唐诗/poet.tang.36000.json','["吳塞當時指此山，吳都亡後綠孱顏。", "嶺梅乍暖殘妝恨，沙鳥初晴小隊閑。", "波闊魚龍應混雜，壁危猿狖奈姦頑。", "會將一副寒蓑笠，來與漁翁作往還。"]'),
('ebff189e-a2fa-42e8-a008-827abb2b0ff3','秋日汴河客舍酬友人','羅隱','唐','唐诗','tang','','[]','梁宋追遊早歲同，偶然違別事皆空。',64,'全唐诗/poet.tang.36000.json','["梁宋追遊早歲同，偶然違別事皆空。", "年如流水催何急，道似危途動即窮。", "醉舞且欣連夜月，狂吟還聚上樓風。", "煩君更枉騷人句，白鳳靈虵滿袖中。"]'),
('2f2e79a1-e504-422a-90c4-c398bc9dc47d','東歸','羅隱','唐','唐诗','tang','','[]','仙桂高高似有神，貂裘敝盡取無因。',64,'全唐诗/poet.tang.36000.json','["仙桂高高似有神，貂裘敝盡取無因。", "難將白髮期公道，不覺丹枝屬別人。", "雙闕往來慙請謁，五湖歸後恥交親。", "盈盤紫蟹千巵酒，添得臨岐淚滿巾。"]'),
('f96f3c83-6ec5-4523-9d33-782f7129f4b2','廣陵李僕射借示近詩因投獻','羅隱','唐','唐诗','tang','','[]','朝論國計暮論兵，餘力猶隨鳳藻生。',64,'全唐诗/poet.tang.36000.json','["朝論國計暮論兵，餘力猶隨鳳藻生。", "語繼盤盂拋俗格，氣兼河岳帶商聲。", "閑尋綺思千花麗，靜想高吟六義清。", "天柄已持堯典在，更堪回首問緣情。"]'),
('397d8aed-01e9-4f40-93b8-1dd63636e148','三衢哭孫員外','羅隱','唐','唐诗','tang','','[]','燕戀雕梁馬戀軒，此心從此更何言。',64,'全唐诗/poet.tang.36000.json','["燕戀雕梁馬戀軒，此心從此更何言。", "直將塵外三生命，未敵君侯一日恩。", "紅蠟有時還入夢，片帆何處獨銷魂？", "忍看明發衣襟上，珠淚痕中見酒痕。"]'),
('af82dc0f-3a0c-4ff4-bd21-c9309f4a7de5','篋中得故王郎中書','羅隱','唐','唐诗','tang','','[]','鳳里前年別望郎，丁寧唯恐滯吳鄉。',64,'全唐诗/poet.tang.36000.json','["鳳里前年別望郎，丁寧唯恐滯吳鄉。", "勸疎杯酒知妨事，乞與書題作裹糧。", "苹鹿未能移海曲，縣花尋已落河陽。", "九原自此無因見，反覆遺蹤淚萬行。"]'),
('6d4cfc91-a317-437e-b1db-e814d9f7e6bb','淚','羅隱','唐','唐诗','tang','','[]','逼臉橫頤咽復勻，也曾讒毀也傷神。',32,'全唐诗/poet.tang.36000.json','["逼臉橫頤咽復勻，也曾讒毀也傷神。", "自從魯國潸然後，不是姦人即婦人。"]'),
('9a8ce2d8-72a5-47ed-a33e-ed9d7b3620ad','子規','羅隱','唐','唐诗','tang','','[]','銅梁路遠草青青，此恨那堪枕上聽。',32,'全唐诗/poet.tang.36000.json','["銅梁路遠草青青，此恨那堪枕上聽。", "一種有冤猶可報，不如銜石疊滄溟。"]'),
('158f4c90-4cfe-425b-bf44-32d9a286cd08','姑蘇臺','羅隱','唐','唐诗','tang','','[]','讓高泰伯開基日，賢見延陵復命時。',32,'全唐诗/poet.tang.36000.json','["讓高泰伯開基日，賢見延陵復命時。", "未會子孫因底事，解崇臺榭爲西施。"]'),
('a50426bd-bae7-4cf5-8087-f5be82570c53','王濬墓','羅隱','唐','唐诗','tang','','[]','男兒未必盡英雄，但到時來即命通。',32,'全唐诗/poet.tang.36000.json','["男兒未必盡英雄，但到時來即命通。", "若使吳都猶王氣，將軍何處立殊功。"]'),
('0f5bdc9f-bf16-4e43-b9ce-bcd65348d156','京中晚望','羅隱','唐','唐诗','tang','','[]','心如野鹿跡如萍，謾向人間性一靈。',32,'全唐诗/poet.tang.36000.json','["心如野鹿跡如萍，謾向人間性一靈。", "往事不知多少夢，夜來和酒一時醒。"]'),
('df280adc-ffab-48b3-b3bb-affe22a73caf','寄竇澤處士二首 一','羅隱','唐','唐诗','tang','','[]','蘭亭醉客舊知聞，欲問平安隔海雲。',32,'全唐诗/poet.tang.36000.json','["蘭亭醉客舊知聞，欲問平安隔海雲。", "不是金陵錢太尉，世事誰肯更容身。"]'),
('b5cae4e5-5bc8-487d-8dbc-e998dfe8553e','寄竇澤處士二首 二','羅隱','唐','唐诗','tang','','[]','鼇背樓臺拂白榆，此中槎客亦踟躕。',32,'全唐诗/poet.tang.36000.json','["鼇背樓臺拂白榆，此中槎客亦踟躕。", "牢山道士無仙骨，却向人間作酒徒。"]'),
('5e37b9d8-3ea8-485f-adf2-a3a01f08d803','省試秋風生桂枝','羅隱','唐','唐诗','tang','','[]','涼吹從何起，中宵景象清。',72,'全唐诗/poet.tang.36000.json','["涼吹從何起，中宵景象清。", "漫隨雲葉動，高傍桂枝生。", "漠漠看無際，蕭蕭別有聲。", "遠吹斜漢轉，低拂白榆輕。", "寥泬工夫大，乾坤歲序更。", "因悲遠歸客，長望一枝榮。"]'),
('bde97bac-83f5-400a-9678-88b15d2de8ed','思故人','羅隱','唐','唐诗','tang','','[]','故人不可見，聊復拂鳴琴。',48,'全唐诗/poet.tang.36000.json','["故人不可見，聊復拂鳴琴。", "鵲繞風枝急，螢藏露草深。", "平生四方志，此夜五湖心。", "惆悵友朋盡，洋洋漫好音。"]'),
('be478254-6ea4-4a09-9338-b4b3e6f68f5c','寄陸龜蒙','羅隱','唐','唐诗','tang','','[]','龍樓李丞相，昔歲仰高文。',48,'全唐诗/poet.tang.36000.json','["龍樓李丞相，昔歲仰高文。", "黃閣尋無主，青山竟未焚。", "夜船乘海月，秋寺伴江雲。", "却恐塵埃裏，浮名點污君。"]'),
('abd05c77-a74d-4137-9ab9-13aa44f9249c','題方干詩','羅隱','唐','唐诗','tang','','[]','中間李建州，夏汭偶同遊。',48,'全唐诗/poet.tang.36000.json','["中間李建州，夏汭偶同遊。", "顧我論佳句，推君最上流。", "九霄無鶴板，雙鬢老漁舟。", "世難方如此，何當浣旅愁。"]'),
('65b819eb-f3d9-43b1-a8ff-510bf02fb397','秋江','羅隱','唐','唐诗','tang','','[]','秋江待晚潮，客歸斾旌搖。',48,'全唐诗/poet.tang.36000.json','["秋江待晚潮，客歸斾旌搖。", "細雨翻蘆葉，高風却柳條。", "兵戈村落破，饑儉虎狼驕。", "吾土兼連此，離魂望裏消。"]'),
('74bb3931-e96a-4d7d-97c1-f635abe052f0','寄制誥李舍人','羅隱','唐','唐诗','tang','','[]','梁王握豹韜，雪裏見枚臯。',48,'全唐诗/poet.tang.36000.json','["梁王握豹韜，雪裏見枚臯。", "上客趨丹陛，遊人歎二毛。", "門閑知待詔，星動想濡毫。", "一首長楊賦，應嫌索價高。"]'),
('b8aba680-09a8-4db6-9639-b370f25d2a89','秋日懷孟夷庚','羅隱','唐','唐诗','tang','','[]','秋日黃陂下，孤舟憶共誰。',36,'全唐诗/poet.tang.36000.json','["秋日黃陂下，孤舟憶共誰。", "江山三分楚，風雨二妃祠。", "知己秦貂沒，流年賈鵩悲。"]'),
('37349bd5-df05-478f-a312-0f80b060d972','送李右丞分司','羅隱','唐','唐诗','tang','','[]','分漕得洛川，讜議更昭然。',48,'全唐诗/poet.tang.36000.json','["分漕得洛川，讜議更昭然。", "在省曾批敕，中臺肯避權。", "所悲時漸薄，共賀道由全。", "賣與清平代，相兼直幾錢。"]'),
('bd9cf968-9a0c-4df8-9bbd-dfeb8c2fba21','郴江遷客','羅隱','唐','唐诗','tang','','[]','不是逢清世，何由見皂囊。',48,'全唐诗/poet.tang.36000.json','["不是逢清世，何由見皂囊。", "事雖危虎尾，名勝泊鵷行。", "毒霧郴江闊，愁雲楚驛長。", "歸時有詩賦，一爲弔沈湘。"]'),
('467d64c8-a182-4939-8cac-65c10d4cea3b','感舊','羅隱','唐','唐诗','tang','','[]','劒佩孫弘閣，戈鋋太尉營。',48,'全唐诗/poet.tang.36000.json','["劒佩孫弘閣，戈鋋太尉營。", "重言虛有位，孤立竟無成。", "丘隴笳簫咽，池臺歲月平。", "此恩何以報，歸處是柴荆。"]'),
('0eac8763-a9f9-4d87-837d-572185bcb594','鷹','羅隱','唐','唐诗','tang','','[]','越海霜天暮，辭韜野草乾。',48,'全唐诗/poet.tang.36000.json','["越海霜天暮，辭韜野草乾。", "俊通司隸職，嚴奉武夫官。", "眼惡藏蜂在，心麤逐物殫。", "近來脂膩足，驅遣不妨難。"]'),
('4142ae0c-d062-451b-952d-3456b909d19a','秋日寄狄補闕','羅隱','唐','唐诗','tang','','[]','紅塵擾擾間，立馬看南山。',48,'全唐诗/poet.tang.36000.json','["紅塵擾擾間，立馬看南山。", "謾道經年往，何妨逐日閑。", "病中霜葉赤，愁裏鬢毛斑。", "不爲良知在，驅車已出關。"]'),
('f4a3bbd8-63a3-41a1-b561-663a0188e7a7','寄易定公乘億侍郎','羅隱','唐','唐诗','tang','','[]','謝舞仍宮柳，高奇世少雙。',48,'全唐诗/poet.tang.36000.json','["謝舞仍宮柳，高奇世少雙。", "侍中生不到，園令死須降。", "班秩通烏府，罇罍奉碧幢。", "昭王有餘烈，試爲禱迷邦。"]'),
('7a3e7589-6d3a-4b75-83b8-9f4a5489262e','寄大理徐郎中','羅隱','唐','唐诗','tang','','[]','佐棘竟誰同，因思證聖中。',48,'全唐诗/poet.tang.36000.json','["佐棘竟誰同，因思證聖中。", "事雖忘顯報，理合有陰功。", "官序詵枝老，幽塵范甑空。", "幾時潘好禮，重與話清風。"]'),
('cdee7e1d-ae6d-449f-a361-508b279fe539','寄蘇拾遺','羅隱','唐','唐诗','tang','','[]','早歲長楊賦，當年諫獵書。',48,'全唐诗/poet.tang.36000.json','["早歲長楊賦，當年諫獵書。", "格高時輩伏，言數宦情疎。", "慷慨傳丹桂，艱難保舊居。", "退朝觀藁草，能望馬相如。"]'),
('ead5fb8e-39c8-48c9-a34c-a8e5b51832eb','寄許融','羅隱','唐','唐诗','tang','','[]','多病仍疎拙，唯君與我同。',48,'全唐诗/poet.tang.36000.json','["多病仍疎拙，唯君與我同。", "帝鄉年共老，江徼業俱空。", "燕冷辭華屋，蛩涼恨曉叢。", "白雲高幾許，全屬採芝翁。"]'),
('ee828e9b-fa64-48ce-9b18-d19717987396','寄禮部鄭員外','羅隱','唐','唐诗','tang','','[]','欒郄門風大，裴王禮樂優。',48,'全唐诗/poet.tang.36000.json','["欒郄門風大，裴王禮樂優。", "班資冠雞舌，人品壓龍頭。", "夜直爐香細，晴編疏草稠。", "近聞潘散騎，三十二悲秋。"]'),
('8a480259-5451-4f83-8ca9-6b099d2bfc4c','菊','羅隱','唐','唐诗','tang','','[]','籬落歲云暮，數枝聊自芳。',48,'全唐诗/poet.tang.36000.json','["籬落歲云暮，數枝聊自芳。", "雪裁纖蘂密，金拆小苞香。", "千載白衣酒，一生青女霜。", "春叢莫輕薄，彼此有行藏。"]'),
('903c2e05-04ca-4177-81e2-e68f917b4d3b','臺城','羅隱','唐','唐诗','tang','','[]','水國春常在，臺城夜未寒。',48,'全唐诗/poet.tang.36000.json','["水國春常在，臺城夜未寒。", "麗華承寵渥，江令捧杯盤。", "宴罷明堂爛，詩成寶炬殘。", "兵來吾有計，金井玉鉤欄。"]'),
('9d5564a4-bca5-45ed-8a14-b578250b0e77','舊遊','羅隱','唐','唐诗','tang','','[]','良時不復再，漸老更難言。',48,'全唐诗/poet.tang.36000.json','["良時不復再，漸老更難言。", "遠水猶經眼，高樓似斷魂。", "依依宋玉宅，歷歷長卿村。", "今日空江畔，相於只酒樽。"]'),
('92deabd7-56ff-4257-bd98-f2dbe25bb63f','寄虔州薛大夫','羅隱','唐','唐诗','tang','','[]','祝融峰下別，三載夢魂勞。',48,'全唐诗/poet.tang.36000.json','["祝融峰下別，三載夢魂勞。", "地轉南康重，官兼亞相高。", "海鵬終負日，神馬背眠槽。", "會得窺成績，幽窗染兔毫。"]'),
('c6733060-b6c9-412e-8c94-5147a0a7b1d1','蘇小小墓','羅隱','唐','唐诗','tang','','[]','魂兮檇李城，猶未有人耕。',48,'全唐诗/poet.tang.36000.json','["魂兮檇李城，猶未有人耕。", "好月當年事，殘花觸處情。", "向誰曾豔冶，隨分得聲名。", "應侍吳王宴，蘭橈暗送迎。"]'),
('53d14187-5e4f-4c09-8999-44cf9a9e7044','寒食日早出城東','羅隱','唐','唐诗','tang','','[]','青門欲曙天，車馬已喧闐。',48,'全唐诗/poet.tang.36000.json','["青門欲曙天，車馬已喧闐。", "禁柳疎風雨，牆花拆露鮮。", "向誰誇麗景，只是歎流年。", "不得高飛便，迴頭望紙鳶。"]'),
('b7765e7f-ba4c-4d42-86c1-d7bdcb894858','秋日懷賈隨進士','羅隱','唐','唐诗','tang','','[]','邊寇日騷動，故人音信稀。',48,'全唐诗/poet.tang.36000.json','["邊寇日騷動，故人音信稀。", "長纓慙賈誼，孤憤憶韓非。", "曉匣魚腸冷，春園鴨掌肥。", "知君安未得，聊且示忘機。"]'),
('9f44f93e-dc0c-4ce4-8ff3-376a75c57ea5','亂後逢友人','羅隱','唐','唐诗','tang','','[]','滄海去未得，倚舟聊問津。',48,'全唐诗/poet.tang.36000.json','["滄海去未得，倚舟聊問津。", "生靈寇盜盡，方鎮改更貧。", "夢裏舊行處，眼前新貴人。", "從來事如此，君莫獨霑巾。"]'),
('a9ca03f2-120a-469f-9df6-535a160b9a4d','殘花','羅隱','唐','唐诗','tang','','[]','已歎良時晚，仍悲別酒催。',48,'全唐诗/poet.tang.36000.json','["已歎良時晚，仍悲別酒催。", "暖芳隨日薄，輕片逐風迴。", "黛斂愁歌扇，妝殘泣鏡臺。", "繁陰莫矜衒，終是共塵埃。"]'),
('274e3283-a3aa-49e8-876a-397f8aa7aced','秋日富春江行','羅隱','唐','唐诗','tang','','[]','遠岸平如翦，澄江靜似鋪。',48,'全唐诗/poet.tang.36000.json','["遠岸平如翦，澄江靜似鋪。", "紫鱗仙客馭，金顆李衡奴。", "冷疊羣山闊，清涵萬象殊。", "嚴陵亦高見，歸臥是良圖。"]'),
('a505b7a3-9631-46f7-9dba-7a17a413908d','寄侯博士','羅隱','唐','唐诗','tang','','[]','規諫揚雄賦，邅迴賈誼官。',48,'全唐诗/poet.tang.36000.json','["規諫揚雄賦，邅迴賈誼官。", "久貧還往少，孤立轉遷難。", "清鏡流年急，高槐旅舍寒。", "侏儒亦何有，飽食向長安。"]'),
('5c7d0e82-2c24-4866-a158-3b418686bfdb','送沈光侍御赴職閩中','羅隱','唐','唐诗','tang','','[]','未至應居右，全家出帝鄉。',48,'全唐诗/poet.tang.36000.json','["未至應居右，全家出帝鄉。", "禮優逢苑雪，官重帶臺霜。", "夜浦吳潮吼，春灘建水狂。", "延平有風雨，從此是騰驤。"]'),
('5a6635ba-e3c0-4aea-b75a-15bd79de18b5','寄袁皓侍郎','羅隱','唐','唐诗','tang','','[]','東臺失路岐，榮辱事堪悲。',48,'全唐诗/poet.tang.36000.json','["東臺失路岐，榮辱事堪悲。", "我寢牛衣敝，君居豸角危。", "風塵慙上品，才業愧明時。", "千里芙蓉幕，何由話所思。"]'),
('479bfb22-e8d0-4675-acfc-9b14b8f2be8d','寄金吾李蓀常侍','羅隱','唐','唐诗','tang','','[]','西班掌禁兵，蘭錡最分明。',48,'全唐诗/poet.tang.36000.json','["西班掌禁兵，蘭錡最分明。", "曉色嚴天仗，春寒避火城。", "安危雖已任，韜略即嘉聲。", "請問何功德，壺關寇始平。"]'),
('d41c1519-3e03-4a11-b1d2-495dca280343','商於驛與于蘊玉話別','羅隱','唐','唐诗','tang','','[]','南朝徐庾流，洛下憶同遊。',48,'全唐诗/poet.tang.36000.json','["南朝徐庾流，洛下憶同遊。", "酒采閑坊菊，山登遠寺樓。", "相思勞寄夢，偶別已經秋。", "還被青青桂，催君不自由。"]'),
('2ec66fc5-f59d-48b6-8b93-3b37285f518c','封禪寺居','羅隱','唐','唐诗','tang','','[]','盛禮何由覩，嘉名偶寄居。',48,'全唐诗/poet.tang.36000.json','["盛禮何由覩，嘉名偶寄居。", "周南太史淚，蠻徼長卿書。", "砌竹搖風直，庭花泣露疎。", "誰能賦秋興，千里隔吾廬。"]'),
('0cb01fab-d4ec-45f0-b3fc-0f3216b08489','錢','羅隱','唐','唐诗','tang','','[]','志士不敢道，貯之成禍胎。',48,'全唐诗/poet.tang.36000.json','["志士不敢道，貯之成禍胎。", "小人無事藝，假爾作梯媒。", "解釋愁腸結，能分睡眼開。", "朱門狼虎性，一半逐君回。"]'),
('04657fcb-1d6b-4602-9f49-6dad410298b4','投寄韋右丞','羅隱','唐','唐诗','tang','','[]','赤壁徵文聘，中臺拜郄詵。',60,'全唐诗/poet.tang.36000.json','["赤壁徵文聘，中臺拜郄詵。", "官資參令僕，曹署轄星辰。", "幞被從誰起，持綱自此新。", "舉朝明典教，封納詔書頻。", "禁樹曾摛藻，臺烏舊避塵。"]'),
('1f1220b8-28ca-4ded-b86b-11a6f4a7c0e7','紅葉','羅隱','唐','唐诗','tang','','[]','不奈荒城畔，那堪晚照中。',48,'全唐诗/poet.tang.36000.json','["不奈荒城畔，那堪晚照中。", "野晴霜浥綠，山冷雨催紅。", "遊子灞陵道，美人長信宮。", "等閑居歲暮，搖落意無窮。"]'),
('aaafa3c0-094c-402f-8610-c706151403bf','期徐道者不至','羅隱','唐','唐诗','tang','','[]','遼鶴虛空語，冥鴻未易親。',48,'全唐诗/poet.tang.36000.json','["遼鶴虛空語，冥鴻未易親。", "偶然來即是，必擬見無因。", "霜霰窮冬令，杯盤旅舍貧。", "只應薊子訓，醉後懶分身。"]'),
('132ac8aa-4524-482a-90bc-35498821b663','歲除夜','羅隱','唐','唐诗','tang','','[]','官曆行將盡，村醪強自傾。',48,'全唐诗/poet.tang.36000.json','["官曆行將盡，村醪強自傾。", "厭寒思暖律，畏老惜殘更。", "歲月已如此，寇戎猶未平。", "兒童不諳事，歌吹待天明。"]'),
('fd9f5498-6508-420a-a943-80951767c24a','雪','羅隱','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u5199\u96ea", "\u96ea"]','盡道豐年瑞，豐年事若何。',24,'全唐诗/poet.tang.36000.json','["盡道豐年瑞，豐年事若何。", "長安有貧者，爲瑞不宜多。"]'),
('3f16be97-3fdf-4508-963d-43104abcff2f','旅夢','羅隱','唐','唐诗','tang','','[]','旅夢思遷次，窮愁有歎嗟。',48,'全唐诗/poet.tang.36000.json','["旅夢思遷次，窮愁有歎嗟。", "子鵝京口遠，粳米會稽賒。", "漏澀纔成滴，燈寒不作花。", "出門聊一望，蟾桂向人斜。"]'),
('bbe2f128-c873-4659-9c4a-4f0501660450','秋寄張坤','羅隱','唐','唐诗','tang','','[]','庭樹已黃落，閉門俱寂寥。',48,'全唐诗/poet.tang.36000.json','["庭樹已黃落，閉門俱寂寥。", "未知棲託處，空羨聖明朝。", "酒醒鄉心闊，雲晴客思遙。", "吾徒自多感，顏子只簞瓢。"]'),
('d8d5aa06-577c-4aba-8fa5-f169d1295d5e','傷華髪','羅隱','唐','唐诗','tang','','[]','舊國迢迢遠，清秋種種新。',48,'全唐诗/poet.tang.36000.json','["舊國迢迢遠，清秋種種新。", "已衰曾軫慮，初見忽霑巾。", "日薄梳兼嬾，根危鑷恐頻。", "青銅不自見，只擬老他人。"]'),
('457e4b9d-7a1b-4c6d-89fc-cf834b93771e','九江早秋','羅隱','唐','唐诗','tang','','[]','雨過晚涼生，樓中枕簟清。',48,'全唐诗/poet.tang.36000.json','["雨過晚涼生，樓中枕簟清。", "海風吹亂木，巖磬落孤城。", "百歲幾多日，四蹄無限程。", "西鄰莫高唱，俱是別離情。"]'),
('36166023-ac59-44e9-bdd6-5f637a9facf4','初秋寄友人','羅隱','唐','唐诗','tang','','[]','九華曾屏跡，罹亂與心違。',48,'全唐诗/poet.tang.36000.json','["九華曾屏跡，罹亂與心違。", "是處堪終老，新秋又未歸。", "病中芳草歇，愁裏白雲飛。", "樵侶兼同志，音書近亦稀。"]'),
('a6412981-f3d1-4051-b7b6-5fe5fe0b885c','秋居有寄','羅隱','唐','唐诗','tang','','[]','端居湖岸東，生計有無中。',48,'全唐诗/poet.tang.36000.json','["端居湖岸東，生計有無中。", "魘處千般鬼，寒時百種風。", "性靈縱道拙，心事奈成空。", "多謝金臺客，何當一笑同。"]'),
('26aab409-d6fc-4be7-8e95-030cdb5e486c','雪霽','羅隱','唐','唐诗','tang','','[]','南山雪乍晴，寒氣轉崢嶸。',48,'全唐诗/poet.tang.36000.json','["南山雪乍晴，寒氣轉崢嶸。", "銷却閑門出，隨他駿馬行。", "一竿如有計，五鼎豈須烹。", "愁見天街草，青青又欲生。"]'),
('1ddef908-251a-42a9-ad6e-930f4886d00c','堠子','羅隱','唐','唐诗','tang','','[]','終日路岐旁，前程亦可量。',48,'全唐诗/poet.tang.36000.json','["終日路岐旁，前程亦可量。", "未能慙面黑，只是恨頭方。", "雅旨逾千里，高文近兩行。", "君知不識字，第一莫形相。"]'),
('131bd556-b400-40a1-9cf6-6671ee1b468f','初夏寄顧紹宗','羅隱','唐','唐诗','tang','','[]','江上偶分袂，四回寒暑更。',48,'全唐诗/poet.tang.36000.json','["江上偶分袂，四回寒暑更。", "青山無路入，白髮滿頭生。", "郢浦鴈尋過，鏡湖蟬又鳴。", "憐君未歸日，杯酒若爲情。"]'),
('14c5376f-dec8-4920-ac45-3e88c1db3150','寄第五尊師','羅隱','唐','唐诗','tang','','[]','苕溪煙月久因循，野鶴衣裘獨繭綸。',64,'全唐诗/poet.tang.36000.json','["苕溪煙月久因循，野鶴衣裘獨繭綸。", "只說泊船無定處，不知攜手是何人。", "朱黃揀日囚尸鬼，青白臨時注腦神。", "欲訪先生問經訣，世間難得不由身。"]'),
('8080ac2d-a841-4a83-a512-f6d0c5d61072','寄西華黃鍊師','羅隱','唐','唐诗','tang','','[]','西華有路入中華，依約山川認永嘉。',64,'全唐诗/poet.tang.36000.json','["西華有路入中華，依約山川認永嘉。", "羽客昔時留篠簜，故人今又種煙霞。", "壇高已降三清鶴，海近應通八月槎。", "盛事兩般君總得，老萊衣服戴顒家。"]'),
('97ccfd55-fff6-41fb-968a-4421d9c44803','所思','羅隱','唐','唐诗','tang','','[]','西上青雲未有期，東歸滄海一何遲。',64,'全唐诗/poet.tang.36000.json','["西上青雲未有期，東歸滄海一何遲。", "酒闌夢覺不稱意，花落月明空所思。", "長恐病侵多事日，可堪貧過少年時。", "鬬雞走狗五陵道，惆悵輸他輕薄兒。"]'),
('c761a2ee-bb55-4192-9a12-2ba8eb341156','送支使蕭中丞赴闕','羅隱','唐','唐诗','tang','','[]','八年刀筆到京華，歸去青冥路未賒。',64,'全唐诗/poet.tang.36000.json','["八年刀筆到京華，歸去青冥路未賒。", "今日風流卿相客，舊時基業帝王家。", "彤庭彩鳳雖添瑞，望府紅蓮已減花。", "從此常僚如有問，海邊麇鹿斗邊槎。"]'),
('9a606ef7-8a48-474d-a800-12b9667c43b2','送人歸湘中兼寄舊知','羅隱','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','青溪煙雨九華山，亂後應同夢寐間。',64,'全唐诗/poet.tang.36000.json','["青溪煙雨九華山，亂後應同夢寐間。", "萬里分飛休掩袂，兩旬相見且開顏。", "君依宰相貉蟬貴，我戀王門鬢髪斑。", "爲謝伏波筵上客，幾時金印擬西還。"]'),
('8bb5983c-9cae-4e89-9eee-fb07f20be96c','自貽','羅隱','唐','唐诗','tang','','[]','衰老應難更進趨，藥畦經卷自朝晡。',64,'全唐诗/poet.tang.36000.json','["衰老應難更進趨，藥畦經卷自朝晡。", "縱無顯效亦藏拙，若有所成甘守株。", "漢武巡遊虛軋軋，秦皇吞併謾驅驅。", "如何只見丁家鶴，依舊遼東歎綠蕪。"]'),
('2345ff52-26aa-4bfa-b41c-3ff2320cb5f2','暇日感懷因寄同院吳蛻拾遺','羅隱','唐','唐诗','tang','','[]','璧池清秩訪燕臺，曾捧瀛州札翰來。',64,'全唐诗/poet.tang.36000.json','["璧池清秩訪燕臺，曾捧瀛州札翰來。", "今日二難俱大夜，當時三幅謾高才。", "戲悲槐市便便笥，狂憶樟亭滿滿杯。", "猶幸小蘭同舍在，每因相見即銜哀。"]'),
('0a7967ec-05e0-40b9-84e2-07889e817cb7','偶興','羅隱','唐','唐诗','tang','','[]','逐隊隨行二十春，曲江池畔避車塵。',32,'全唐诗/poet.tang.36000.json','["逐隊隨行二十春，曲江池畔避車塵。", "如今贏得將衰老，閑看人間得意人。"]'),
('55a77027-05df-4909-9d2c-ec41e83606cc','題鑿石山僧院','羅隱','唐','唐诗','tang','','[]','日夜潮聲送是非，一迴登眺一忘機。',32,'全唐诗/poet.tang.36000.json','["日夜潮聲送是非，一迴登眺一忘機。", "憐師好事無人見，不把蘭芽染褐衣。"]'),
('1bb652cd-890a-4457-87b3-2805735b7234','圉城偶作','羅隱','唐','唐诗','tang','','[]','東望陳留日欲曛，每因刀筆想夫君。',32,'全唐诗/poet.tang.36000.json','["東望陳留日欲曛，每因刀筆想夫君。", "自從郭泰碑銘後，只見黃金不見文。"]'),
('ccbad745-971e-43b0-8cf5-45c815886c0f','烏程','羅隱','唐','唐诗','tang','','[]','兩府攀陪十五年，郡中甘雨幕中蓮。',32,'全唐诗/poet.tang.36000.json','["兩府攀陪十五年，郡中甘雨幕中蓮。", "一瓶猶是烏程酒，須對霜風度泫然。"]'),
('a90dd720-cd19-4f65-a6ad-cbe8c7456853','送楊鍊師却歸貞浩巖','羅隱','唐','唐诗','tang','','[]','宦途不復更經營，歸去東南任意行。',64,'全唐诗/poet.tang.36000.json','["宦途不復更經營，歸去東南任意行。", "別後幾回思會面，到來相見似前生。", "久居竹蓋知勤苦，舊業蓮峰想變更。", "爲謝佯狂吳道士，耳中時有鐵船聲。"]'),
('0b2f935d-adca-41d3-9d60-65dfdfa9ee6f','暇日投錢尚父','羅隱','唐','唐诗','tang','','[]','牛斗星邊女宿間，棟梁虛敞麗江關。',64,'全唐诗/poet.tang.36000.json','["牛斗星邊女宿間，棟梁虛敞麗江關。", "望高漢相東西閣，名重淮王大小山。", "禮設鬬傾金鑿落，馬蹄爭撼玉連環。", "自慙麇鹿無能事，未報深恩鬢已斑。"]'),
('acca0a2a-2d2d-4aff-ab26-70b61e5eab53','覽晉史','羅隱','唐','唐诗','tang','','[]','齊王僚屬好男兒，偶覓東歸便得歸。',64,'全唐诗/poet.tang.36000.json','["齊王僚屬好男兒，偶覓東歸便得歸。", "滿目路岐拋似夢，一船風雨去如飛。", "盤擎紫線蓴初熟，箸撥紅絲鱠正肥。", "惆悵途中無限事，與君千載兩忘機。"]'),
('6e813292-67fe-43c0-9052-f3b63740b2bf','感別元帥尚父','羅隱','唐','唐诗','tang','','[]','玉函瑤檢下台司，記得當時捧領時。',64,'全唐诗/poet.tang.36000.json','["玉函瑤檢下台司，記得當時捧領時。", "半壁龍虵蟠造化，滿筐山岳動神祇。", "疲牛舐犢心猶切，陰鶴鳴雛力已衰。", "稚子不才身抱疾，日窺貞跡淚雙垂。"]'),
('4778ce22-246f-41ec-9aad-3b1ebd51cf9b','尚父偶建小樓特摛麗藻絕句不敢稱揚三首 一','羅隱','唐','唐诗','tang','','[]','結構叨馮柱石才，敢期幢蓋此裴回。',32,'全唐诗/poet.tang.36000.json','["結構叨馮柱石才，敢期幢蓋此裴回。", "陽春曲調高誰和，盡日焚香倚隗臺。"]'),
('e3d2f3d2-f693-432c-9ff4-9e5ca6d885bb','尚父偶建小樓特摛麗藻絕句不敢稱揚三首 二','羅隱','唐','唐诗','tang','','[]','瑇簪珠履愧非才，時凭闌干首重迴。',32,'全唐诗/poet.tang.36000.json','["瑇簪珠履愧非才，時凭闌干首重迴。", "只待淮妖翦除後，別傾巵酒賀行臺。"]'),
('c76d9b17-b356-4174-b775-52daa8e9d8d6','尚父偶建小樓特摛麗藻絕句不敢稱揚三首 三','羅隱','唐','唐诗','tang','','[]','闌檻初成愧楚才，不知星彩尚迂迴。',32,'全唐诗/poet.tang.36000.json','["闌檻初成愧楚才，不知星彩尚迂迴。", "風流孔令陶鈞外，猶記山妖逼小臺。"]'),
('f5bcf908-fc2c-4ab0-81cf-1533e11f218e','題玄同先生草堂三首 一','羅隱','唐','唐诗','tang','','[]','杳杳諸天路，蒼蒼大滌山。',48,'全唐诗/poet.tang.36000.json','["杳杳諸天路，蒼蒼大滌山。", "景輿留不得，毛節去應閒。", "相府舊知己，教門新啓關。", "太平匡濟術，流落在人間。"]'),
('ce8ce364-7798-4f3f-a329-cefac4f3ae36','題玄同先生草堂三首 二','羅隱','唐','唐诗','tang','','[]','先生訣行日，曾奉數行書。',48,'全唐诗/poet.tang.36000.json','["先生訣行日，曾奉數行書。", "意密尋難會，情深恨有餘。", "石橋春暖後，句漏藥成初。", "珍重雲兼鶴，從來不定居。"]'),
('23b33a36-98f8-443e-a80e-865d5729c6ec','題玄同先生草堂三首 三','羅隱','唐','唐诗','tang','','[]','常時憶討論，歷歷事猶存。',48,'全唐诗/poet.tang.36000.json','["常時憶討論，歷歷事猶存。", "酒向餘杭盡，雲從大滌昏。", "往來無道侶，歸去有台恩。", "自此玄言絕，長應閉洞門。"]'),
('a922ef7b-7689-470f-9ebe-ca4cf3cff3c1','城西作','羅隱','唐','唐诗','tang','','[]','從軍無一事，終日掩空齋。',48,'全唐诗/poet.tang.36000.json','["從軍無一事，終日掩空齋。", "道薄交遊少，才疎進取乖。", "野禽鳴聒耳，庭草綠侵階。", "幸自同樗櫟，何妨愜所懷。"]'),
('8a3b559f-79c9-4fa9-ab55-3e24f7b38946','冬暮城西晚眺','羅隱','唐','唐诗','tang','','[]','謬忝蓮華幕，虛霑柏署官。',48,'全唐诗/poet.tang.36000.json','["謬忝蓮華幕，虛霑柏署官。", "欹危長抱疾，衰老不禁寒。", "時事已日過，世途行轉難。", "千崖兼萬壑，只向望中看。"]'),
('4dfe1ebd-1ade-4b05-9e45-951d1e789274','秋霽後','羅隱','唐','唐诗','tang','','[]','淨碧山光冷，圓明露點勻。',48,'全唐诗/poet.tang.36000.json','["淨碧山光冷，圓明露點勻。", "渚蓮丹臉恨，堤柳翠眉顰。", "蟬已送行客，鴈應辭主人。", "蠅蚊漸無況，日晚自相親。"]'),
('7b3fec15-9678-4497-8b9c-147a49214458','茅齋','羅隱','唐','唐诗','tang','','[]','從事不從事，養生非養生。',48,'全唐诗/poet.tang.36000.json','["從事不從事，養生非養生。", "職爲尸祿本，官是受恩名。", "時態已相失，歲華從自驚。", "西齋一巵酒，衰老與誰傾。"]'),
('9ae7636f-1bc3-43cb-a107-3ca874e154eb','使者','羅隱','唐','唐诗','tang','','[]','使者銜中旨，崎嶇萬里行。',48,'全唐诗/poet.tang.36000.json','["使者銜中旨，崎嶇萬里行。", "人心猶未革，天意似難明。", "四海霍光第，六宮張奉營。", "陪臣無以報，西望不勝情。"]'),
('173cb325-a798-46a8-a8ea-20c689e18617','途中逢劉知遠','羅隱','唐','唐诗','tang','','[]','吳楚煙波裏，巢由季孟間。',48,'全唐诗/poet.tang.36000.json','["吳楚煙波裏，巢由季孟間。", "只言無事貴，不道致身閑。", "別渚蓮根斷，歸心桂樹頑。", "空勞鍾璞意，塵世隔函關。"]'),
('70988f5e-b0ff-4ca8-90a8-8fb2b9065204','遁跡','羅隱','唐','唐诗','tang','','[]','遁跡知安住，霑襟欲奈何。',48,'全唐诗/poet.tang.36000.json','["遁跡知安住，霑襟欲奈何。", "朝廷猶禮樂，郡邑忍干戈。", "華馬憑誰問，胡塵自此多。", "因思漢明帝，中夜憶廉頗。"]'),
('f1c8679d-597a-47c9-81d2-6030bccfae2f','隴頭水','羅隱','唐','唐诗','tang','','[]','借問隴頭水，年年恨何事。',48,'全唐诗/poet.tang.36000.json','["借問隴頭水，年年恨何事。", "全疑嗚咽聲，中有征人淚。", "自古無長策，況我非深智。", "何計謝潺湲，一宵空不寐。"]'),
('658b52dc-3731-4d60-9bc4-5b1a60db00f2','秦中富人','羅隱','唐','唐诗','tang','','[]','高高起華堂，區區引流水。',36,'全唐诗/poet.tang.36000.json','["高高起華堂，區區引流水。", "糞土金玉珍，猶嫌未奢侈。", "陋巷滿蓬蒿，誰知有顏子。"]'),
('dddbcb22-0162-42ea-950d-a4e5555b0411','思歸行','羅隱','唐','唐诗','tang','','[]','不耕南畝田，爲愛東堂桂。',48,'全唐诗/poet.tang.36000.json','["不耕南畝田，爲愛東堂桂。", "身同樹上花，一落又經歲。", "交親亦相薄，知己恩潛替。", "日開十二門，自是無歸計。"]'),
('af25b610-63f7-4899-94b3-cc078a027aed','即事中元甲子','羅隱','唐','唐诗','tang','','[]','三秦流血已成川，塞上黃雲戰[馬]閒。',66,'全唐诗/poet.tang.36000.json','["三秦流血已成川，塞上黃雲戰[馬]閒。", "只有羸兵填渭水，終無奇事出商山。", "田園已沒紅塵內，弟姪相逢白刃間。", "惆悵翠華猶未返，淚痕空滴劒文斑。"]'),
('a79d78bc-4e00-4bce-99e9-b3a1f8977193','魏城逢故人','羅隱','唐','唐诗','tang','','["\u6292\u60c5", "\u7559\u5ff5", "\u5199\u666f"]','一年兩度錦江遊，前值東風後值秋。',64,'全唐诗/poet.tang.36000.json','["一年兩度錦江遊，前值東風後值秋。", "芳草有情皆礙馬，好雲無處不遮樓。", "山將別恨和心斷，水帶離聲入夢流。", "今日因君試回首，澹煙喬木隔綿州。"]'),
('bed6a301-cc0e-446b-bc03-c8e95524a0be','遊江夏口','羅隱','唐','唐诗','tang','','[]','醉別江東酒一杯，往年曾此駐塵埃。',64,'全唐诗/poet.tang.36000.json','["醉別江東酒一杯，往年曾此駐塵埃。", "魚聽建業歌聲過，水看瞿塘雪影來。", "黃祖不能容賤客，費禕終是負仙才。", "平生膽氣平生恨，今日江邊首嬾迴。"]'),
('eb926914-184e-49ae-a5e0-90b9fb27af44','春思','羅隱','唐','唐诗','tang','','[]','蕩漾春風淥似波，惹情搖恨去傞傞。',64,'全唐诗/poet.tang.36000.json','["蕩漾春風淥似波，惹情搖恨去傞傞。", "燕翻永日音聲好，柳舞空城意緒多。", "蜀國暖迴溪峽浪，衛娘清轉遏雲歌。", "可憐戶外桃兼李，仲蔚蓬蒿奈爾何。"]'),
('9e52a652-5415-41f1-a900-79497ac40fc5','黃鶴驛寓題','羅隱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','野雲芳草繞離鞭，敢對青樓倚少年。',64,'全唐诗/poet.tang.36000.json','["野雲芳草繞離鞭，敢對青樓倚少年。", "秋色未催榆塞鴈，人心先下洞庭船。", "高歌酒市非狂者，大嚼屠門亦偶然。", "車馬同歸莫同恨，古人頭白盡林泉。"]'),
('7194db68-423e-480e-9610-b60aaefc2984','安陸贈徐礪','羅隱','唐','唐诗','tang','','[]','靈虵橋下水聲聲，曾向橋邊話別情。',64,'全唐诗/poet.tang.36000.json','["靈虵橋下水聲聲，曾向橋邊話別情。", "一榻偶依陳太守，三年深憶禰先生。", "塵欺鬢色非前事，火爇蓬根有去程。", "還把餘杯重相勸，不堪秋色背鄖城。"]'),
('751a9800-ee11-416b-bdf3-3eff172b271c','寄鍾常侍','羅隱','唐','唐诗','tang','','[]','一從朱履步金臺，蘗苦冰寒奉上台。',64,'全唐诗/poet.tang.36000.json','["一從朱履步金臺，蘗苦冰寒奉上台。", "峻節不由人學得，遠途終是自將來。", "風高漸展摩天翼，榦聳方呈構廈材。", "應笑樟亭舊同舍，九州無驗滿爐灰。"]'),
('2298227e-be83-43e0-9f33-5acb617c9c46','中秋夜不見月','羅隱','唐','唐诗','tang','','[]','陰雲薄霧上空虛，此夕清光已破除。',32,'全唐诗/poet.tang.36000.json','["陰雲薄霧上空虛，此夕清光已破除。", "只恐異時開霽後，玉輪依舊養蟾蜍。"]'),
('c4e111f1-872b-4103-8db1-a17e5ec87cdc','魏博羅令公附卷有迴','羅隱','唐','唐诗','tang','','[]','寒門雖得在諸宗，棲北巢南恨不同。',64,'全唐诗/poet.tang.36000.json','["寒門雖得在諸宗，棲北巢南恨不同。", "馬上固慙消髀肉，幄中由羨愈頭風。", "蹉跎歲月心仍切，迢遰江山夢未通。", "深荷吾宗有知己，好將刀筆爲英雄。"]'),
('bd598908-a75e-497a-ab3a-5ecbdb0d60a1','寄處默師','羅隱','唐','唐诗','tang','','[]','甘露卷簾看雨脚，樟亭倚柱望潮頭。',64,'全唐诗/poet.tang.36000.json','["甘露卷簾看雨脚，樟亭倚柱望潮頭。", "十年顧我醉中過，兩地與師方外遊。", "久隔兵戈常寄夢，近無書信更堪憂。", "香爐煙靄虎溪月，終棹鐵船尋惠休。"]'),
('f663790e-f9d9-4b1e-af51-bc49385fab49','病中上錢尚父','羅隱','唐','唐诗','tang','','[]','左脚方行右臂攣，每慙名跡污賓筵。',64,'全唐诗/poet.tang.36000.json','["左脚方行右臂攣，每慙名跡污賓筵。", "縱饒吳土容衰病，爭奈燕臺費料錢。", "藜杖已乾難更把，竹輿雖在不堪懸。", "深恩重德無言處，迴首浮生淚泫然。"]'),
('e11c89d2-6302-4ea0-a049-bf64053ad91d','送梅處士歸寧國','羅隱','唐','唐诗','tang','','[]','十五年前即別君，別時天下未紛紜。',64,'全唐诗/poet.tang.36000.json','["十五年前即別君，別時天下未紛紜。", "亂罹且喜身俱在，存沒那堪耳更聞。", "良會謾勞悲曩跡，舊交誰去弔荒墳。", "殷勤爲謝逃名客，想望千秋嶺上雲。"]'),
('35042c83-6625-4baa-a633-7e280124bcd5','經故友所居','羅隱','唐','唐诗','tang','','[]','槐花漠漠向人黃，此地追遊跡已荒。',64,'全唐诗/poet.tang.36000.json','["槐花漠漠向人黃，此地追遊跡已荒。", "清論不知莊叟達，死交空歡趙岐忙。", "病來未忍言閑事，老去唯知覓醉鄉。", "日暮街東策羸馬，一聲橫笛似山陽。"]'),
('70b581af-f43b-491e-8a29-e7a03cc389ac','大梁從事居汜水','羅隱','唐','唐诗','tang','','[]','前年帝里望行塵，記得仙家第四人。',64,'全唐诗/poet.tang.36000.json','["前年帝里望行塵，記得仙家第四人。", "泉暖舊諳龍偃息，露寒初見鶴精神。", "歌聲上榻梁園晚，夢遶殘鐘汜水春。", "知有篋中編集在，只應從此是經綸。"]'),
('84ee256d-3599-4534-9f72-c74ca62033ad','杜處士新居','羅隱','唐','唐诗','tang','','[]','翠斂王孫草，荒誅宋玉茅。',48,'全唐诗/poet.tang.36000.json','["翠斂王孫草，荒誅宋玉茅。", "寇餘無故物，時薄少深交。", "迸笋穿行徑，饑雛出壞巢。", "小園吾亦有，多病近來拋。"]'),
('db40f212-23cf-4858-a4e3-371cc0ae35b0','絕境','羅隱','唐','唐诗','tang','','[]','絕境非身事，流年但物華。',48,'全唐诗/poet.tang.36000.json','["絕境非身事，流年但物華。", "水梳苔髪直，風引蕙心斜。", "凡客從題鳳，膚音未勝蛙。", "小船兼有槳，始與問漁家。"]'),
('11098e31-1df2-4627-9dbd-d1f5600e7330','雪中懷友人','羅隱','唐','唐诗','tang','','[]','臘酒復臘雪，故人今越鄉。',48,'全唐诗/poet.tang.36000.json','["臘酒復臘雪，故人今越鄉。", "所思誰把醆，端坐恨無航。", "兔苑舊遊盡，龜臺仙路長。", "未知鄒孟子，何以奉梁王。"]'),
('3840a008-1325-4ebd-a31c-fdc54e1dcc4b','秋晚','羅隱','唐','唐诗','tang','','[]','宰邑慙良術，爲文愧壯圖。',48,'全唐诗/poet.tang.36000.json','["宰邑慙良術，爲文愧壯圖。", "縱饒長委命，爭奈漸非夫。", "杯酒有時有，亂罹無處無。", "金庭在何域，回首一踟躕。"]'),
('50e334c7-1993-4676-b4f8-14e29829c662','昇仙橋','羅隱','唐','唐诗','tang','','[]','危梁枕路岐，駐馬問前時。',48,'全唐诗/poet.tang.36000.json','["危梁枕路岐，駐馬問前時。", "價自友朋得，名因婦女知。", "直須論運命，不得逞文詞。", "執戟君鄉里，榮華竟若爲。"]'),
('8507e813-5ed4-4fa4-855e-49b63c7eab4b','姑蘇[真]娘墓','羅隱','唐','唐诗','tang','','[]','春草荒墳墓，萋萋向虎丘。',48,'全唐诗/poet.tang.36000.json','["春草荒墳墓，萋萋向虎丘。", "死猶嫌寂寞，生肯不風流。", "皎鏡山泉冷，輕裾海霧秋。", "還應伴西子，香逕夜深遊。"]'),
('584bf15b-b357-4e00-9825-69f1e97d374a','靈山寺','羅隱','唐','唐诗','tang','','[]','晚景聊攄抱，憑欄幾蕩魂。',36,'全唐诗/poet.tang.36000.json','["晚景聊攄抱，憑欄幾蕩魂。", "檻虛從四面，江闊奈孤根。", "幽徑薜蘿色，小山菭蘚痕。"]'),
('7bde0eaf-4976-4226-bee4-fd4eea7f0800','倚櫂','羅隱','唐','唐诗','tang','','[]','倚櫂聽鄰笛，霑衣認酒壚。',48,'全唐诗/poet.tang.36000.json','["倚櫂聽鄰笛，霑衣認酒壚。", "自緣悲巨室，誰復爲窮途。", "樹解將軍夢，城遺御史烏。", "直應齊始了，傾酌向寒蕪。"]'),
('72a76099-2881-41a9-96a9-9cf30d89aa1e','秋夕對月','羅隱','唐','唐诗','tang','','[]','夜月色可掬，倚樓聊解顏。',48,'全唐诗/poet.tang.36000.json','["夜月色可掬，倚樓聊解顏。", "未能分寇盜，徒欲滿關山。", "背冷金蟾滑，毛寒玉兔頑。", "姮娥謾偷藥，長寡老中閒。"]'),
('8390a735-8d6e-4735-bf8d-a7654ace28b3','寄徵士魏員外','羅隱','唐','唐诗','tang','','[]','家遁蘇門節，清貧粉署官。',48,'全唐诗/poet.tang.36000.json','["家遁蘇門節，清貧粉署官。", "不矜朝命重，只恨路行難。", "窗曉雞譚倦，庭秋蝶夢闌。", "羨君歸未得，還有釣魚竿。"]'),
('9fa001e9-f339-4f45-851c-3a9445d859de','宿彭蠡館','羅隱','唐','唐诗','tang','','[]','孤館少行旅，解鞍增別愁。',48,'全唐诗/poet.tang.36000.json','["孤館少行旅，解鞍增別愁。", "遠山矜薄暮，高柳怯清秋。", "病裏見時態，醉中思舊遊。", "所懷今已矣，何必恨東流。"]'),
('0a132269-6d2f-4c0d-b33b-8a5f46c77f1c','螢','羅隱','唐','唐诗','tang','','[]','空庭夜未央，點點度西牆。',48,'全唐诗/poet.tang.36000.json','["空庭夜未央，點點度西牆。", "抱影何微細，乘時忽發揚。", "不思因腐草，便擬倚孤光。", "若道能通照，車公業肯長。"]'),
('0878208a-077c-4a26-9aa1-3b7d6a3cf1fd','早秋宿葉墮所居','羅隱','唐','唐诗','tang','','[]','池荷葉正圓，長曆報時殫。',48,'全唐诗/poet.tang.36000.json','["池荷葉正圓，長曆報時殫。", "曠野雲蒸熱，空庭雨始寒。", "蠅蚊猶得志，簟席若爲安。", "浮世知誰是，勞歌共一懽。"]'),
('c1e9756f-7235-4dc3-82af-62b9ac125201','蜨','羅隱','唐','唐诗','tang','','[]','漢王刀筆精，寫爾逼天生。',48,'全唐诗/poet.tang.36000.json','["漢王刀筆精，寫爾逼天生。", "舞巧何妨急，飛高所恨輕。", "野田黃雀慮，山館主人情。", "此物那堪作，莊周夢不成。"]'),
('366e760c-9b39-4c24-a6b3-b2c7c3db4a69','春居','羅隱','唐','唐诗','tang','','[]','春風百卉搖，舊國路迢迢。',48,'全唐诗/poet.tang.36000.json','["春風百卉搖，舊國路迢迢。", "偶病成疎散，因貧得寂寥。", "倚簾高柳弱，乘露小桃夭。", "春色常無處，村醪更一瓢。"]'),
('9be51aba-ce9c-4c38-b06a-bd752d53e98c','輕飆','羅隱','唐','唐诗','tang','','[]','輕飆掠晚莎，秋物慘關河。',48,'全唐诗/poet.tang.36000.json','["輕飆掠晚莎，秋物慘關河。", "戰壘平時少，齋壇上處多。", "楚雖屈子重，漢亦憶廉頗。", "不及雲臺議，空山老薜蘿。"]'),
('07d0b64a-05f0-4786-a6ae-966c9c2fdfc7','燕','羅隱','唐','唐诗','tang','','[]','不必嫌漂露，何妨養羽毛。',48,'全唐诗/poet.tang.36000.json','["不必嫌漂露，何妨養羽毛。", "漢妃金屋遠，盧女杏梁高。", "野迥雙飛急，煙晴對語勞。", "猶勝黃雀在，棲息是蓬蒿。"]'),
('22c995bb-273b-4eab-af5e-c9c0e2fbf0c1','陝西晚思','羅隱','唐','唐诗','tang','','[]','長途已自窮，此去便西東。',48,'全唐诗/poet.tang.36000.json','["長途已自窮，此去便西東。", "樹色榮衰裏，人心往返中。", "別情流水急，歸夢故山空。", "莫忘交遊分，從來事一同。"]'),
('e25c764c-0011-4e53-9871-13bca20195ca','除夜寄張達','羅隱','唐','唐诗','tang','','[]','梅花已著眼，竹葉況黏脣。',48,'全唐诗/poet.tang.36000.json','["梅花已著眼，竹葉況黏脣。", "只此留殘歲，那堪憶故人。", "亂罹書不遠，衰病日相親。", "江浦思歸意，明朝又一春。"]'),
('071199b2-efba-4061-b79b-4d123c7a2800','寄酬鄴王羅令公五首 一','羅隱','唐','唐诗','tang','','[]','營室東迴廕斥丘，少年承襲擁青油。',64,'全唐诗/poet.tang.36000.json','["營室東迴廕斥丘，少年承襲擁青油。", "坐調金鼎尊明主，橫把琱戈拜列侯。", "書札二王爭巧拙，篇章七子避風流。", "西園舊跡今應在，衰老無因奉勝游。"]'),
('5372777f-9cad-46d9-a01c-adba1b9f305e','寄酬鄴王羅令公五首 二','羅隱','唐','唐诗','tang','','[]','脉散源分歷幾朝，縱然官宦只卑僚。',64,'全唐诗/poet.tang.36000.json','["脉散源分歷幾朝，縱然官宦只卑僚。", "正憂末派淪滄海，忽見高枝拂絳霄。", "十萬貔貅趨玉帳，三千賓客珥金貂。", "良時難得吾宗少，應念寒門更寂寥。"]'),
('e2eb084b-79d7-4d4f-b81f-6c8dfbcab6fb','寄酬鄴王羅令公五首 三','羅隱','唐','唐诗','tang','','[]','敢將衰弱附強宗，細筭還緣血脉同。',64,'全唐诗/poet.tang.36000.json','["敢將衰弱附強宗，細筭還緣血脉同。", "湘浦煙波無舊跡，鄴都蘭菊有遺風。", "每憐罹亂書猶達，所恨雲泥路不通。", "珍重珠璣兼繡段，草玄堂下寄揚雄。"]'),
('ede3aeb6-6953-4165-bb4a-6cb51b697d7d','寄酬鄴王羅令公五首 四','羅隱','唐','唐诗','tang','','[]','水雲開霽立高亭，依約黎陽對福星。',64,'全唐诗/poet.tang.36000.json','["水雲開霽立高亭，依約黎陽對福星。", "只見篇章矜鏤管，不知勳業柱青冥。", "早緣入夢金方礪，晚爲傳家鼎始銘。", "鶴髪四垂煙閣遠，此生何處拜儀形。"]'),
('9c1a55d7-e75b-4900-8fe8-7e58d1b6649c','寄酬鄴王羅令公五首 五','羅隱','唐','唐诗','tang','','[]','錦笈朱囊連復連，紫鸞飛下浙江邊。',64,'全唐诗/poet.tang.36000.json','["錦笈朱囊連復連，紫鸞飛下浙江邊。", "綃從海室奪煙霧，樂奏帝官勝管弦。", "長笑應劉悲顯達，每嫌伊霍少詩篇。", "戴灣老圃根基薄，虛費工夫八十年。"]'),
('beb2c8ba-cf74-4b09-a6ac-5149ec7b399b','春日投錢塘元帥尚父二首 一','羅隱','唐','唐诗','tang','','[]','正憂衰老辱金臺，敢望昭王顧問來。',66,'全唐诗/poet.tang.36000.json','["正憂衰老辱金臺，敢望昭王顧問來。", "門外旌旗屯[虎豹]，壁閒章句動風雷。", "三都節已聯翩降，兩地花應次第開。", "若比紫髯分鼎足，未聞餘力有瓊環。"]'),
('4c55aa21-2074-4bac-b235-fdf1a5bfbe15','春日投錢塘元帥尚父二首 二','羅隱','唐','唐诗','tang','','["\u9ec4\u6cb3"]','征東幕府十三州，敢望非才忝上游。',64,'全唐诗/poet.tang.36000.json','["征東幕府十三州，敢望非才忝上游。", "官秩已叨吳品職，姓名兼顯魯春秋。", "鹽車顧後聲方重，火井窺來焰始浮。", "一句黃河千載事，麥城王粲謾登樓。"]'),
('d938ab61-c83e-4164-8d9b-64486930297c','錢塘府亭','羅隱','唐','唐诗','tang','','[]','新恩別啓館娃宮，還拜吳王向此中。',64,'全唐诗/poet.tang.36000.json','["新恩別啓館娃宮，還拜吳王向此中。", "九牧土田周制在，兩藩茅社漢儀同。", "春生舊苑芳洲雨，香入高臺小徑風。", "更有寵光人未見，問安調膳盡三公。"]'),
('2c05c64a-c6d3-44fc-9c4e-2a786e425773','野狐泉','羅隱','唐','唐诗','tang','','[]','潏潏寒光濺路塵，相傳妖物此潛身。',32,'全唐诗/poet.tang.36000.json','["潏潏寒光濺路塵，相傳妖物此潛身。", "又應改換皮毛後，何處人間作好人。"]'),
('be848f6b-a2a3-4e89-9afd-ad0bb68bda17','宿紀南驛','羅隱','唐','唐诗','tang','','[]','策蹇南游憶楚朝，陰風淅淅樹蕭蕭。',32,'全唐诗/poet.tang.36000.json','["策蹇南游憶楚朝，陰風淅淅樹蕭蕭。", "不知無忌姦邪骨，又作何山野葛苗。"]'),
('bc0103da-c20c-4d6c-8e2a-7d2fd0bbb862','贈無相禪師','羅隱','唐','唐诗','tang','','[]','人人盡道事空王，心裏忙於市井忙。',32,'全唐诗/poet.tang.36000.json','["人人盡道事空王，心裏忙於市井忙。", "惟有馬當山上客，死門生路兩相忘。"]'),
('f1a3cf70-d6fd-4d19-97ed-df1721dae438','遣興','羅隱','唐','唐诗','tang','','[]','青雲路不通，歸計奈長蒙。',48,'全唐诗/poet.tang.36000.json','["青雲路不通，歸計奈長蒙。", "老恐醫方誤，窮憂酒醆空。", "何堪罹亂後，更入是非中。", "長短遭譏笑，迴頭避釣翁。"]'),
('e0c4adf0-707b-4ad6-a613-80f09917dab3','江夏酬高崇節','羅隱','唐','唐诗','tang','','[]','臘雪都堂試，春風汴水行。',48,'全唐诗/poet.tang.36000.json','["臘雪都堂試，春風汴水行。", "十年雖抱疾，何處不無情？", "羣盜正當路，此游應隔生。", "勞君問流落，山下已躬耕。"]'),
('4b9fddd5-a802-4367-92b4-ecaec0e7efe6','鸎聲','羅隱','唐','唐诗','tang','','[]','井上梧桐暗，花間霧露晞。',48,'全唐诗/poet.tang.36000.json','["井上梧桐暗，花間霧露晞。", "一枝晴復暖，百囀是兼非。", "金屋夢初覺，玉關人未歸。", "不堪閑日聽，因爾又霑衣。"]'),
('5d2aa0e3-f6df-4f2c-8b1c-9e3038f7d54b','倣玉臺體','羅隱','唐','唐诗','tang','','[]','青樓枕路隅，壁甃復椒塗。',48,'全唐诗/poet.tang.36000.json','["青樓枕路隅，壁甃復椒塗。", "晚夢通簾柙，春寒逼酒罏。", "解吟憐芍藥，難見恨菖蒲。", "試問年多少，鄰姬亦姓胡。"]'),
('274e5ab1-a01e-43f1-8f4d-cb6517493786','夜泊義興戲呈邑宰','羅隱','唐','唐诗','tang','','[]','溪畔維舟問戴星，此中三害有圖經。',32,'全唐诗/poet.tang.36000.json','["溪畔維舟問戴星，此中三害有圖經。", "長橋可避南山遠，却恐難防是最靈。"]'),
('5a083f14-011f-4861-9615-ac6b5ac9643f','聽琵琶','羅隱','唐','唐诗','tang','','[]','香筵酒散思朝散，偶向梧桐暗處聞。',32,'全唐诗/poet.tang.36000.json','["香筵酒散思朝散，偶向梧桐暗處聞。", "大底曲中皆有恨，滿樓人自不知君。"]'),
('df71f7a9-3486-4c20-beb8-ed851bdf40ab','經耒陽杜工部墓','羅隱','唐','唐诗','tang','','[]','紫菊馨香覆楚醪，奠君江畔雨蕭騷。',64,'全唐诗/poet.tang.36000.json','["紫菊馨香覆楚醪，奠君江畔雨蕭騷。", "旅魂自是才相累，閑骨何妨塚更高。", "騄驥喪來空蹇蹶，芝蘭衰後長蓬蒿。", "屈原宋玉鄰君處，幾駕青螭緩鬱陶。"]'),
('ab7f881b-9e02-4400-85ce-6ab14c9dcc89','題袁溪張逸人所居','羅隱','唐','唐诗','tang','','[]','蒲梢獵獵燕差差，數里溪光日落時。',48,'全唐诗/poet.tang.36000.json','["蒲梢獵獵燕差差，數里溪光日落時。", "芳樹文君機上錦，遠山孫壽鏡中眉。", "雞窗夜靜開書卷，魚檻春深展釣絲。"]'),
('48f161af-3e62-464f-97c0-d13167214eff','昇平公主舊第','羅隱','唐','唐诗','tang','','[]','乘鳳仙人降此時，玉篇纔罷到文詞。',64,'全唐诗/poet.tang.36000.json','["乘鳳仙人降此時，玉篇纔罷到文詞。", "兩輪水磑光明照，百尺鮫綃換好詩。", "帶礪山河今盡在，風流罇俎見無期。", "壇場客散香街暝，惆悵齊竽取次吹。"]'),
('a44285cc-9b71-447c-9e56-17b19fc5f4d5','寄黔中王從事','羅隱','唐','唐诗','tang','','[]','故人刀筆事軍書，南轉黔江半月餘。',64,'全唐诗/poet.tang.36000.json','["故人刀筆事軍書，南轉黔江半月餘。", "別後鄉關情幾許，近來詩酒興何如。", "貪將醉袖矜鶯谷，不把瑤緘附鯉魚。", "今日舉觴君莫問，生涯牢落鬢蕭疎。"]'),
('9c898cd1-2aeb-44dc-9c99-6d8138b71cb7','關亭春望','羅隱','唐','唐诗','tang','','[]','關畔春雲拂馬頭，馬前春事共悠悠。',64,'全唐诗/poet.tang.36000.json','["關畔春雲拂馬頭，馬前春事共悠悠。", "風搖岸柳長條困，露裛山花小朵愁。", "信越功名高似狗，裴王氣力大於牛。", "未知至竟將何用，渭水涇川一向流。"]'),
('59cb956e-506d-4f4e-be4d-1b11d782d2b5','寄徐濟進士','羅隱','唐','唐诗','tang','','[]','往年疎嬾共江湖，月滿花香記得無。',64,'全唐诗/poet.tang.36000.json','["往年疎嬾共江湖，月滿花香記得無。", "霜壓楚蓮秋後折，雨催蠻酒夜深酤。", "紅塵偶別迷前事，丹桂相傾媿後徒。", "出得函關抽得手，從來不及阮元瑜。"]'),
('41ace288-8b23-4e7b-bbc0-a2906f3b418d','寄韋贍','羅隱','唐','唐诗','tang','','[]','石城蓑笠阻心期，落盡山花有所思。',64,'全唐诗/poet.tang.36000.json','["石城蓑笠阻心期，落盡山花有所思。", "羸馬二年蓬轉後，故人何處月明時？", "風催曉雁看看別，雨脅秋蠅漸漸癡。", "禪智闌干市橋酒，縱然相見只相悲。"]'),
('1c066a85-1b54-4929-834d-d43490becfa5','霅溪晚泊寄裴庶子','羅隱','唐','唐诗','tang','','[]','溪風如扇雨如絲，閑步閑吟柳惲詩。',64,'全唐诗/poet.tang.36000.json','["溪風如扇雨如絲，閑步閑吟柳惲詩。", "杯酒疎狂非曩日，野花狼藉似當時。", "道窮謾有依劉感，才急應無借寇期。", "滿眼雲山莫相笑，與君俱是受深知。"]'),
('aff7711a-e6a9-4165-94b4-87e62754345f','送姚安之赴任秋浦','羅隱','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','官罷春坊地象雷，片帆高指貴池開。',64,'全唐诗/poet.tang.36000.json','["官罷春坊地象雷，片帆高指貴池開。", "五侯水暖魚鱗去，九子山晴雁敘來。", "江夏黃童徒逞辯，廣都龐令恐非才。", "到頭稱意須年少，贏得時光向酒杯。"]'),
('e4110930-1989-4cdc-a320-68d961de9cd3','寄喬逸人','羅隱','唐','唐诗','tang','','[]','南經湘浦北揚州，別後風帆幾度游。',64,'全唐诗/poet.tang.36000.json','["南經湘浦北揚州，別後風帆幾度游。", "春酒誰家禁爛熳，野花何處最淹留？", "欲憑尺素邊鴻嬾，未定雕梁海燕愁。", "長短此行須入手，更饒君占一年秋。"]'),
('c590d55d-3153-4043-bf4c-4cdfc1fdeb40','塞外','羅隱','唐','唐诗','tang','','[]','塞外偷兒塞內兵，聖君宵旰望升平。',64,'全唐诗/poet.tang.36000.json','["塞外偷兒塞內兵，聖君宵旰望升平。", "碧幢未作朝廷計，白梃猶驅婦女行。", "可使禦戎無上策，只應憂國是虛聲。", "漢王第宅秦田土，今日將軍已自榮。"]'),
('7617c9fa-edf9-4d0c-9466-d49d1f18d652','裴庶子除太僕卿因賀','羅隱','唐','唐诗','tang','','[]','楚珪班序未爲輕，莫惜良途副聖明。',64,'全唐诗/poet.tang.36000.json','["楚珪班序未爲輕，莫惜良途副聖明。", "宮省舊推皇甫謐，寺曹今得夏侯嬰。", "秩隨科第臨時貴，官逐簪裾到處清。", "應笑馬安虛巧宦，四迴遷轉始爲卿。"]'),
('b0954ea1-5991-4671-bff4-87f3fb4c5f1e','詠史','羅隱','唐','唐诗','tang','','[]','蠹簡遺編試一尋，寂寥前事似如今。',64,'全唐诗/poet.tang.36000.json','["蠹簡遺編試一尋，寂寥前事似如今。", "徐陵筆硯珊瑚架，趙勝賓朋瑇瑁簪。", "未必片言資國計，只應邪說動人心。", "九原郝泚何由起，虛誤西蕃八尺金。"]'),
('594aa891-9234-42b6-8d39-d797a55bffb3','中元夜泊淮口','羅隱','唐','唐诗','tang','','[]','木葉迴飄水面平，偶因孤棹已三更。',64,'全唐诗/poet.tang.36000.json','["木葉迴飄水面平，偶因孤棹已三更。", "秋涼霧露侵燈下，夜靜魚龍逼岸行。", "欹枕正牽題柱思，隔樓誰轉遶梁聲。", "錦帆天子狂魂魄，應過揚州看月明。"]'),
('65c821c4-8e3e-4825-a465-e1839f3667b7','寄池州鄭員外','羅隱','唐','唐诗','tang','','[]','獸遶朱輪酒滿船，郡城蕭灑貴池邊。',64,'全唐诗/poet.tang.36000.json','["獸遶朱輪酒滿船，郡城蕭灑貴池邊。", "衣同萊子曾分筆，扇似袁宏別有天。", "九點好山樓上客，兩行高柳雨中煙。", "陵陽百姓將何福，社舞村歌又一年。"]'),
('45ba85be-9355-400f-b3f2-20b7349c3b8c','歸夢','羅隱','唐','唐诗','tang','','[]','陸海波濤漸漸深，一迴歸夢抵千金。',64,'全唐诗/poet.tang.36000.json','["陸海波濤漸漸深，一迴歸夢抵千金。", "路傍草色休多事，牆外鶯聲肯有心。", "日晚向隅悲斷梗，夜闌澆酒哭知音。", "貪財敗陣誰相悉，鮑叔如今不可尋。"]'),
('48c0eca6-e03c-40c5-9ca2-1d86a0f70453','送溪州使君','羅隱','唐','唐诗','tang','','[]','兵寇傷殘國力衰，就中南土藉良醫。',64,'全唐诗/poet.tang.36000.json','["兵寇傷殘國力衰，就中南土藉良醫。", "鳳銜泥詔辭丹闕，鵰倚霜風上畫旗。", "官職不須輕遠地，生靈只是計臨時。", "灞橋酒醆黔巫月，從此江心兩所思。"]'),
('59d553bc-61c8-4108-98e9-3bcac1b7869d','送霅川鄭員外','羅隱','唐','唐诗','tang','','[]','明時塞詔列分麾，東擁朱輪出帝畿。',64,'全唐诗/poet.tang.36000.json','["明時塞詔列分麾，東擁朱輪出帝畿。", "銅虎貴提天子印，銀魚榮傍老萊衣。", "歌聽茗塢春山暖，詩詠蘋洲暮鳥飛。", "知有掖垣南步在，可能須待政成歸。"]'),
('17c5b59b-6355-4cdd-ab2d-0e41834c3369','酬寄右司李員外','羅隱','唐','唐诗','tang','','[]','當年憶見桂枝春，自此清途未四旬。',64,'全唐诗/poet.tang.36000.json','["當年憶見桂枝春，自此清途未四旬。", "左省望高推健筆，右曹官重得名人。", "閑摛麗藻嫌秋興，靜獵遺編笑過秦。", "猶把隨和向泥滓，應憐疎散任天真。"]'),
('72567d89-5a52-4888-9aaf-0860182f9f2c','蓮塘驛','羅隱','唐','唐诗','tang','','[]','蓮塘館東初日明，蓮塘館西行人行。',64,'全唐诗/poet.tang.36000.json','["蓮塘館東初日明，蓮塘館西行人行。", "隔林啼鳥似相應，當路好花疑有情。", "一夢不須追往事，數杯猶可慰勞生。", "莫言來去只如此，君看鬢邊霜幾莖。"]'),
('7599d611-9bb5-487e-8134-c4502e6fe456','甘露寺火後','羅隱','唐','唐诗','tang','','[]','六朝勝事已塵埃，猶有閑人悵望來。',64,'全唐诗/poet.tang.36000.json','["六朝勝事已塵埃，猶有閑人悵望來。", "只道鬼神能護物，不知龍象自成灰。", "犀慙水府渾非怪，燕說吳宮未是災。", "還識平泉故侯否，一生蹤跡比樓臺。"]'),
('3142a69e-ec91-4f6b-a400-52f6ff112b1f','春日登上元石頭故城','羅隱','唐','唐诗','tang','','[]','萬里傷心極目春，東南王氣只逡巡。',64,'全唐诗/poet.tang.36000.json','["萬里傷心極目春，東南王氣只逡巡。", "野花相笑落滿地，山鳥自驚啼傍人。", "謾道城池須險阻，可知豪傑亦埃塵。", "太平寺主惟輕薄，却把三公與賊臣。"]'),
('0d5817e2-23e3-4255-a699-d30f0febe0ad','送宣武徐巡官','羅隱','唐','唐诗','tang','','[]','傲睨公卿二十年，東來西去只悠然。',64,'全唐诗/poet.tang.36000.json','["傲睨公卿二十年，東來西去只悠然。", "白知關畔元非馬，玄覺壺中別有天。", "漢帝詔銜應異日，梁王風雪是初筵。", "臨行不惜刀圭便，愁殺長安買笑錢。"]'),
('ad3db1c4-790d-4a9c-8150-7004586d0ed6','冬暮寄裴郎中','羅隱','唐','唐诗','tang','','[]','曉髪星星入鏡宜，早年容易近年悲。',64,'全唐诗/poet.tang.36000.json','["曉髪星星入鏡宜，早年容易近年悲。", "敢言得事時將晚，只恐酬恩日漸遲。", "南國傾心應望速，東堂開口欲從誰。", "仙郎舊有黃金約，瀝膽隳肝更禱祈。"]'),
('81cea04b-a1bf-49a5-a04b-6bdf8c82aed4','中元甲子以辛丑駕幸蜀四首 一','羅隱','唐','唐诗','tang','','[]','子儀不起渾瑊亡，西幸誰人從武皇。',64,'全唐诗/poet.tang.36000.json','["子儀不起渾瑊亡，西幸誰人從武皇。", "四海爲家雖未遠，九州多事竟難防。", "已聞旰食思真將，會待畋遊致假王。", "應感兩朝巡狩跡，綠槐端正驛荒涼。"]'),
('ffe17864-b25a-4c21-935d-31da714a47f4','中元甲子以辛丑駕幸蜀四首 二','羅隱','唐','唐诗','tang','','[]','爪牙柱石兩俱銷，一點渝塵九土搖。',64,'全唐诗/poet.tang.36000.json','["爪牙柱石兩俱銷，一點渝塵九土搖。", "敢恨甲兵爲棄物，所嗟流品誤清朝。", "幾時睿算殲張角，何處愚人戴隗囂？", "跪望嵕山重啓告，可能餘烈不勝妖。"]'),
('2d7a0b2f-c70f-4cff-be01-40c9a2055cf2','中元甲子以辛丑駕幸蜀四首 三','羅隱','唐','唐诗','tang','','[]','邪氣奔屯瑞氣移，清平過盡到艱危。',64,'全唐诗/poet.tang.36000.json','["邪氣奔屯瑞氣移，清平過盡到艱危。", "縱饒犬彘迷常理，不奈豺狼幸此時。", "九廟有靈思李令，三川悲憶恨張儀。", "可憐一曲還京樂，重對紅蕉教蜀兒。"]'),
('144dd730-1b1e-4241-b687-3503139abf8d','中元甲子以辛丑駕幸蜀四首 四','羅隱','唐','唐诗','tang','','[]','白丁攘臂犯長安，翠輦蒼黃路屈盤。',64,'全唐诗/poet.tang.36000.json','["白丁攘臂犯長安，翠輦蒼黃路屈盤。", "丹鳳有情塵外遠，玉龍無跡渡頭寒。", "靜憐貴族謀身易，危惜文皇創業難。", "不將不侯何計是，釣魚船上淚闌干。"]'),
('5fe6d5e7-b600-41fe-b0bf-eacc20a2800f','題潤州妙善前石羊','羅隱','唐','唐诗','tang','','[]','紫髯桑蓋此沈吟，很石猶存事可尋。',64,'全唐诗/poet.tang.36000.json','["紫髯桑蓋此沈吟，很石猶存事可尋。", "漢鼎未安聊把手，楚醪雖滿肯同心。", "英雄已往時難問，苔蘚何知日漸深。", "還有市鄽沽酒客，雀喧鳩聚話蹄涔。"]'),
('564dbdf3-62d8-4e54-bed8-3332111b33da','登宛陵條風樓寄竇常侍','羅隱','唐','唐诗','tang','','[]','亂罹時節懶登臨，試借條風半日吟。',64,'全唐诗/poet.tang.36000.json','["亂罹時節懶登臨，試借條風半日吟。", "只有遠山含煖律，不知高閣動歸心。", "溪喧晚棹千聲浪，雲護寒郊數丈陰。", "自笑疎慵似麇鹿，也教臺上費黃金。"]'),
('15df63b3-2839-4f86-8905-f63288586443','臺城','羅隱','唐','唐诗','tang','','[]','晚雲陰暎下空城，六代纍纍夕照明。',64,'全唐诗/poet.tang.36000.json','["晚雲陰暎下空城，六代纍纍夕照明。", "玉井已乾龍不起，金甌雖破虎曾爭。", "亦知霸世才難得，却是蒙塵事最平。", "深谷作陵山作海，茂弘流輩莫傷情。"]'),
('649cca9f-4298-499e-b0a3-ad885fd23caf','甘露寺看雪上周相公','羅隱','唐','唐诗','tang','','[]','篩寒灑白亂溟濛，禱請功兼造化功。',64,'全唐诗/poet.tang.36000.json','["篩寒灑白亂溟濛，禱請功兼造化功。", "光薄乍迷京口月，影交初展海門風。", "細黏謝客衣裾上，輕墮梁王酒醆中。", "一種爲祥君看取，半禳災沴半年豐。"]'),
('222195f8-718a-4bb2-9be1-ad8c49bf679b','寄京闕陸郎中昆仲','羅隱','唐','唐诗','tang','','[]','柏臺蘭署四周旋，賓榻何妨雁影連。',64,'全唐诗/poet.tang.36000.json','["柏臺蘭署四周旋，賓榻何妨雁影連。", "纔見玳簪欹細柳，便知油幕勝紅蓮。", "家從入洛聲名大，跡爲依劉事分偏。", "爭奈亂罹人漸少，麥城新賦許誰傳。"]'),
('dcdcfe16-ef25-4e28-8e51-51ed6beb6494','偶題','羅隱','唐','唐诗','tang','','[]','鍾陵醉別十餘春，重見雲英掌上身。',32,'全唐诗/poet.tang.36000.json','["鍾陵醉別十餘春，重見雲英掌上身。", "我未成名君未嫁，可能俱是不如人。"]'),
('0062c24e-650b-4978-ae4e-b12c65b840aa','故都','羅隱','唐','唐诗','tang','','[]','江南江北兩風流，一作迷津一拜侯。',32,'全唐诗/poet.tang.36000.json','["江南江北兩風流，一作迷津一拜侯。", "至竟不如隋煬帝，破家猶得到揚州。"]'),
('88775d50-097b-4777-a8bf-b4aaa78e73c4','董仲舒','羅隱','唐','唐诗','tang','','[]','災變儒生不合聞，謾將刀筆指乾坤。',32,'全唐诗/poet.tang.36000.json','["災變儒生不合聞，謾將刀筆指乾坤。", "偶然留得陰陽術，閉却南門又北門。"]'),
('9e55f238-9d05-48ba-b13d-b6f1cfb3a37e','獻尚父大王','羅隱','唐','唐诗','tang','','[]','數年鐵甲定東甌，夜渡江山瞻斗牛。',32,'全唐诗/poet.tang.36000.json','["數年鐵甲定東甌，夜渡江山瞻斗牛。", "今日朱方平殄後，虎符龍節十三州。"]'),
('f7513920-9e51-4c34-ae10-8ab77d73fb07','蜂','羅隱','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u601c\u60af", "\u5bd3\u8a00", "\u548f\u7269"]','不論平地與山尖，無限風光盡被占。',32,'全唐诗/poet.tang.36000.json','["不論平地與山尖，無限風光盡被占。", "採得百花成蜜後，爲誰辛苦爲誰甜。"]'),
('041222a2-9c0c-4ea9-a253-8fa3a0d81d12','簾二首 一','羅隱','唐','唐诗','tang','','[]','疊影重紋暎畫堂，玉鉤銀燭共熒煌。',32,'全唐诗/poet.tang.36000.json','["疊影重紋暎畫堂，玉鉤銀燭共熒煌。", "會應得見神仙在，休下真珠十二行。"]'),
('9bd8d309-926b-4143-ae2c-870d7bc1927f','簾二首 二','羅隱','唐','唐诗','tang','','[]','翡翠佳名世共稀，玉堂高下巧相宜。',32,'全唐诗/poet.tang.36000.json','["翡翠佳名世共稀，玉堂高下巧相宜。", "殷勤爲囑纖纖手，捲上銀鉤莫放垂。"]'),
('a742242a-651f-4554-9355-edd4ab8446e9','送顧雲下第','羅隱','唐','唐诗','tang','','[]','行行杯酒莫辭頻，怨歎勞歌兩未伸。',64,'全唐诗/poet.tang.36000.json','["行行杯酒莫辭頻，怨歎勞歌兩未伸。", "漢帝後宮猶識字，楚王前殿更無人。", "年深旅舍衣裳敝，潮打村田活計貧。", "百歲都來多幾日，不堪相別又傷春。"]'),
('0e4fd9b0-c786-4b0e-bcdb-2120ac3484b3','村橋','羅隱','唐','唐诗','tang','','[]','村橋酒斾月明樓，偶逐漁舟繫葉舟。',64,'全唐诗/poet.tang.36000.json','["村橋酒斾月明樓，偶逐漁舟繫葉舟。", "莫學魯人疑海鳥，須知莊叟惡犧牛。", "心寒已分灰無焰，事往曾將水共流。", "除却思量太平在，肯拋疎散換公侯。"]'),
('d4fb78aa-cdb9-47ec-a36b-e4f8aeab16a2','送劉校書之新安寄吳常侍','羅隱','唐','唐诗','tang','','[]','野雲如火照行塵，會績溪邊去問津。',64,'全唐诗/poet.tang.36000.json','["野雲如火照行塵，會績溪邊去問津。", "才子省銜非幕客，楚君科第是同人。", "狂思下國千場醉，病負東堂兩度春。", "他日酒筵應見問，鹿裘漁艇隔朱輪。"]'),
('de0e3d55-aa1b-42aa-80d1-acb65c839b05','官池秋夕','羅隱','唐','唐诗','tang','','[]','池邊月影閑婆娑，池上醉來成短歌。',64,'全唐诗/poet.tang.36000.json','["池邊月影閑婆娑，池上醉來成短歌。", "芙渠抵死怨珠露，蟋蟀苦口嫌金波。", "往事向人言不得，舊遊臨老恨空多。", "松醪作酒蘭爲棹，十載煙塵奈爾何。"]'),
('a68505c1-99a5-45f7-a96b-8e87333be899','奉使宛陵別二三從事','羅隱','唐','唐诗','tang','','[]','梁王雪裏有深知，偶別家鄉隔路岐。',64,'全唐诗/poet.tang.36000.json','["梁王雪裏有深知，偶別家鄉隔路岐。", "官品共傳勝曩日，酒杯爭肯忍當時。", "豫章地暖矜千尺，越嶠天寒愧一枝。", "還有釣魚蓑笠在，不堪風雨失歸期。"]'),
('0a16d3ad-e1c9-4459-a76d-12f8672868ad','金陵思古','羅隱','唐','唐诗','tang','','[]','杜秋在時花解言，杜秋死後花更繁。',64,'全唐诗/poet.tang.36000.json','["杜秋在時花解言，杜秋死後花更繁。", "柔姿曼態葬何處，天紅膩白愁荒原。", "高洞紫簫吹夢想，小窗殘雨濕精魂。", "綺筵金縷無消息，一陣征帆過海門。"]'),
('0c7ea43e-04ec-40e8-9887-32f8a6abce46','送王使君赴蘇臺','羅隱','唐','唐诗','tang','','[]','東南一望可長吁，猶憶王孫領虎符。',64,'全唐诗/poet.tang.36000.json','["東南一望可長吁，猶憶王孫領虎符。", "兩地干戈連越絕，數年麋鹿臥姑蘇。", "疲甿賦重全家盡，舊族兵侵太半無。", "料得伍員兼旅寓，不妨招取好揶揄。"]'),
('420966fc-be4c-4137-8e3e-beef4e9e88f9','憶九華','羅隱','唐','唐诗','tang','','[]','九華巉崪廕柴扉，長憶前時此息機。',64,'全唐诗/poet.tang.36000.json','["九華巉崪廕柴扉，長憶前時此息機。", "黃菊倚風村酒熟，綠蒲低雨釣魚歸。", "干戈已是三年別，塵土那堪萬事違。", "回首佳期恨多少，夜闌霜露又霑衣。"]'),
('0a73982c-926c-4f04-a40f-dc96d5ddb32d','送裴饒歸會稽','羅隱','唐','唐诗','tang','','[]','金庭路指剡川隈，珍重良朋自此來。',64,'全唐诗/poet.tang.36000.json','["金庭路指剡川隈，珍重良朋自此來。", "兩鬢不堪悲歲月，一巵猶得話塵埃。", "家通曩分心空在，世逼橫流眼未開。", "笑殺山陰雪中客，等閑乘興又須回。"]'),
('2dd7f0b3-6258-4504-83f6-ba8f7a339991','送程尊師之晉陵','羅隱','唐','唐诗','tang','','[]','棟間雲出認行軒，郊外陰陰夏木繁。',48,'全唐诗/poet.tang.36000.json','["棟間雲出認行軒，郊外陰陰夏木繁。", "高道乍爲張翰侶，使君兼是世龍孫。", "溪含句曲清連底，酒貰餘杭淥滿罇。"]'),
('41559dac-b084-4396-a5d1-ca37267febce','吳門晚泊寄句曲道友','羅隱','唐','唐诗','tang','','[]','采香徑在人不留，采香徑下停葉舟。',64,'全唐诗/poet.tang.36000.json','["采香徑在人不留，采香徑下停葉舟。", "桃花李花鬬紅白，山鳥水鳥自獻酬。", "十萬梅鋗空寸土，三分孫策竟荒丘。", "未知到了關身否，笑殺雷平許遠遊。"]'),
('c008f9c1-4ddc-4ed7-870b-556333d3bfcb','貴池曉望','羅隱','唐','唐诗','tang','','[]','稂莠參天剪未平，且乘孤櫂且行行。',64,'全唐诗/poet.tang.36000.json','["稂莠參天剪未平，且乘孤櫂且行行。", "計疎狡兔無三窟，羈甚賓鴻欲一生。", "合眼亦知非本意，傷心其奈是多情。", "前溪好泊誰爲主，昨夜沙禽占月明。"]'),
('21f96fb6-f725-48d0-b687-ec4821651a9f','寄崔慶孫','羅隱','唐','唐诗','tang','','[]','故人何處又留連，月冷風高鏡水邊。',64,'全唐诗/poet.tang.36000.json','["故人何處又留連，月冷風高鏡水邊。", "文陣解圍纔昨日，醉鄉分袂已三年。", "交情澹泊應長在，俗態流離且勉旃。", "還擬山陰一乘興，雪寒難得渡江船。"]'),
('70f489e5-ec50-4b47-8039-beeb7b5d5a76','寄楊秘書','羅隱','唐','唐诗','tang','','[]','蕭蕭檐雪打窗聲，因憶江東阮步兵。',64,'全唐诗/poet.tang.36000.json','["蕭蕭檐雪打窗聲，因憶江東阮步兵。", "兩信海潮書不達，數峰稽嶺眼長明。", "梅繁幾處垂鞭看，酒好何人倚檻傾。", "會待與君開秫甕，滿船般載鏡中行。"]'),
('98a8961e-2d55-4199-9412-9d5778c4c13e','酬章處士見寄','羅隱','唐','唐诗','tang','','[]','中原甲馬未曾安，今日逢君事萬端。',64,'全唐诗/poet.tang.36000.json','["中原甲馬未曾安，今日逢君事萬端。", "亂後幾回鄉夢隔，別來何處路行難。", "霜鱗共落三門浪，雪鬢同歸七里灘。", "何必新詩更相戲，小樓吟罷暮天寒。"]'),
('ef7f30b0-195c-4f2e-8bd9-622a3d5bd920','送丁明府赴紫溪任','羅隱','唐','唐诗','tang','','[]','金徽玉軫肯躇[躕]，偶滯良途半月餘。',66,'全唐诗/poet.tang.36000.json','["金徽玉軫肯躇[躕]，偶滯良途半月餘。", "樓上酒闌梅拆後，馬前山好雪晴初。", "欒公社在憐鄉樹，潘令花繁賀版輿。", "縣譜莫辭留舊本，異時量度更何如。"]'),
('b5e2977f-0092-4218-938e-4663d8cc46fd','寄前宣州竇常侍','羅隱','唐','唐诗','tang','','[]','往年西謁謝玄暉，罇酒留歡醉始歸。',64,'全唐诗/poet.tang.36000.json','["往年西謁謝玄暉，罇酒留歡醉始歸。", "曲檻柳濃鶯未老，小園花煖蝶初飛。", "噴香瑞獸金三尺，舞雪佳人玉一圍。", "今日亂罹尋不得，滿蓑風雨釣魚磯。"]'),
('5de880f4-5373-4b36-9420-fb3eee9ffa84','秦望山僧院','羅隱','唐','唐诗','tang','','[]','巉巉危岫倚滄洲，聞說秦皇亦此遊。',64,'全唐诗/poet.tang.36000.json','["巉巉危岫倚滄洲，聞說秦皇亦此遊。", "霸主卷衣纔二世，老僧傳錫已千秋。", "陰崖水賴松梢直，蘚壁苔侵畫像愁。", "各是病來俱未了，莫將煩惱問湯休。"]'),
('677c599a-f6f6-439f-a766-a4227b2d96dc','送光祿崔卿赴闕','羅隱','唐','唐诗','tang','','[]','一年極目望西轅，此日殷勤聖主恩。',64,'全唐诗/poet.tang.36000.json','["一年極目望西轅，此日殷勤聖主恩。", "上國已留虞寄命，中朝應聽范汪言。", "官從府幕歸卿寺，路向干戈見禁門。", "鵷侶寂寥曹署冷，更堪嗚咽問田園。"]'),
('7fa4016e-ccab-445d-a39b-3f6d495a9cef','寄程尊師','羅隱','唐','唐诗','tang','','[]','鶴信雖然到五湖，煙波迢遰路崎嶇。',64,'全唐诗/poet.tang.36000.json','["鶴信雖然到五湖，煙波迢遰路崎嶇。", "玉書分薄花生眼，金鼎功遲雪滿鬚。", "三秀紫芝勞夢寐，一番紅槿恨朝晡。", "未知朽敗凡間骨，中授先生指教無。"]'),
('6101a577-e246-46c7-b451-000521d1f2bb','定遠樓','羅隱','唐','唐诗','tang','','[]','前年上將定妖氛，曾築巖城駐大軍。',64,'全唐诗/poet.tang.36000.json','["前年上將定妖氛，曾築巖城駐大軍。", "近日關防雖弛柝，舊時欄檻尚侵雲。", "蠻兵績盛人皆伏，坐石名高世共聞。", "唯恐亂來良吏少，不知誰解敘功勳。"]'),
('b24c44c9-d48a-4d7f-ba13-be8433a97c2f','送程尊師東遊有寄','羅隱','唐','唐诗','tang','','[]','華蓋峰前擬卜耕，主人無奈又閑行。',64,'全唐诗/poet.tang.36000.json','["華蓋峰前擬卜耕，主人無奈又閑行。", "且憑鶴駕尋滄海，又恐犀軒過赤城。", "絳簡便應朝右弼，紫旄兼合見東卿。", "勸君莫忘歸時節，芝似螢光處處生。"]'),
('6b599447-34c3-46ef-a55c-cfac2584aee2','江亭別裴饒','羅隱','唐','唐诗','tang','','[]','行杯且待怨歌終，多病憐君事事同。',64,'全唐诗/poet.tang.36000.json','["行杯且待怨歌終，多病憐君事事同。", "衰鬢別來光景裏，故鄉歸去亂罹中。", "乾坤墊裂三分在，井邑摧殘一半空。", "日晚長亭問西使，不堪車馬尚萍蓬。"]'),
('f9d15499-e147-430b-9a5b-ea45bd6e1eaf','江南寄所知周僕射','羅隱','唐','唐诗','tang','','[]','曾陪公子醉西園，峴首碑前事嬾言。',64,'全唐诗/poet.tang.36000.json','["曾陪公子醉西園，峴首碑前事嬾言。", "世亂共嗟王粲老，時危俱受信陵恩。", "潮憐把醆吟江徼，雨憶凭闌望海門。", "飛蓋寂寥清宴罷，不知簪履更誰存。"]'),
('1a92305b-7497-4ed5-979a-f0eb89d170a7','錢唐見芮逢','羅隱','唐','唐诗','tang','','[]','蔡倫池北雁峰前，罹亂相兼十九年。',64,'全唐诗/poet.tang.36000.json','["蔡倫池北雁峰前，罹亂相兼十九年。", "所喜故人猶會面，不堪良牧已重泉。", "醉思把筯欹歌席，狂憶判身入酒船。", "今日與君贏得在，戴家灣裏兩皤然。"]'),
('bfd14c86-ad99-4dcc-a5d0-c51aaad5329b','江都','羅隱','唐','唐诗','tang','','[]','淮王高讌動江都，曾憶狂生亦坐隅。',64,'全唐诗/poet.tang.36000.json','["淮王高讌動江都，曾憶狂生亦坐隅。", "九里樓臺牽翡翠，兩行鴛鷺踏真珠。", "歌聽麗句秦雲咽，詩轉新題蜀錦鋪。", "惆悵晉陽星拆後，世間兵革地荒蕪。"]'),
('46d5aab7-719f-4885-a33a-34f115c93731','湖上歲暮感懷有寄友人','羅隱','唐','唐诗','tang','','[]','雪天螢席幾辛勤，同志當時四五人。',66,'全唐诗/poet.tang.36000.json','["雪天螢席幾辛勤，同志當時四五人。", "蘭版地寒俱[受]露，桂堂風惡獨傷春。", "音書久絕應埋玉，編簡難言竟委塵。", "唯有廣都龐令在，白頭罇酒憶交親。"]'),
('53a0a9c9-3322-4505-9bdf-b028ee16fc32','送張綰游鍾陵','羅隱','唐','唐诗','tang','','[]','南憶龍沙兩岸行，當時天下尚清平。',64,'全唐诗/poet.tang.36000.json','["南憶龍沙兩岸行，當時天下尚清平。", "醉眠野寺花方落，吟倚江樓月欲明。", "老去亦知難重到，亂來爭肯不牽情。", "西山十二真人在，從此煩君語姓名。"]'),
('b0c210de-b965-48fd-ab4f-1275dfbe2d24','送{巩/言}光大師','羅隱','唐','唐诗','tang','','[]','禹祠分首戴灣逢，健筆尋知達九重。',64,'全唐诗/poet.tang.36000.json','["禹祠分首戴灣逢，健筆尋知達九重。", "聖主賜衣憐絕藝，侍臣摛藻許高蹤。", "寧親久別街西寺，待詔初離海上峰。", "一種苦心師得了，不須回首笑龍鍾。"]'),
('09941bcf-4168-41c5-a3c1-3e4941f6d802','息夫人廟','羅隱','唐','唐诗','tang','','[]','百雉摧殘連野青，廟門猶見昔朝廷。',64,'全唐诗/poet.tang.36000.json','["百雉摧殘連野青，廟門猶見昔朝廷。", "一生雖抱楚王恨，千載終爲息地靈。", "蟲網翠環終縹緲，風吹寶瑟助微冥。", "玉顏渾似羞來客，依舊無言照畫屏。"]'),
('cebcbc22-16f4-4384-9dd5-21a0411e2f34','漂母塚','羅隱','唐','唐诗','tang','','[]','寂寂荒墳一水濱，蘆洲絕島自相親。',64,'全唐诗/poet.tang.36000.json','["寂寂荒墳一水濱，蘆洲絕島自相親。", "青娥已落淮邊月，白骨甘爲泉下塵。", "原上荻花飄素髪，道傍菰葉碎羅巾。", "雖然寂寞千秋魄，猶是韓侯舊主人。"]'),
('9d8d8a66-2da9-425d-813a-eea228a8d09f','感懷','羅隱','唐','唐诗','tang','','[]','石徑松軒亦自由，謾隨浮世逐飄流。',64,'全唐诗/poet.tang.36000.json','["石徑松軒亦自由，謾隨浮世逐飄流。", "駑駘路結前程恨，蟋蟀床生半夜秋。", "揜耳惡聞宮妾語，低顏須向路人羞。", "雖教小事相催逼，未到青雲擬白頭。"]'),
('4711cb1e-1139-4d70-870f-be1ed149e06d','扇上畫牡丹','羅隱','唐','唐诗','tang','','[]','爲愛紅芳滿砌堦，教人扇上畫將來。',64,'全唐诗/poet.tang.36000.json','["爲愛紅芳滿砌堦，教人扇上畫將來。", "葉隨彩筆參差長，花逐輕風吹第開。", "閑挂幾曾停蛺蜨，頻搖不怕落莓苔。", "根生無地如仙桂，疑是姮娥月裏栽。"]'),
('a724d990-45eb-45ba-83ed-aae74c3c4028','書懷','羅隱','唐','唐诗','tang','','[]','釣船拋却異鄉來，擬向何門用不才。',32,'全唐诗/poet.tang.36000.json','["釣船拋却異鄉來，擬向何門用不才。", "日晚獨登樓上望，馬蹄車轍滿塵埃。"]'),
('08b7195e-2b66-4935-868e-679f9419bf43','七夕','羅隱','唐','唐诗','tang','','[]','月帳星房次第開，兩情惟恐曙光催。',32,'全唐诗/poet.tang.36000.json','["月帳星房次第開，兩情惟恐曙光催。", "時人不用穿鍼待，沒得心情送巧來。"]'),
('dcbaba50-ee8f-4aed-b8a3-76de8820ad59','柳','羅隱','唐','唐诗','tang','','[]','一簇青煙鎖玉樓，半垂闌畔半垂溝。',32,'全唐诗/poet.tang.36000.json','["一簇青煙鎖玉樓，半垂闌畔半垂溝。", "明年更有新條在，繞亂春風卒未休。"]'),
('41b5f696-3eae-4a5c-93c0-74a6d31677dd','羅敷水','羅隱','唐','唐诗','tang','','[]','雉聲角角野田春，試駐征車問水濱。',32,'全唐诗/poet.tang.36000.json','["雉聲角角野田春，試駐征車問水濱。", "數樹枯桑雖不語，思量應合識秦人。"]'),
('1dbdbf4e-0e7b-4e8f-b9bb-0b0d910f1b24','京中正月七日立春','羅隱','唐','唐诗','tang','','[]','一二三四五六七，萬木生芽是今日。',32,'全唐诗/poet.tang.36000.json','["一二三四五六七，萬木生芽是今日。", "遠天歸雁拂雲飛，近水遊魚迸冰出。"]'),
('b1d648ad-eb39-45ac-b3e7-e6ad133e39cd','貴游','羅隱','唐','唐诗','tang','','[]','館陶園外雨初晴，繡轂香車入鳳城。',32,'全唐诗/poet.tang.36000.json','["館陶園外雨初晴，繡轂香車入鳳城。", "八尺家僮三尺箠，何知高祖要蒼生。"]'),
('6ea74125-a999-437c-b429-50d484d27f3b','嚴陵灘','羅隱','唐','唐诗','tang','','[]','中都九鼎勤英髦，漁釣牛蓑且遁逃。',32,'全唐诗/poet.tang.36000.json','["中都九鼎勤英髦，漁釣牛蓑且遁逃。", "世祖升遐夫子死，原陵不及釣臺高。"]'),
('d312188d-6a0f-471f-b359-f613ac79e84f','虛白堂前牡丹相傳云太傅手植在錢塘','羅隱','唐','唐诗','tang','','[]','欲詢往事奈無言，六十年來託此根。',64,'全唐诗/poet.tang.36000.json','["欲詢往事奈無言，六十年來託此根。", "香暖幾飄袁虎扇，格高常對孔融罇。", "曾憂世亂陰難合，且喜春殘色上存。", "莫背闌干便相笑，與君俱受主人恩。"]'),
('42aaf6ae-5478-4d8a-bd32-be4b97a5073a','縣齋秋晚酬友人朱瓚見寄','羅隱','唐','唐诗','tang','','[]','中和節後捧瓊瑰，坐讀行吟數月來。',64,'全唐诗/poet.tang.36000.json','["中和節後捧瓊瑰，坐讀行吟數月來。", "只歎雕龍方擅價，不知赬尾竟空回。", "千枝白露陶潛柳，百尺黃金郭隗臺。", "惆悵報君無玉案，水天東望一裴回。"]'),
('34b2ca6f-22d3-4213-84e9-9f57691e4988','第五將軍于餘杭天柱宮入道因題寄','羅隱','唐','唐诗','tang','','[]','交棃火棗味何如，聞說苕川已下車。',64,'全唐诗/poet.tang.36000.json','["交棃火棗味何如，聞說苕川已下車。", "瓦榼尚攜京口酒，草堂應寫潁陽書。", "亦知得意須乘鶴，未必忘機便釣魚。", "欲恐武皇還望祀，軟輪徵入問玄虛。"]'),
('1959433c-2d93-4d1e-bb6c-bcba84bc7a1c','寄無相禪師','羅隱','唐','唐诗','tang','','[]','老住西峰第幾層，爲師回首憶南能。',64,'全唐诗/poet.tang.36000.json','["老住西峰第幾層，爲師回首憶南能。", "有緣有相應非佛，無我無人始是僧。", "爛椹作袍名復利，鑠金爲講愛兼憎。", "何如一衲塵埃外，日日香煙夜夜燈。"]'),
('860a14fe-e927-43ef-a579-a966dd6525d9','秋日有寄','羅隱','唐','唐诗','tang','','[]','丹青未合便回頭，見盡人閒事始休。',64,'全唐诗/poet.tang.36000.json','["丹青未合便回頭，見盡人閒事始休。", "只有百神朝寶鏡，永無纖浪犯虛舟。", "曾臨鐵甕雖分職，近得金陵亦偶遊。", "東去西來人不會，上卿踪跡本玄洲。"]'),
('9e4963dc-7a73-41a9-951a-475b2c20fee8','送前南昌崔令替任映攝新城縣','羅隱','唐','唐诗','tang','','[]','五年苛政甚蟲螟，深喜夫君已戴星。',64,'全唐诗/poet.tang.36000.json','["五年苛政甚蟲螟，深喜夫君已戴星。", "大族不唯專禮樂，上才終是惜生靈。", "亦知單父琴猶在，莫厭東歸酒未醒。", "二月春風何處好，亞夫營畔柳青青。"]'),
('0921c427-83e4-47aa-aff9-38f0edc6cb30','下第作','羅隱','唐','唐诗','tang','','[]','年年模樣一般般，何似東歸把釣竿。',64,'全唐诗/poet.tang.36000.json','["年年模樣一般般，何似東歸把釣竿。", "嵒谷謾勞思雨露，彩雲終是逐鵷鸞。", "塵迷魏闕身應老，水到吳門葉欲殘。", "至竟窮途也須達，才能長與世人看。"]'),
('06122850-e2d5-4e8d-ae8b-03ea47f02d60','丁亥歲作','羅隱','唐','唐诗','tang','','[]','病想醫門渴望梅，十年心地僅成灰。',64,'全唐诗/poet.tang.36000.json','["病想醫門渴望梅，十年心地僅成灰。", "早知世事長如此，自是孤寒不合來。", "谷畔氣濃高蔽日，蟄邊聲煖乍聞雷。", "滿城桃李君看取，一一還從舊處開。"]'),
('1e6c7afe-d709-472a-a611-b3a436878615','北邙山','羅隱','唐','唐诗','tang','','[]','一種山前路入秦，嵩山堪愛此傷神。',64,'全唐诗/poet.tang.36000.json','["一種山前路入秦，嵩山堪愛此傷神。", "魏明未死虛留意，莊叟雖生酌滿巾。", "何必更尋無主骨，也知曾有弄權人。", "羨他緱嶺吹簫客，閑訪雲頭看俗塵。"]'),
('3af802af-9104-444a-85cc-9f01a3f2d511','重過三衢哭孫員外','羅隱','唐','唐诗','tang','','[]','爛柯山下忍重到，雙檜樓前日欲殘。',64,'全唐诗/poet.tang.36000.json','["爛柯山下忍重到，雙檜樓前日欲殘。", "華屋未移春照灼，故侯何在淚汍瀾。", "不唯濟物工夫大，長憶容才尺度寬。", "一慟旁人莫相笑，知音衰盡路行難。"]'),
('fad88e8e-d295-4d9a-97b8-bcbdcbe0a229','送蘄州裴員外','羅隱','唐','唐诗','tang','','[]','六枝仙桂最先春，蕭灑高辭九陌塵。',64,'全唐诗/poet.tang.36000.json','["六枝仙桂最先春，蕭灑高辭九陌塵。", "兩晉家聲須有主，六朝文雅別無人。", "榮驅豹尾拋同輩，貴上螭頭見近臣。", "蘄水蒼生莫相羨，早看歸去掌絲綸。"]'),
('254e8d60-2913-44d3-9360-01a328651127','重九日廣陵道中','羅隱','唐','唐诗','tang','','[]','秋山抱病何處登，前時韋曲今廣陵。',64,'全唐诗/poet.tang.36000.json','["秋山抱病何處登，前時韋曲今廣陵。", "廣陵大醉不解悶，韋曲舊遊堪拊膺。", "佳節縱饒隨分過，流年無奈得人憎。", "却驅羸馬向前去，牢落路岐非所能。"]'),
('b8bd7953-fdbf-42f7-b4b4-ffa39d44571b','東歸別所知','羅隱','唐','唐诗','tang','','[]','芙蓉宮闕二妃壇，兩處因依五歲寒。',64,'全唐诗/poet.tang.36000.json','["芙蓉宮闕二妃壇，兩處因依五歲寒。", "鄒律有風吹不變，郄枝無分住應難。", "愁心似火還燒鬢，別淚非珠謾落盤。", "却羨淮南好雞犬，也能終始逐劉安。"]'),
('0d8d0496-b8fb-4cc5-b59b-8a67cb611e66','旅舍書懷寄所知二首 一','羅隱','唐','唐诗','tang','','[]','思量前事不堪尋，牢落餘情滿素琴。',64,'全唐诗/poet.tang.36000.json','["思量前事不堪尋，牢落餘情滿素琴。", "四海豈無騰躍路，一家長有別離心。", "道從汩沒甘雌伏，跡恐因循更陸沈。", "寂寞誰應弔空館，異鄉時節獨霑襟。"]'),
('a01761e1-66ca-440f-ad31-9a610dea9514','旅舍書懷寄所知二首 二','羅隱','唐','唐诗','tang','','[]','簟卷兩牀琴瑟秋，暫憑前計奈相尤。',64,'全唐诗/poet.tang.36000.json','["簟卷兩牀琴瑟秋，暫憑前計奈相尤。", "塵飄馬尾甘蓬轉，酒憶江邊有夢留。", "隋帝舊祠雖寂寞，楚妃清唱亦風流。", "可憐別恨無人見，獨背殘陽下寺樓。"]'),
('9aa54def-386d-4a9b-81a6-002102127901','西京道中','羅隱','唐','唐诗','tang','','[]','半夜秋聲獨斷蓬，百年身事筭成空。',64,'全唐诗/poet.tang.36000.json','["半夜秋聲獨斷蓬，百年身事筭成空。", "禰生詞賦拋江夏，漢祖精神憶沛中。", "未必他時能富貴，只應從此見窮通。", "邊禽隴水休相笑，自有滄洲一棹風。"]'),
('f44053ed-a02a-448d-b685-aa934cd36755','粉','羅隱','唐','唐诗','tang','','[]','每持纖白助君時，霜自無憀雪自疑。',64,'全唐诗/poet.tang.36000.json','["每持纖白助君時，霜自無憀雪自疑。", "郎若姓何應解傅，女能窺宋不勞施。", "妝成麗色唯花妬，落盡啼痕只鏡知。", "最好玉京仙署裏，更知秋月照瓊枝。"]'),
('fee650e5-e9fc-410a-8e67-736f0ea4ea07','贈漁翁','羅隱','唐','唐诗','tang','','[]','葉艇悠揚鶴髪垂，生涯空託一綸絲。',64,'全唐诗/poet.tang.36000.json','["葉艇悠揚鶴髪垂，生涯空託一綸絲。", "是非不向眼前起，寒暑任從波上移。", "風瀁長歌籠月裏，夢和春雨晝眠時。", "逍遙此意誰人會，應有青山淥水知。"]'),
('89d752ce-b1ab-413f-a91f-26a04f59c54f','下第寄張坤','羅隱','唐','唐诗','tang','','[]','謾費精神掉五侯，破琴孤劒是身讐。',64,'全唐诗/poet.tang.36000.json','["謾費精神掉五侯，破琴孤劒是身讐。", "九衢護闕擬何去，玉壘銅梁空舊遊。", "蝴蝶有情牽晚夢，杜鵑無賴伴春愁。", "思量不及張公子，經歲池江倚酒樓。"]'),
('9db6276d-22da-4c7e-8ebe-4ff07748f1c3','東歸別常修','羅隱','唐','唐诗','tang','','[]','六載辛勤九陌中，却尋歸路五湖東。',64,'全唐诗/poet.tang.36000.json','["六載辛勤九陌中，却尋歸路五湖東。", "名慙桂苑一枝綠，鱠憶松江兩筯紅。", "浮世到頭須適性，男兒何必盡成功。", "唯慙鮑叔深知我，他日蒲帆百尺風。"]'),
('48bacbae-c4d2-45a0-93e9-b6daa8b51e15','言','羅隱','唐','唐诗','tang','','[]','珪玷由來尚可磨，似簧終日復如何。',64,'全唐诗/poet.tang.36000.json','["珪玷由來尚可磨，似簧終日復如何。", "成名成事皆因慎，亡國亡家只爲多。", "須信禍胎生利口，莫將譏思逞懸河。", "猩猩鸚鵡無端解，長向人間被網羅。"]'),
('e37b8021-3571-4d44-974d-e0c28b209f0b','簡令生日','羅隱','唐','唐诗','tang','','[]','祥煙靄靄拂樓臺，慶積玄元節後來。',64,'全唐诗/poet.tang.36000.json','["祥煙靄靄拂樓臺，慶積玄元節後來。", "已向青陽標四序，便從嵩嶽應三台。", "龜銜玉柄增年筭，鶴舞瓊筵獻壽杯。", "自顧下儒何以祝，柱天功業濟時才。"]'),
('7ee74800-56eb-4d0b-9644-52094e1dbf50','晚眺','羅隱','唐','唐诗','tang','','[]','凭古城邊眺晚晴，遠村高樹轉分明。',64,'全唐诗/poet.tang.36000.json','["凭古城邊眺晚晴，遠村高樹轉分明。", "天如鏡面都來靜，地似人心總不平。", "雲向嶺頭閑不徹，水流溪裏太忙生。", "誰人得及莊居老，免被榮枯寵辱驚。"]'),
('7a0d6e69-ee2c-4bdb-97a4-f5673fc378a2','野花','羅隱','唐','唐诗','tang','','[]','萬點紅芳血色殷，爲無名字對空山。',64,'全唐诗/poet.tang.36000.json','["萬點紅芳血色殷，爲無名字對空山。", "多映戲蜨尋香住，少有行人輟櫂攀。", "若在侯門看不足，爲生江岸見如閑。", "結根必竟輸桃李，長向春城紫陌間。"]'),
('d5c78173-41c5-4d03-9e37-8cc2b02876ec','病驄馬','羅隱','唐','唐诗','tang','','[]','櫪上病驄蹄褭褭，江邊廢宅路迢迢。',96,'全唐诗/poet.tang.36000.json','["櫪上病驄蹄褭褭，江邊廢宅路迢迢。", "自經梅雨長垂耳，乍食菰漿欲折腰。", "金絡銜頭光未滅，玉花毛色瘦來焦。", "曾聽禁漏驚街鼓，慣踏康莊怕小橋。", "夜半雄聲心尚壯，日中高臥尾還搖。", "龍媒落地天池遠，何事牽牛在碧霄。"]'),
('3d5c30c2-fb5e-41bc-8c8c-0bb1115cf94d','狄浦','羅隱','唐','唐诗','tang','','[]','晴川倚落暉，極目思依依。',48,'全唐诗/poet.tang.36000.json','["晴川倚落暉，極目思依依。", "野色寒來淺，人家亂後稀。", "久貧身不達，多病意長違。", "還有漁舟在，時時夢裏歸。"]'),
('9289c3bc-1558-423d-859f-64da2a242c51','南康道中','羅隱','唐','唐诗','tang','','[]','弱冠負文翰，此中聽鹿鳴。',48,'全唐诗/poet.tang.36000.json','["弱冠負文翰，此中聽鹿鳴。", "使君延上榻，時輩仰前程。", "丹桂竟多故，白雲空有情。", "唯餘路旁淚，霑灑向塵纓。"]'),
('b57d4268-2cf1-42f2-b87b-51d921d2176c','北固亭東望寄默師','羅隱','唐','唐诗','tang','','[]','高亭暮色中，往事更誰同。',48,'全唐诗/poet.tang.36000.json','["高亭暮色中，往事更誰同。", "水謾矜天闊，山應到此窮。", "病憐京口酒，老怯海門風。", "唯有言堪解，何由見遠公。"]'),
('d5054aa7-3d44-4983-b847-c33de498ca7e','華清宮','羅隱','唐','唐诗','tang','','[]','樓殿層層佳氣多，開元時節好笙歌。',32,'全唐诗/poet.tang.36000.json','["樓殿層層佳氣多，開元時節好笙歌。", "也知道德勝堯舜，爭奈楊妃解笑何。"]'),
('13487697-62e7-4226-ad1a-ff59455bb4f5','韓信廟','羅隱','唐','唐诗','tang','','[]','翦項移秦勢自雄，布衣還是負深功。',32,'全唐诗/poet.tang.36000.json','["翦項移秦勢自雄，布衣還是負深功。", "寡妻稚女俱堪恨，却把餘杯奠蒯通。"]'),
('bc76e677-8144-4471-95d6-b962c366bbe1','韋公子','羅隱','唐','唐诗','tang','','[]','擊柱狂歌慘別顏，百年人事夢魂閒。',32,'全唐诗/poet.tang.36000.json','["擊柱狂歌慘別顏，百年人事夢魂閒。", "李將軍自嘉聲在，不得封侯亦自閑。"]'),
('358d3aeb-89c8-484c-9d8f-5f07d8e11e02','望思臺','羅隱','唐','唐诗','tang','','[]','芳草臺邊魂不歸，野煙喬木弄殘暉。',32,'全唐诗/poet.tang.36000.json','["芳草臺邊魂不歸，野煙喬木弄殘暉。", "可憐高祖清平業，留與閑人作是非。"]'),
('4bdb35d4-c035-4718-a0b9-a370804e514d','帝幸蜀','羅隱','唐','唐诗','tang','','[]','馬嵬山色翠依依，又見鑾輿幸蜀歸。',32,'全唐诗/poet.tang.36000.json','["馬嵬山色翠依依，又見鑾輿幸蜀歸。", "泉下阿蠻應有語，這迴休更怨楊妃。"]'),
('302ca5d4-da71-404f-ab9f-2753300e5133','王夷甫','羅隱','唐','唐诗','tang','','[]','把得閑書坐水濱，讀來前事亦酸辛。',32,'全唐诗/poet.tang.36000.json','["把得閑書坐水濱，讀來前事亦酸辛。", "莫言麈尾清譚柄，壞却淳風是此人。"]'),
('7119dbe0-b773-4c90-b4e5-28c155631907','鷺鷥','羅隱','唐','唐诗','tang','','[]','斜陽澹澹柳陰陰，風褭寒絲映水深。',32,'全唐诗/poet.tang.36000.json','["斜陽澹澹柳陰陰，風褭寒絲映水深。", "不要向人誇素白，也知常有羨魚心。"]'),
('2dcc2b4b-e4ec-4e10-b990-3b20a87f1e7e','書淮陰侯傳','羅隱','唐','唐诗','tang','','[]','寒燈挑盡見遺塵，試瀝椒漿合有神。',32,'全唐诗/poet.tang.36000.json','["寒燈挑盡見遺塵，試瀝椒漿合有神。", "莫恨高皇不終始，滅秦謀項是何人。"]'),
('e8863962-9946-497c-891b-647435ebd726','青山廟','羅隱','唐','唐诗','tang','','[]','市簫聲咽跡崎嶇，雪恥酬恩此丈夫。',32,'全唐诗/poet.tang.36000.json','["市簫聲咽跡崎嶇，雪恥酬恩此丈夫。", "霸主兩亡時亦異，不知魂魄更無歸。"]'),
('cee3fb5b-ae43-47d0-a10c-16aa3320e16a','小松','羅隱','唐','唐诗','tang','','[]','已有清陰逼座隅，愛聲仙客肯過無。',32,'全唐诗/poet.tang.36000.json','["已有清陰逼座隅，愛聲仙客肯過無。", "陵遷谷變須高節，莫向人間作大夫。"]'),
('4db79e1b-aa48-4759-9a2c-1373f63d7c52','竹','羅隱','唐','唐诗','tang','','[]','籬外清陰接藥闌，曉風交戛碧琅玕。',32,'全唐诗/poet.tang.36000.json','["籬外清陰接藥闌，曉風交戛碧琅玕。", "子猷死後知音少，粉節霜筠謾歲寒。"]'),
('079f7f8f-d3a8-4151-95d9-a4064ec5ccc1','謾天嶺','羅隱','唐','唐诗','tang','','[]','西去休言蜀道難，此中危峻已多端。',32,'全唐诗/poet.tang.36000.json','["西去休言蜀道難，此中危峻已多端。", "到頭未會蒼蒼色，爭得禁他兩度謾。"]'),
('f43ae73e-8db4-4d73-bd16-b4331e2d3b00','秋蟲賦','羅隱','唐','唐诗','tang','','[]','物之小兮，迎網而斃。',50,'全唐诗/poet.tang.36000.json','["物之小兮，迎網而斃。", "物之大兮，兼網而逝。", "網也者，繩其小而不繩其大。", "吾不知爾身之危兮，腹之餒兮。", "吁！。"]'),
('bf25390e-0c8b-4ccf-996c-3a8a5c4fe4f7','蟋蟀詩','羅隱','唐','唐诗','tang','','[]','頑颸斃芳，吹愁夕長。',160,'全唐诗/poet.tang.36000.json','["頑颸斃芳，吹愁夕長。", "屑戍有動，歌離弔夢。", "如訴如言，緒引虛寬。", "周隙伺榻，繁咽夤緣。", "范睡蟬老，冠峨緌好。", "不冠不緌，爾奚以悲。", "蚊蚋有毒，食人肌肉。", "蒼蠅多端，黑白偷安。", "爾也出處，物兮莫累。", "壞舍啼衰，虛堂泣曙。", "勿徇諠譁，鼠豈無牙。", "勿學萋菲，垣亦有耳。", "危條槁飛，抽恨咿咿。", "別帳缸冷，柔魂不定。", "美人在何，夜影流波。", "與子佇立，裴回思多。"]'),
('4cffa133-1dd0-411b-9529-7953920c1aa0','西川與蔡十九同別子超','羅隱','唐','唐诗','tang','','[]','相歡雖則不多時，相別那能不歛眉。',64,'全唐诗/poet.tang.36000.json','["相歡雖則不多時，相別那能不歛眉。", "蜀客賦高君解愛，楚宮腰細我還知。", "百年恩愛無終始，萬里因緣有夢思。", "腸斷門前舊行處，不堪全屬五陵兒。"]'),
('43580422-ead9-4e06-b4aa-e881b4965287','龍泉東下却寄孫員外','羅隱','唐','唐诗','tang','','[]','縠江東下幾多程，每泊孤舟即有情。',64,'全唐诗/poet.tang.36000.json','["縠江東下幾多程，每泊孤舟即有情。", "山色已隨遊子遠，水紋猶認主人清。", "恩如海岳何時報，恨似煙花觸處生。", "百尺風帆兩行淚，不堪迴首望崢嶸。"]'),
('40f33b24-11f8-4b3b-a125-809932e9101f','牡丹','羅隱','唐','唐诗','tang','','[]','豔多煙重欲開難，紅蘂當心一抹檀。',64,'全唐诗/poet.tang.36000.json','["豔多煙重欲開難，紅蘂當心一抹檀。", "公子醉歸燈下見，美人朝插鏡中看。", "當庭始覺春風貴，帶雨方知國色寒。", "日晚更將何所似，太真無力凭闌干。"]'),
('067ad4c1-e52d-4048-9eae-9b27c33a6c4b','巫山高','羅隱','唐','唐诗','tang','','[]','下壓重泉上千仞，香雲結夢西風緊。',96,'全唐诗/poet.tang.36000.json','["下壓重泉上千仞，香雲結夢西風緊。", "縱有精靈得往來，狖軛鼯軒亦顛隕。", "嵐光雙雙雷隱隱，愁爲衣裳恨爲鬢。", "暮灑朝行何所之，江邊日月情無盡。", "珠零冷露丹墮楓，細腰長臉愁滿宮。", "人生對面猶異同，況在千巖萬壑中。"]'),
('042d20d8-077a-4692-891b-8e236e32fce0','江南行','羅隱','唐','唐诗','tang','','[]','江煙濕雨蛟綃軟，漠漠小山眉黛淺。',80,'全唐诗/poet.tang.36000.json','["江煙濕雨蛟綃軟，漠漠小山眉黛淺。", "水國多愁又有情，夜槽壓酒銀船滿。", "細絲搖柳凝曉空，吳王臺榭春夢中。", "鴛鴦鸂鶒喚不起，平鋪綠水眠東風。", "西陵路邊月悄悄，油碧輕車蘇小小。"]'),
('cc86bce2-f842-4643-9372-3e4e82c31add','空城雀','羅隱','唐','唐诗','tang','','[]','雀入官倉中，所食能損幾。',48,'全唐诗/poet.tang.36000.json','["雀入官倉中，所食能損幾。", "所恨往復頻，官倉乃害爾。", "魚網不在天，鳥網不張水。", "飲啄要自然，何必空城裏。"]'),
('d3589d6f-b2ff-452a-a1eb-3ab22ea94a59','芳樹','羅隱','唐','唐诗','tang','','[]','細蕚慢逐風，暖香閑破鼻。',163,'全唐诗/poet.tang.36000.json','["細蕚慢逐風，暖香閑破鼻。", "青帝固有心，時時漏天意。", "去年高枝猶墮地，今年低枝已顦顇。", "吾所以見造化之權，變通之理。", "春夏作頭，秋冬爲尾。", "循環反覆無終已，人生長短同一軌。", "若使威可以制，力可以止。", "則秦皇不肯斂手下沙丘，孟賁不合低頭入蒿里。", "伊人強猛猶如此，顧我勞生何足恃。", "但顧我開素袍，傾綠蟻。", "陶陶兀兀大醉於清宵白晝間，任他上是天，下是地。"]'),
('885da9f9-7098-4858-8130-75764fd2797b','聽琴','羅隱','唐','唐诗','tang','','[]','寒雨蕭蕭落井梧，夜深何處怨啼烏？不知一盞臨邛酒，救得相如渴病無。',32,'全唐诗/poet.tang.36000.json','["寒雨蕭蕭落井梧，夜深何處怨啼烏？不知一盞臨邛酒，救得相如渴病無。"]'),
('34540fe9-9378-4280-8146-b0e9d421e07a','大梁見喬詡','羅隱','唐','唐诗','tang','','[]','湘水春浮岸，淮燈夜滿橋。',192,'全唐诗/poet.tang.36000.json','["湘水春浮岸，淮燈夜滿橋。", "六年悲梗斷，兩地各萍漂。", "刀筆依三事，篇章奏珥貂。", "跡卑甘汩沒，名散稱逍遙。", "好寺松爲徑，空江桂作橈。", "野香花伴落，缸暖酒和燒。", "晉沼尋遊鳳，秦冠竟歎鴞。", "骨凡雞犬薄，魂斷蕙蘭招。", "悵望添燕琯，蹉跎厭魯瓢。", "敗桐方委爨，冤匣正沖霄。", "戰代安釐國，封崇孝景朝。", "千年非有限，一醉解無聊。", "漏永燈花暗，爐紅雪片銷。", "久遊家共遠，相對鬢俱凋。", "運命從難合，光陰奈不饒。", "到頭蓑笠契，兩信釣魚潮。"]'),
('0a9a8b2f-3cef-4df4-8767-0df44bf64429','寄洪正師','羅隱','唐','唐诗','tang','','[]','寄蹇渾成跡，經年滯杜南。',48,'全唐诗/poet.tang.36000.json','["寄蹇渾成跡，經年滯杜南。", "價輕猶有二，足刖已過三。", "雞肋曹公忿，猪肝仲叔慙。", "會應謀避地，依約近禪菴。"]'),
('58d3b5b9-212f-48be-9cbf-f9724e6be9bc','聖真觀劉真師院十韻','羅隱','唐','唐诗','tang','','[]','簾下嚴君卜，窗間少室峰。',120,'全唐诗/poet.tang.36000.json','["簾下嚴君卜，窗間少室峰。", "攝生門已盡，混跡世猶逢。", "山藪師王烈，簪纓友戴顒。", "魚跳介象鱠，飯吐葛玄蜂。", "紫飽垂新椹，黃輕墮小松。", "塵埃金谷路，樓閣上陽鐘。", "野耗鳶肩寄，仙書鳥爪封。", "支牀龜縱老，取箭鶴何慵。", "別久曾牽念，閑來肯壓重。", "尚餘青竹在，試爲剪成龍。"]'),
('30f9cafd-f1ee-466f-9983-d651fbe44ac3','寄聶尊師','羅隱','唐','唐诗','tang','','[]','欲芟荆棘種交棃，指畫城中日恐遲。',32,'全唐诗/poet.tang.36000.json','["欲芟荆棘種交棃，指畫城中日恐遲。", "安得紫青磨鏡石，與君閑處看榮衰。"]'),
('ca2ecd97-8029-4a50-ba71-07d6a3509658','金山僧院','羅隱','唐','唐诗','tang','','[]','根盤蛟蜃路藤蘿，四面無塵輟棹過。',32,'全唐诗/poet.tang.36000.json','["根盤蛟蜃路藤蘿，四面無塵輟棹過。", "得似吾師始惆悵，眼前終日有風波。"]'),
('26848a50-5cfa-42a5-ab77-82e90d4d8262','酬高崇節','羅隱','唐','唐诗','tang','','[]','舊遊雖一夢，別緒忽千般。',48,'全唐诗/poet.tang.36000.json','["舊遊雖一夢，別緒忽千般。", "敗草湯陵晚，衰槐楚寺寒。", "數奇常自愧，時薄欲何干。", "猶賴君相勉，慇懃貢禹冠。"]'),
('cc6f537b-504b-4eda-b491-cb902117583a','送汝州李中丞十二韻','羅隱','唐','唐诗','tang','','[]','羣盜方爲梗，分符奏未寧。',144,'全唐诗/poet.tang.36000.json','["羣盜方爲梗，分符奏未寧。", "黃巾攻郡邑，白梃掠生靈。", "塵土周畿暗，瘡痍汝水腥。", "一兇雖剪滅，數縣尚凋零。", "理必資寬猛，謀須藉典刑。", "與能纔物論，慎選忽天庭。", "官品尊臺秩，山河擁福星。", "虎知應去境，牛在肯全形。", "舊政窮人瘼，新銜展武經。", "關防秋草白，城壁晚峰青。", "破膽期來復，迷魂想待醒。", "魯山行縣後，聊爲奠惟馨。"]'),
('bad1e4c7-e8dd-48cd-9246-a008d173b2b9','淮南送節度盧端公將命之汴州端公常爲汴州相公從事','羅隱','唐','唐诗','tang','','[]','吹臺高倚圃田東，此去軺車事不同。',64,'全唐诗/poet.tang.36000.json','["吹臺高倚圃田東，此去軺車事不同。", "珠履舊參蕭相國，綵衣今佐晉司空。", "醉離淮甸寒星下，吟指梁園密雪中。", "到彼的知宣室語，幾時徵拜黑頭公。"]'),
('b4b2c1d1-e85e-47ac-8e23-43b780a1e7cf','送盧端公歸臺盧校書之夏縣','羅隱','唐','唐诗','tang','','[]','綿綿隄草拂征輪，龍虎俱辭楚水濱。',64,'全唐诗/poet.tang.36000.json','["綿綿隄草拂征輪，龍虎俱辭楚水濱。", "只是勝之爲御史，不知梅福是仙人。", "地推八米源流盛，才笑三張事業貧。", "一種西歸一般達，柏臺霜冷夏城春。"]'),
('3c4d816f-818e-4209-a74b-ef9f90855b00','送朗州張員外','羅隱','唐','唐诗','tang','','[]','聖朝綸閣最延才，須牧生民始入來。',64,'全唐诗/poet.tang.36000.json','["聖朝綸閣最延才，須牧生民始入來。", "鳳藻已期他日用，隼旟應是隔年迴。", "旗飄峴首嵐光重，酒奠湘江杜魄哀。", "腸斷秦原二三月，好花全爲使君開。"]'),
('5eb99ee8-7f00-4972-bd75-c473daccf06b','淮南送工部盧員外赴闕','羅隱','唐','唐诗','tang','','[]','始從豸角曳長裾，又吐雞香奏玉除。',64,'全唐诗/poet.tang.36000.json','["始從豸角曳長裾，又吐雞香奏玉除。", "隋邸舊僚推謝掾，漢廷高議得相如。", "貴分赤筆升蘭署，榮著緋衣從板輿。", "遙想到時秋欲盡，禁城涼冷露槐疎。"]'),
('427d96ec-b5a2-4e87-9ec8-e34d63c4bde6','淮南送司勳李郎中赴闕','羅隱','唐','唐诗','tang','','[]','中朝品秩重文章，雙筆依前賜望郎。',64,'全唐诗/poet.tang.36000.json','["中朝品秩重文章，雙筆依前賜望郎。", "五夜星辰歸帝座，半年樽俎奉梁王。", "南都水煖蓮分影，北極天寒雁著行。", "不必戀恩多感激，過淮應合見徵黃。"]'),
('2f46eaf0-0fc6-4ed3-88a6-9300674f4018','送陸郎中赴闕','羅隱','唐','唐诗','tang','','[]','幕下留連兩月強，爐邊侍史舊焚香。',64,'全唐诗/poet.tang.36000.json','["幕下留連兩月強，爐邊侍史舊焚香。", "不關雨露偏垂意，自是鴛鸞合著行。", "三署履聲通建禮，九霄星彩映明光。", "少瑜鏤管丘遲錦，從此西垣使鳳凰。"]'),
('93efeb8f-09d7-493c-b02d-2fffa90bdbcc','途中送人東遊有寄','羅隱','唐','唐诗','tang','','[]','離驂莫惜暫逡巡，君向池陽我入秦。',64,'全唐诗/poet.tang.36000.json','["離驂莫惜暫逡巡，君向池陽我入秦。", "歲月易拋非曩日，酒桮難得是同人。", "路經隋苑橋燈夜，江轉臺城岸草春。", "此處故交誰見問，爲言霜鬢壓風塵。"]'),
('82f13e09-e6e1-4b12-9961-56b4277c84c4','過廢江寧縣','羅隱','唐','唐诗','tang','','[]','縣前水色細鱗鱗，一爲夫君弔水濱。',64,'全唐诗/poet.tang.36000.json','["縣前水色細鱗鱗，一爲夫君弔水濱。", "漫把文章矜後代，可知榮貴是他人。", "鶯偷舊韻還成曲，草賴餘吟盡解春。", "我亦有心無處說，等閑停棹似迷津。"]'),
('a6ec0d0b-9377-4502-a81a-c297be4ffe08','邊夜','羅隱','唐','唐诗','tang','','[]','光景漂如水，生涯轉似萍。',36,'全唐诗/poet.tang.36000.json','["光景漂如水，生涯轉似萍。", "雁門窮朔路，牛斗故鄉星。", "句盡人誰切，歌終淚自零。"]'),
('73c531f4-075b-4cce-a110-1d4af4837f75','哭張博士太常','羅隱','唐','唐诗','tang','','[]','前輩倏云歿，媿君曾比方。',48,'全唐诗/poet.tang.36000.json','["前輩倏云歿，媿君曾比方。", "格卑雖不稱，言重亦難忘。", "諫草猶青瑣，悲風已白楊。", "只應移理窟，泉下對真長。"]'),
('8eb2ebff-196f-4916-ab7e-ce273a1cdc2d','淮口軍葬','羅隱','唐','唐诗','tang','','[]','一陣孤軍不復迴，更無分別只荒堆。',32,'全唐诗/poet.tang.36000.json','["一陣孤軍不復迴，更無分別只荒堆。", "莫言賦分須如此，曾作文皇赤子來。"]'),
('59f51467-08d8-4ccb-ad66-a9b137ce667f','燕昭王墓','羅隱','唐','唐诗','tang','','[]','戰國蒼茫難重尋，此中踪跡想知音。',64,'全唐诗/poet.tang.36000.json','["戰國蒼茫難重尋，此中踪跡想知音。", "強停別騎山花曉，欲弔遺魂野草深。", "浮世近來輕駿骨，高臺何處有黃金？", "思量郭隗平生事，不殉昭王是負心。"]'),
('0718070a-79f8-422f-b0ea-1b8cdeeffbb7','江南','羅隱','唐','唐诗','tang','','[]','玉樹歌聲澤國春，纍纍輜重憶亡陳。',32,'全唐诗/poet.tang.36000.json','["玉樹歌聲澤國春，纍纍輜重憶亡陳。", "垂衣端拱渾閑事，忍把江山乞與人。"]'),
('dab288a3-ee47-4a46-8b51-49d4bbb7a512','江北','羅隱','唐','唐诗','tang','','[]','廢宮荒苑莫閑愁，成敗終須要徹頭。',32,'全唐诗/poet.tang.36000.json','["廢宮荒苑莫閑愁，成敗終須要徹頭。", "一種風流一種死，朝歌爭得似揚州。"]'),
('e670d591-68cb-4dd0-bb77-ba8da3019155','早登新安縣樓','羅隱','唐','唐诗','tang','','[]','關城樹色齊，往事未全迷。',48,'全唐诗/poet.tang.36000.json','["關城樹色齊，往事未全迷。", "塞路真人氣，封門壯土泥。", "草濃延蝶舞，花密教鶯啼。", "若以鳴爲德，鸞皇不及雞。"]'),
('a605cbe4-ca13-45fd-8159-7b533cdf5d21','干越亭','羅隱','唐','唐诗','tang','','[]','楚水蕭蕭多病身，強凭危檻送殘春。',64,'全唐诗/poet.tang.36000.json','["楚水蕭蕭多病身，強凭危檻送殘春。", "高城自有陵兼谷，流水那知越與秦。", "岸下藤蘿陰作怪，橋邊蛟蜃夜欺人。", "琵琶洲遠江村闊，迴首征途淚滿巾。"]'),
('762dfcac-43d0-4cf0-b868-484c053623f6','南園題','羅隱','唐','唐诗','tang','','[]','搏擊路終迷，南園且灌畦。',120,'全唐诗/poet.tang.36000.json','["搏擊路終迷，南園且灌畦。", "敢言逃俗態，自是樂幽棲。", "葉長春松闊，科圓早薤齊。", "雨霑虛檻冷，雪壓遠山低。", "竹好還成徑，桃夭亦有蹊。", "小窗奔野馬，閑甕養醯雞。", "水石心逾切，煙霄分已暌。", "病憐王猛畚，愚笑隗囂泥。", "澤國潮平岸，江村柳覆堤。", "到頭乘興是，誰手好提攜。"]'),
('503cd816-6f8b-4371-b0d8-06236e2d5a5e','人日新安道中見梅花','羅隱','唐','唐诗','tang','','[]','長途酒醒臘春寒，嫩蘂香英撲馬鞍。',32,'全唐诗/poet.tang.36000.json','["長途酒醒臘春寒，嫩蘂香英撲馬鞍。", "不上壽陽公主面，憐君開得却無端。"]'),
('b42fead9-4e26-4ccc-a874-7147b82fdebb','許由廟','羅隱','唐','唐诗','tang','','[]','高挂風瓢濯漢濱，土階三尺愧清塵。',32,'全唐诗/poet.tang.36000.json','["高挂風瓢濯漢濱，土階三尺愧清塵。", "可憐比屋堪封日，若到人間是衆人。"]'),
('cca3dc32-2bb1-490a-ad00-87392746a58f','題段太尉廟','羅隱','唐','唐诗','tang','','[]','近甸蒙塵日，南梁反正年。',48,'全唐诗/poet.tang.36000.json','["近甸蒙塵日，南梁反正年。", "飄流茂陵椀，零落太官椽。", "建纛非降楚，披圖異錄燕。", "堪嗟侍中血，不及御衣前。"]'),
('42fb4b55-ff70-47e7-b16d-6a783f01ed66','湘妃廟','羅隱','唐','唐诗','tang','','[]','劉表荒碑斷水濱，廟前幽草閉殘春。',64,'全唐诗/poet.tang.36000.json','["劉表荒碑斷水濱，廟前幽草閉殘春。", "已將怨淚流斑竹，又感悲風入白蘋。", "八族未來誰北拱，四兇猶在莫南巡。", "九峰相似堪疑處，望見蒼梧不見人。"]'),
('d7bdd4f4-fd6a-45d4-8fdb-5ae21cb3097b','八駿圖','羅隱','唐','唐诗','tang','','[]','穆滿當年物外程，電腰風脚一何輕。',32,'全唐诗/poet.tang.36000.json','["穆滿當年物外程，電腰風脚一何輕。", "如今縱有驊騮在，不得長鞭不肯行。"]'),
('c34af532-0492-452a-bd0a-22cff9b13212','庭花','羅隱','唐','唐诗','tang','','[]','昨日芳豔濃，開尊幾同醉。',48,'全唐诗/poet.tang.36000.json','["昨日芳豔濃，開尊幾同醉。", "今朝風雨惡，惆悵人生事。", "南威病不起，西子老兼至。", "向晚寂無人，相偎墮紅淚。"]'),
('5a3a8df0-23dc-4c1e-acfc-67144119c682','病中題主人庭鶴','羅隱','唐','唐诗','tang','','[]','遼水華亭舊所聞，病中毛羽最憐君。',32,'全唐诗/poet.tang.36000.json','["遼水華亭舊所聞，病中毛羽最憐君。", "稻粱且足身兼健，何必青雲與白雲。"]'),
('05ed6c66-7717-4ae4-992e-4d924d4445e6','蟬','羅隱','唐','唐诗','tang','','[]','天地工夫一不遺，與君聲調借君緌。',32,'全唐诗/poet.tang.36000.json','["天地工夫一不遺，與君聲調借君緌。", "風棲露飽今如此，應忘當年滓濁時。"]'),
('6bb18e69-a6ba-4654-8e85-6c2eb8278a26','薛陽陶觱篥歌','羅隱','唐','唐诗','tang','','[]','平泉上相東征日，曾爲陽陶歌觱篥。',256,'全唐诗/poet.tang.36000.json','["平泉上相東征日，曾爲陽陶歌觱篥。", "烏江太守會稽侯，相次三篇皆俊逸。", "橋山殯葬衣冠後，金印蒼黃南去疾。", "龍樓冷落夏口寒，從此風流爲廢物。", "人間至藝難得主，懷抱差池恨星律。", "邗溝僕射戎政閑，試渡瓜洲吐伊鬱。", "西風九月草樹秋，萬喧沈寂登高樓。", "左篁揭指徵羽吼，煬帝起坐淮王愁。", "高飄咽滅出滯氣，下感知己時橫流。", "穿空激遠不可遏，髣髴似向伊水頭。", "伊水林泉今已矣，因取遺編認前事。", "武宗皇帝御宇時，四海恬然知所自。", "掃除桀黠似提箒，制壓羣豪若穿鼻。", "九鼎調和各有門，謝安空儉真兒戲。", "功高近代竟誰知，藝小似君猶不棄。", "勿惜喑嗚更一吹，與君共下難逢淚。"]'),
('656ca402-52dd-4131-8a96-5b768d0f856f','酬丘光庭','羅隱','唐','唐诗','tang','','[]','正月十一日書札，五月十六日到來。',256,'全唐诗/poet.tang.36000.json','["正月十一日書札，五月十六日到來。", "柳吟秦望咫尺地，鯉魚何處閑裴回？", "故人情意未疎索，次第序述眉眼開。", "上言二年隔煙水，下有數幅真瓊瑰。", "行吟坐讀口不倦，瀑泉激射琅玕摧。", "壁池蘭蕙日已老，村酒蘸甲時幾桮。", "鶴齡鴻算不復見，雨後蓑笠空莓苔。", "自從黃寇擾中土，人心波蕩猶未迴。", "道殷合眼拜九列，張濬掉舌升三台。", "朝廷濟濟百揆序，寧將對面容姦回。", "禍生有基妖有漸，翠華西幸蒙塵埃。", "三川梗塞兩河閉，大明宮殿生蒿萊。", "懦夫早歲不量力，策蹇仰北高崔嵬。", "千門萬戶扃鎖密，良匠不肯雕散材。", "君今得意尚如此，況我麋鹿悠悠哉。", "榮衰貴賤目所睹，莫嫌頭白黃金臺。"]'),
('25df70d9-524a-44bd-a037-c7b50e7e27f1','投宣武鄭尚書二十韻','羅隱','唐','唐诗','tang','','[]','漢代簪纓盛，梁園雉堞雄。',240,'全唐诗/poet.tang.36000.json','["漢代簪纓盛，梁園雉堞雄。", "物情須重德，時論在明公。", "族大踰開魏，高神本降嵩。", "世家惟蹇諤，官業即清通。", "翰苑論思外，綸闈嘯傲中。", "健豪驚綵鳳，高步出冥鴻。", "履歷雖吾道，行藏必聖聰。", "絳霄無繫滯，浙水忽西東。", "庾監高樓月，袁郎滿扇風。", "四年將故事，兩地有全功。", "去去才須展，行行道益隆。", "避權辭憲署，仗節出南宮。", "雁影相承接，龍圖共始終。", "自然須作礪，不必恨臨戎。", "幕下蓮花盛，竿頭㺗佩紅。", "騎兒逢郭伋，戰士得文翁。", "人地應無比，簞瓢奈屢空。", "因思一枝桂，已作斷根蓬。", "往事應歸捷，勞歌且責躬。", "殷勤信陵館，今日自途窮。"]'),
('93fd4881-1591-40c0-aa9c-1fe53cf28348','投浙東王大夫二十韻','羅隱','唐','唐诗','tang','','[]','越嶺千峰秀，淮流一派長。',240,'全唐诗/poet.tang.36000.json','["越嶺千峰秀，淮流一派長。", "暫憑開物手，來展濟時方。", "舊跡蘭亭在，高風桂樹香。", "地清無等級，天闊任徊翔。", "麈尾談何勝，螭頭筆更狂。", "直曾批鳳詔，高已冠鵷行。", "嘯傲辭民部，雍容出帝鄉。", "趙堯推印綬，句踐與封疆。", "水占仙人吹，城留御史牀。", "嘉賓鄒潤甫，百姓賀知章。", "席煖飛鸚鵡，塵輕駐驌驦。", "夜歌珠斷續，晴舞雪悠揚。", "化向棠陰布，春隨棣萼芳。", "盛名韜不得，雄略晦彌彰。", "自愧三冬學，來窺數仞牆。", "感深惟刻骨，時去欲霑裳。", "想望魚燒尾，咨嗟鼠嚙腸。", "可能因蹇拙，便合老滄浪。", "題柱心猶壯，移山志不忘。", "深慚百般病，今日問醫王。"]'),
('43dff396-d559-4a13-aebc-6c3a49106ebb','寄剡縣主簿','羅隱','唐','唐诗','tang','','[]','金庭養真地，珠篆會稽官。',48,'全唐诗/poet.tang.36000.json','["金庭養真地，珠篆會稽官。", "境勝堪長往，時危喜暫安。", "洞連滄海闊，山擁赤城寒。", "他日拋塵土，因君擬煉丹。"]'),
('ee5e99d4-99ce-48c2-8c40-7cac55b41eed','中秋不見月','羅隱','唐','唐诗','tang','','[]','風簾淅淅漏燈痕，一半秋光此夕分。',32,'全唐诗/poet.tang.36000.json','["風簾淅淅漏燈痕，一半秋光此夕分。", "天爲素娥孀怨苦，併教西北起浮雲。"]'),
('b1ee057f-f8c1-42b8-9b93-76fb0ce0b3b7','答宗人衮','羅隱','唐','唐诗','tang','','[]','崑崙水色九般流，飲即神仙憩即休。',64,'全唐诗/poet.tang.36000.json','["崑崙水色九般流，飲即神仙憩即休。", "敢恨守株曾失意，始知緣木更難求。", "鴒原謾欲均餘力，鶴髪那堪問舊遊。", "遙望北辰當上國，羨君歸掉五諸侯。"]'),
('abd590ad-4fe8-4649-900a-29ca58ac224c','早行','羅隱','唐','唐诗','tang','','[]','雨灑江聲風又吹，扁舟正與睡相宜。',32,'全唐诗/poet.tang.36000.json','["雨灑江聲風又吹，扁舟正與睡相宜。", "無端戍鼓催前去，別却青山向曉時。"]'),
('9a8a2c14-79aa-4b70-b64f-1bffc3da08bc','詠白菊','羅隱','唐','唐诗','tang','','[]','雖被風霜競欲催，皎然顏色不低摧。',64,'全唐诗/poet.tang.36000.json','["雖被風霜競欲催，皎然顏色不低摧。", "已疑素手能粧出，又似金錢未染來。", "香散自宜飄淥酒，葉交仍得蔭香苔。", "尋思閉戶中宵見，應認寒窗雪一堆。"]'),
('06268909-4216-483a-9eda-7e8fa0f7a603','晚泊宿松','羅隱','唐','唐诗','tang','','[]','解纜隨江流，晚泊古淮岸。',48,'全唐诗/poet.tang.36000.json','["解纜隨江流，晚泊古淮岸。", "歸雲送春和，繁星麗雲漢。", "春深胡雁飛，人喧水禽散。", "仰君邈難親，沈思夜將旦。"]'),
('38f597b5-438a-4ff6-9b38-9cf47637e5f3','錢塘遇默師憶潤州舊遊','羅隱','唐','唐诗','tang','','[]','歌敲玉唾壺，醉擊珊瑚枝。',48,'全唐诗/poet.tang.37000.json','["歌敲玉唾壺，醉擊珊瑚枝。", "石羊妙善街，甘露平泉碑。", "捫苔想豪傑，剔蘚看文詞。", "歸來北固山，水檻光參差。"]'),
('76bdbeba-eb3a-4907-b488-92d718252ddb','江南別','羅隱','唐','唐诗','tang','','[]','去年今夜江南別，鴛鴦翅冷飛蓬爇。',48,'全唐诗/poet.tang.37000.json','["去年今夜江南別，鴛鴦翅冷飛蓬爇。", "今年今夜江北邊，鯉魚腸斷音書絕。", "男兒心事無了時，出門上馬不自知。"]'),
('24dc017c-0acd-42bf-b425-4e5c6064f20b','四頂山','羅隱','唐','唐诗','tang','','[]','勝景天然別，精神入畫圖。',48,'全唐诗/poet.tang.37000.json','["勝景天然別，精神入畫圖。", "一山分四頂，三面瞰平湖。", "過夏僧無熱，凌冬草不枯。", "遊人來至此，願剃髪和鬚。"]'),
('044096d3-e7c3-42d9-9a3e-1ded241c8b41','姥山','羅隱','唐','唐诗','tang','','[]','臨塘古廟一神仙，繡幌花容色儼然。',64,'全唐诗/poet.tang.37000.json','["臨塘古廟一神仙，繡幌花容色儼然。", "爲逐朝雲來此地，因隨暮雨不歸天。", "眉分初月湖中鑑，香散餘風竹上煙。", "借問邑人沈水事，已經秦漢幾千年。"]'),
('b40e8056-4761-44a8-bb86-1bc4e8a22afa','岐王宅','羅隱','唐','唐诗','tang','','[]','朱邸平臺隔禁闈，貴遊陳跡尚依稀。',64,'全唐诗/poet.tang.37000.json','["朱邸平臺隔禁闈，貴遊陳跡尚依稀。", "雲低雍畤祈年去，雨細長楊從獵歸。", "申白賓朋傳道義，應劉文彩寄音徽。", "承平舊物惟君盡，猶寫雕鞍伴六飛。"]'),
('0bce38b1-7faa-45dd-8ce7-96966f1bcea1','長明燈','羅隱','唐','唐诗','tang','','[]','破暗長明世代深，煙和香氣兩沈沈。',64,'全唐诗/poet.tang.37000.json','["破暗長明世代深，煙和香氣兩沈沈。", "不知初點何人在，秪見當年火至今。", "曉似紅蓮開沼面，夜如寒月鎮潭心。", "孤光自有龍神護，雀戲蛾飛不敢侵。"]'),
('abd010b3-9dc8-4b4c-bf71-2ab48bd21504','堋口逢人','羅隱','唐','唐诗','tang','','[]','艱難別離久，中外往還深。',24,'全唐诗/poet.tang.37000.json','["艱難別離久，中外往還深。", "已改當時髪，空餘舊日心。"]'),
('0343d78e-0909-409a-92b7-93da28dbc88a','遇邊使','羅隱','唐','唐诗','tang','','[]','累年無的信，每夜望邊城。',24,'全唐诗/poet.tang.37000.json','["累年無的信，每夜望邊城。", "袖掩千行淚，書封一尺金。"]'),
('3fd0ecc8-0541-409e-b799-8a3c28f57a3a','移住別友','羅隱','唐','唐诗','tang','','[]','自到西川住，惟君別有情。',24,'全唐诗/poet.tang.37000.json','["自到西川住，惟君別有情。", "常逢對門遠，又隔一重城。"]'),
('67238820-3542-463b-a332-09a7a62b8945','宮詞','羅隱','唐','唐诗','tang','','[]','巧畫蛾眉獨出羣，當時人道便承恩。',32,'全唐诗/poet.tang.37000.json','["巧畫蛾眉獨出羣，當時人道便承恩。", "經年不見君王面，落日黃昏空掩門。"]'),
('0463eb51-53a6-43e2-9c01-f2c50e230415','涇溪','羅隱','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u54f2\u7406", "\u5199\u6c34"]','涇溪石險人競懼，終歲不聞傾覆人。',32,'全唐诗/poet.tang.37000.json','["涇溪石險人競懼，終歲不聞傾覆人。", "却是平流無石處，時時聞說有沈淪。"]'),
('6367b6e2-d4a1-4224-b560-8372242c49e9','題杜甫集','羅隱','唐','唐诗','tang','','[]','楚水悠悠浸楚亭，楚南天地兩無情。',32,'全唐诗/poet.tang.37000.json','["楚水悠悠浸楚亭，楚南天地兩無情。", "忍交孫武重泉下，不見時人說用兵。"]'),
('0580ca82-2c37-4b9b-bc82-82d6899b23c6','感弄猴人賜朱紱','羅隱','唐','唐诗','tang','','[]','十二三年就試期，五湖煙月奈相違。',32,'全唐诗/poet.tang.37000.json','["十二三年就試期，五湖煙月奈相違。", "何如買取胡孫弄，一笑君王便著緋。"]'),
('21aa5e67-97b1-40c1-9e74-19a3b07d3383','題磻溪垂釣圖','羅隱','唐','唐诗','tang','','["\u897f\u6e56"]','呂望當年展廟謨，直鉤釣國更誰如。',32,'全唐诗/poet.tang.37000.json','["呂望當年展廟謨，直鉤釣國更誰如。", "若教生在西湖上，也是須供使宅魚。"]'),
('f7b3ebdd-e208-4a78-ba9a-2582bb0b5411','春風','羅隱','唐','唐诗','tang','','[]','也知有意吹噓切，爭奈人間善惡分。',32,'全唐诗/poet.tang.37000.json','["也知有意吹噓切，爭奈人間善惡分。", "但是粃糠細微物，等閑擡舉到青雲。"]'),
('d308178f-d9f2-4c3e-bb2b-654142f693af','竹下殘雪','羅隱','唐','唐诗','tang','','[]','牆下濃陰對此君，小山尖險玉爲羣。',32,'全唐诗/poet.tang.37000.json','["牆下濃陰對此君，小山尖險玉爲羣。", "夜來解凍風雖急，不向寒城減一分。"]'),
('e7fc83db-33c4-465d-aedd-38e0d709d00f','杏花','羅隱','唐','唐诗','tang','','[]','暖氣潛催次第春，梅花已謝杏花新。',32,'全唐诗/poet.tang.37000.json','["暖氣潛催次第春，梅花已謝杏花新。", "半開半落閑園裏，何異榮枯世上人。"]'),
('81bd221d-5447-40f5-af88-e3756cf5f35f','鎮海軍所貢','羅隱','唐','唐诗','tang','','[]','簷前飛雪扇前塵，千里移添上苑春。',32,'全唐诗/poet.tang.37000.json','["簷前飛雪扇前塵，千里移添上苑春。", "他日丁寧柿林院，莫宣恩澤與閑人。"]'),
('151a54e2-00a6-4f9b-8811-3cff804feb3a','席上歌水調','羅隱','唐','唐诗','tang','','[]','餘聲宛宛拂庭梅，通濟渠邊去又回。',32,'全唐诗/poet.tang.37000.json','["餘聲宛宛拂庭梅，通濟渠邊去又回。", "若使煬皇魂魄在，爲君應合過江來。"]'),
('0bcca360-220b-4952-b7e8-147be14fd945','題新榜','羅隱','唐','唐诗','tang','','[]','黃土原邊狡兔肥，犬如流電馬如飛。',32,'全唐诗/poet.tang.37000.json','["黃土原邊狡兔肥，犬如流電馬如飛。", "灞陵老將無功業，猶憶當時夜獵歸。"]'),
('57a81627-e395-4593-a5f9-94db08580faf','句','羅隱','唐','唐诗','tang','','[]','夏窗七葉連陰暗。',96,'全唐诗/poet.tang.37000.json','["夏窗七葉連陰暗。", "賴家橋上潏河邊。", "細看月輪真有意，已知青桂近嫦娥。", "一箇禰衡容不得，思量黃祖謾英雄。", "張華謾出如丹語，不及劉侯一紙書。", "山雨霏微宿上亭，雨中因想雨淋鈴。", "老僧齋罷關門睡，不管波濤四面生。"]'),
('f7c2649e-94cc-40d3-94d6-f043a2f178ed','比紅兒詩 一','羅虬','唐','唐诗','tang','','[]','姓字看侵尺五天，芳菲占斷百花鮮。',32,'全唐诗/poet.tang.37000.json','["姓字看侵尺五天，芳菲占斷百花鮮。", "馬嵬好笑當時事，虛賺明皇幸蜀川。"]'),
('84f12917-909d-473b-b75d-c67f4274fe66','比紅兒詩 二','羅虬','唐','唐诗','tang','','[]','金谷園中花正繁，墜樓從道感深恩。',32,'全唐诗/poet.tang.37000.json','["金谷園中花正繁，墜樓從道感深恩。", "齊奴却是來東市，不爲紅兒死更冤。"]'),
('91baf145-703d-455e-9de4-3178a25468a5','比紅兒詩 三','羅虬','唐','唐诗','tang','','[]','陷却平陽爲小憐，周師百萬戰長川。',32,'全唐诗/poet.tang.37000.json','["陷却平陽爲小憐，周師百萬戰長川。", "更教乞與紅兒貌，舉國山川不值錢。"]'),
('5115c0b1-6faa-4af3-b838-d4bcd690ac8d','比紅兒詩 四','羅虬','唐','唐诗','tang','','[]','一曲都緣張麗華，六宮齊唱後庭花。',32,'全唐诗/poet.tang.37000.json','["一曲都緣張麗華，六宮齊唱後庭花。", "若教比竝紅兒貌，枉破當年國與家。"]'),
('3d69c475-ebef-4767-b2ee-f95f5f41c71c','比紅兒詩 五','羅虬','唐','唐诗','tang','','[]','樂營門外柳如陰，中有佳人畫閣深。',32,'全唐诗/poet.tang.37000.json','["樂營門外柳如陰，中有佳人畫閣深。", "若是五陵公子見，買時應不啻千金。"]'),
('df78dfc0-2640-476d-b3a0-fcc444c4a556','比紅兒詩 六','羅虬','唐','唐诗','tang','','[]','青絲高綰石榴裙，腸斷當筵酒半醺。',32,'全唐诗/poet.tang.37000.json','["青絲高綰石榴裙，腸斷當筵酒半醺。", "置向漢宮圖畫裏，入胡應不數昭君。"]'),
('995762fa-6cdb-4dd5-b791-4d6a5a2f84e6','比紅兒詩 七','羅虬','唐','唐诗','tang','','[]','斜凭欄杆醉態新，歛眸微盻不勝春。',32,'全唐诗/poet.tang.37000.json','["斜凭欄杆醉態新，歛眸微盻不勝春。", "當時若遇東昏主，金葉蓮花是此人。"]'),
('fe71a808-e391-4347-b14b-010a68f4bacc','比紅兒詩 八','羅虬','唐','唐诗','tang','','[]','匼匝千山與萬山，碧桃花下景長閑。',32,'全唐诗/poet.tang.37000.json','["匼匝千山與萬山，碧桃花下景長閑。", "神仙得似紅兒貌，應免劉郎憶世間。"]'),
('4d22f0d5-cfe0-49c3-9626-3303a09dd5e0','比紅兒詩 九','羅虬','唐','唐诗','tang','','[]','越山重疊越溪斜，西子休憐解浣紗。',32,'全唐诗/poet.tang.37000.json','["越山重疊越溪斜，西子休憐解浣紗。", "得似紅兒今日貌，肯教將去與夫差。"]'),
('a34eb77f-f02c-4a01-a51d-3b2f02635208','比紅兒詩 十','羅虬','唐','唐诗','tang','','[]','詔下人間覓好花，月眉雲髻選人家。',32,'全唐诗/poet.tang.37000.json','["詔下人間覓好花，月眉雲髻選人家。", "紅兒若向當時見，繫臂先封第一紗。"]'),
('6e2a0765-2acf-4fcc-a642-4471eb046e77','比紅兒詩 十一','羅虬','唐','唐诗','tang','','[]','鋒鏑縱橫不敢看，淚垂玉筯正汍瀾。',32,'全唐诗/poet.tang.37000.json','["鋒鏑縱橫不敢看，淚垂玉筯正汍瀾。", "應緣近似紅兒貌，始得深宮奉五官。"]'),
('a0c160c9-cc4c-40e1-aee2-61355cb85ee3','比紅兒詩 十二','羅虬','唐','唐诗','tang','','[]','金縷濃薰百和香，臉紅眉黛入時妝。',32,'全唐诗/poet.tang.37000.json','["金縷濃薰百和香，臉紅眉黛入時妝。", "當時便向喬家見，未敢將心在窈娘。"]'),
('8a3df723-26e1-4895-b101-992d3f60f3c2','比紅兒詩 十三','羅虬','唐','唐诗','tang','','[]','通宵甲帳散香塵，漢帝精神禮百神。',32,'全唐诗/poet.tang.37000.json','["通宵甲帳散香塵，漢帝精神禮百神。", "若見紅兒醉中態，也應休憶李夫人。"]'),
('a8f28cea-40ca-4610-8146-84fa16a9cb80','比紅兒詩 十四','羅虬','唐','唐诗','tang','','[]','拔得芙蓉出水新，魏家公子信才人。',32,'全唐诗/poet.tang.37000.json','["拔得芙蓉出水新，魏家公子信才人。", "若教瞥見紅兒貌，不肯留情付洛神。"]'),
('71094f9c-6a99-4ac2-aa15-2fe64d977b0e','比紅兒詩 十五','羅虬','唐','唐诗','tang','','[]','芳姿不合竝常人，雲在遙天玉在塵。',32,'全唐诗/poet.tang.37000.json','["芳姿不合竝常人，雲在遙天玉在塵。", "因事愛思荀奉倩，一生閑坐枉傷神。"]'),
