('1b44fbc3-93bc-4bc6-b9a7-8ca466d19e29','比紅兒詩 七十四','羅虬','唐','唐诗','tang','','[]','前代休憐事可奇，後來還出有光輝。',32,'全唐诗/poet.tang.37000.json','["前代休憐事可奇，後來還出有光輝。", "爭知晝臥紗窗裏，不見神人覆玉衣。"]'),
('96fc80c7-a798-4841-9e5c-871f58d06737','比紅兒詩 七十五','羅虬','唐','唐诗','tang','','[]','化羽嘗聞赴九天，只疑塵世是虛傳。',32,'全唐诗/poet.tang.37000.json','["化羽嘗聞赴九天，只疑塵世是虛傳。", "自從一見紅兒貌，始信人間有謫仙。"]'),
('270caa14-0611-4c73-bd14-8215fa28e39d','比紅兒詩 七十六','羅虬','唐','唐诗','tang','','[]','從道長陵小市東，巧將花貌占春風。',32,'全唐诗/poet.tang.37000.json','["從道長陵小市東，巧將花貌占春風。", "紅兒若是同時見，未必伊先入紫宮。"]'),
('40ef3ea3-22a6-461f-8a2b-a011ebf8c718','比紅兒詩 七十七','羅虬','唐','唐诗','tang','','[]','人間難免是深情，命斷紅兒向此生。',32,'全唐诗/poet.tang.37000.json','["人間難免是深情，命斷紅兒向此生。", "不似前時李丞相，枉拋才力爲鶯鶯。"]'),
('f5662a5a-00f1-4a52-82ce-9835a0a76cb5','比紅兒詩 七十八','羅虬','唐','唐诗','tang','','[]','鳳舞香飄繡幕風，暖穿馳道百花中。',32,'全唐诗/poet.tang.37000.json','["鳳舞香飄繡幕風，暖穿馳道百花中。", "還緣有似紅兒貌，始道迎將入漢宮。"]'),
('b3125e54-d800-4281-a2b2-595040e7e60b','比紅兒詩 七十九','羅虬','唐','唐诗','tang','','[]','休道將軍出世才，盡驅諸妓下歌臺。',32,'全唐诗/poet.tang.37000.json','["休道將軍出世才，盡驅諸妓下歌臺。", "都緣沒箇紅兒貌，致使輕教後閣開。"]'),
('ea6278f0-3327-43cf-882e-cf82ad2291f8','比紅兒詩 八十','羅虬','唐','唐诗','tang','','[]','馮媛須知住漢宮，將身只是解當熊。',32,'全唐诗/poet.tang.37000.json','["馮媛須知住漢宮，將身只是解當熊。", "不聞有貌傾人國，爭得今朝更似紅。"]'),
('1cf8b684-301f-4668-a0e9-4a33cc2cdd5b','比紅兒詩 八十一','羅虬','唐','唐诗','tang','','[]','能將一笑使人迷，花豔何須上大堤。',32,'全唐诗/poet.tang.37000.json','["能將一笑使人迷，花豔何須上大堤。", "疎屬便同巫峽路，洛川真是武陵溪。"]'),
('caeb49a8-5819-4799-8546-62e2ee95937d','比紅兒詩 八十二','羅虬','唐','唐诗','tang','','[]','辭輦當時意可知，寵深還恐寵先衰。',32,'全唐诗/poet.tang.37000.json','["辭輦當時意可知，寵深還恐寵先衰。", "若教得似紅兒貌，占却君恩自不疑。"]'),
('a132ad66-a7f5-4cf8-9039-501234b07c27','比紅兒詩 八十三','羅虬','唐','唐诗','tang','','[]','三吳時俗重風光，未見紅兒一面妝。',32,'全唐诗/poet.tang.37000.json','["三吳時俗重風光，未見紅兒一面妝。", "好寫妖嬈與教看，便應休更話真娘。"]'),
('68602aae-0354-44a5-8a0e-b55e9b4abd68','比紅兒詩 八十四','羅虬','唐','唐诗','tang','','[]','波平楚澤浸星辰，臺上君王宴早春。',32,'全唐诗/poet.tang.37000.json','["波平楚澤浸星辰，臺上君王宴早春。", "畢竟章華會中客，冠纓虛絕爲何人。"]'),
('74becf1f-4f55-4e40-8fd0-09c0e72ab1c7','比紅兒詩 八十五','羅虬','唐','唐诗','tang','','[]','紅兒不向漢宮生，便使雙成謾得名。',32,'全唐诗/poet.tang.37000.json','["紅兒不向漢宮生，便使雙成謾得名。", "疑是麻姑惱塵世，暫教微步下層城。"]'),
('4c9a0923-b63d-455a-9cc1-368f7e90b72b','比紅兒詩 八十六','羅虬','唐','唐诗','tang','','[]','天碧輕紗只六銖，宛如含露透肌膚。',32,'全唐诗/poet.tang.37000.json','["天碧輕紗只六銖，宛如含露透肌膚。", "便教漢曲爭明媚，應沒心情更弄珠。"]'),
('531e9264-c993-4084-a4b3-e79170015596','比紅兒詩 八十七','羅虬','唐','唐诗','tang','','[]','共嗟含恨向衡陽，方寸花牋寄沈郎。',32,'全唐诗/poet.tang.37000.json','["共嗟含恨向衡陽，方寸花牋寄沈郎。", "不似紅兒些子貌，當時爭得少年狂。"]'),
('8761ab06-216f-4fbe-8466-c98068fee128','比紅兒詩 八十八','羅虬','唐','唐诗','tang','','[]','淺色桃花亞短牆，不因風送也聞香。',32,'全唐诗/poet.tang.37000.json','["淺色桃花亞短牆，不因風送也聞香。", "凝情盡日君知否，還似紅兒淡薄妝。"]'),
('77499824-5ddf-4770-a8b8-8b672e085fe6','比紅兒詩 八十九','羅虬','唐','唐诗','tang','','[]','火色櫻桃摘得初，仙宮只有世間無。',32,'全唐诗/poet.tang.37000.json','["火色櫻桃摘得初，仙宮只有世間無。", "凝情盡日君知否，真似紅兒口上朱。"]'),
('ca1b9c5f-e95d-4d6c-9558-1d00e4c7c7e3','比紅兒詩 九十','羅虬','唐','唐诗','tang','','[]','宿雨初晴春日長，入簾花氣靜難忘。',32,'全唐诗/poet.tang.37000.json','["宿雨初晴春日長，入簾花氣靜難忘。", "凝情盡日君知否，真似紅兒舞袖香。"]'),
('0a695742-0317-47a5-99b4-c7cc028a3d94','比紅兒詩 九十一','羅虬','唐','唐诗','tang','','[]','初月纖纖映碧池，池波不動獨看時。',32,'全唐诗/poet.tang.37000.json','["初月纖纖映碧池，池波不動獨看時。", "凝情盡日君知否，真似紅兒罷舞眉。"]'),
('7f579f6a-a7aa-435f-bdb2-bfa4cd421587','比紅兒詩 九十二','羅虬','唐','唐诗','tang','','[]','濃豔濃香雪壓枝，褭煙和露曉風吹。',32,'全唐诗/poet.tang.37000.json','["濃豔濃香雪壓枝，褭煙和露曉風吹。", "紅兒被掩妝成後，含笑無人獨立時。"]'),
('ceff3574-8f5e-49c1-a037-29e15bf87d54','比紅兒詩 九十三','羅虬','唐','唐诗','tang','','[]','樓上嬌歌褭夜霜，近來休數踏歌娘。',32,'全唐诗/poet.tang.37000.json','["樓上嬌歌褭夜霜，近來休數踏歌娘。", "紅兒謾唱伊州遍，認取輕敲玉韻長。"]'),
('e3e0be92-8f86-4b4d-b95c-1cb17d15eb77','比紅兒詩 九十四','羅虬','唐','唐诗','tang','','[]','金粟妝成扼臂環，舞腰輕薄瑞雲間。',32,'全唐诗/poet.tang.37000.json','["金粟妝成扼臂環，舞腰輕薄瑞雲間。", "紅兒生在開元末，羞殺新豐謝阿蠻。"]'),
('c6468afd-ebea-42a5-8cc3-a767699ea31e','比紅兒詩 九十五','羅虬','唐','唐诗','tang','','[]','君看紅兒學醉妝，誇裁宮襭砑裙長。',32,'全唐诗/poet.tang.37000.json','["君看紅兒學醉妝，誇裁宮襭砑裙長。", "誰能更把閑心力，比竝當時武媚娘。"]'),
('d46b6a56-03a6-4c4d-8215-5f52e02caab4','比紅兒詩 九十六','羅虬','唐','唐诗','tang','','[]','梔子同心裛露垂，折來深恐沒人知。',32,'全唐诗/poet.tang.37000.json','["梔子同心裛露垂，折來深恐沒人知。", "花前醉客頻相問，不贈紅兒贈阿誰。"]'),
('84413e00-9309-4525-a6ad-667060ae69e2','比紅兒詩 九十七','羅虬','唐','唐诗','tang','','[]','雲間翡翠一雙飛，水上鴛鴦不暫離。',32,'全唐诗/poet.tang.37000.json','["雲間翡翠一雙飛，水上鴛鴦不暫離。", "寫向人間百般態，與君題作比紅詩。"]'),
('ea19a565-d34a-459a-b5f0-46a40c89078e','比紅兒詩 九十八','羅虬','唐','唐诗','tang','','[]','舊恨長懷不語中，幾回偷泣向春風。',32,'全唐诗/poet.tang.37000.json','["舊恨長懷不語中，幾回偷泣向春風。", "還緣不及紅兒貌，却得生教入楚宮。"]'),
('d1cde0ca-ca8b-4752-9a84-7a476dfa041e','比紅兒詩 九十九','羅虬','唐','唐诗','tang','','[]','一舸春深指鄂君，好風從度水成紋。',32,'全唐诗/poet.tang.37000.json','["一舸春深指鄂君，好風從度水成紋。", "越人若見紅兒貌，繡被應羞徹夜薰。"]'),
('76a06d68-949a-4fa1-b742-0eeb039e197a','比紅兒詩 一百','羅虬','唐','唐诗','tang','','[]','花落塵中玉墮泥，香魂應上窈娘堤。',32,'全唐诗/poet.tang.37000.json','["花落塵中玉墮泥，香魂應上窈娘堤。", "欲知此恨無窮處，長倩城烏夜夜啼。"]'),
('b59ebaa7-8bae-4973-a57a-e032b22a2e74','句','羅虬','唐','唐诗','tang','','[]','窗前遠岫懸生碧，簾外殘霞挂熟紅。',16,'全唐诗/poet.tang.37000.json','["窗前遠岫懸生碧，簾外殘霞挂熟紅。"]'),
('00702981-1884-4b20-99fc-354e8ced4aa0','星精亭','鄭損','唐','唐诗','tang','','[]','星沈萬古痕，孤絕勢無鄰。',48,'全唐诗/poet.tang.37000.json','["星沈萬古痕，孤絕勢無鄰。", "地窄少留竹，空多剩占雲。", "釣篷和雨看，樵斧帶霜聞。", "莫惜尋常到，清風不負人。"]'),
('f57365ae-b81f-4729-ac92-8b9da3ebf708','釣閣','鄭損','唐','唐诗','tang','','[]','小閣愜幽尋，周遭萬竹森。',48,'全唐诗/poet.tang.37000.json','["小閣愜幽尋，周遭萬竹森。", "誰知一沼內，亦有五湖心。", "釣直魚應笑，身閑樂自深。", "晚來春醉熟，香餌任浮沈。"]'),
('30f95f18-fa3a-4bb9-8a75-61744687a5f1','玉聲亭','鄭損','唐','唐诗','tang','','[]','世間泉石本無價，那更天然落景中。',64,'全唐诗/poet.tang.37000.json','["世間泉石本無價，那更天然落景中。", "漢佩琮琤寒溜雨，秦簫縹緲夜敲風。", "一方清氣羣陰伏，半局閑棋萬慮空。", "借問主人能住久，後來好事有誰同。"]'),
('5efaec0e-670b-4f46-89a6-214d5cf06f5b','藝堂','鄭損','唐','唐诗','tang','','[]','堂開凍石千年翠，藝講秋膠百步威。',64,'全唐诗/poet.tang.37000.json','["堂開凍石千年翠，藝講秋膠百步威。", "揖讓未能忘典禮，英雄孰不慣戎衣。", "風波險似金機駭，日月忙如雪羽飛。", "莫怪尊前頻浩歎，男兒志願與時違。"]'),
('85edeea7-a75d-43df-aebd-b92720f096ee','星精石','鄭損','唐','唐诗','tang','','[]','突險呀空龍虎蹲，由來英氣蓄寒根。',64,'全唐诗/poet.tang.37000.json','["突險呀空龍虎蹲，由來英氣蓄寒根。", "蒼苔點染雲生靨，老雨淋漓鐵漬痕。", "松韻遠趨疑認祖，山陰輕覆似憐孫。", "孤巖恰恰容幽搆，可愛江南釋子園。"]'),
('bdca155c-6b4e-493f-8e12-f9705df9e1eb','泛香亭','鄭損','唐','唐诗','tang','','[]','流杯處處稱佳致，何似斯亭出自然。',64,'全唐诗/poet.tang.37000.json','["流杯處處稱佳致，何似斯亭出自然。", "山溜穿雲來幾里，石盤和蘚鑿何年。", "聲交鳴玉歌沈板，色幌寒金酒滿船。", "莫怪坐中難得醉，醒人心骨有潺湲。"]'),
('d7ef9625-cf5a-4a58-a217-26c26733f917','巴州寒食晚眺','張禕','唐','唐诗','tang','','[]','東望青天周與秦，杏花榆葉故園春。',32,'全唐诗/poet.tang.37000.json','["東望青天周與秦，杏花榆葉故園春。", "野寺一傾寒食酒，晚來風景重愁人。"]'),
('8493466b-7eb6-4de2-8143-12786a652f70','題擊甌樓','張禕','唐','唐诗','tang','','[]','駐旌元師遺風在，擊缶高人逸興酣。',32,'全唐诗/poet.tang.37000.json','["駐旌元師遺風在，擊缶高人逸興酣。", "水轉巴文清溜急，山連蒙岫翠光涵。"]'),
('6107fb38-ce0c-497c-a35f-ac7d24961f84','題司空圖壁','盧攜','唐','唐诗','tang','','[]','姓氏司空貴，官班御史卑。',24,'全唐诗/poet.tang.37000.json','["姓氏司空貴，官班御史卑。", "老夫如且在，不用歎屯奇。"]'),
('d7ce5740-8899-4cc1-ae6b-7aad23851365','愁詩','李廷璧','唐','唐诗','tang','','[]','到來難遣去難留，著骨黏心萬事休。',64,'全唐诗/poet.tang.37000.json','["到來難遣去難留，著骨黏心萬事休。", "潘岳愁絲生鬢裏，婕妤悲色上眉頭。", "長途詩盡空騎馬，遠雁聲初獨倚樓。", "更有相思不相見，酒醒燈背月如鉤。"]'),
('4b2492bf-0268-4378-9572-b1d9991e930b','題菖蒲廢觀','許三畏','唐','唐诗','tang','','[]','本是安期燒藥處，今來改作坐禪宮。',64,'全唐诗/poet.tang.37000.json','["本是安期燒藥處，今來改作坐禪宮。", "數僧梵響滿樓月，深谷猨聲半夜風。", "金簡事移松閣逈，綵雲影散閬山空。", "我來不見修真客，却得真如問遠公。"]'),
('6f709530-f1bd-452c-af6d-eb87040360ab','致孫狀元訴醵罰錢','盧嗣業','唐','唐诗','tang','','[]','未識都君面，頻輸復分錢。',48,'全唐诗/poet.tang.37000.json','["未識都君面，頻輸復分錢。", "苦心事筆硯，得志助花鈿。", "徒步求秋賦，持杯給暮饘。", "力微多謝病，非不奉同年。"]'),
('e4962c05-fe08-4951-a08c-d92d4b36600e','紅薔薇','牛嶠','唐','唐诗','tang','','[]','曉啼珠露渾無力，繡簇羅襦不著行。',32,'全唐诗/poet.tang.37000.json','["曉啼珠露渾無力，繡簇羅襦不著行。", "若綴壽陽公主額，六宮爭肯學梅妝。"]'),
('92867325-bf68-467d-955c-7d786fd1f323','楊柳枝五首 一','牛嶠','唐','唐诗','tang','','["\u5bd3\u4eba", "\u540c\u60c5", "\u548f\u7269", "\u67f3\u6811", "\u548f\u7269\u8bd7"]','解凍風來末上青，解垂羅袖拜卿卿。',32,'全唐诗/poet.tang.37000.json','["解凍風來末上青，解垂羅袖拜卿卿。", "無端褭娜臨官路，舞送行人過一生。"]'),
('76816c38-6228-4031-987d-c51b7ae83754','楊柳枝五首 二','牛嶠','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u67f3\u6811", "\u548f\u7269\u8bd7"]','吳王宮裏色偏深，一簇纖條萬縷金。',32,'全唐诗/poet.tang.37000.json','["吳王宮裏色偏深，一簇纖條萬縷金。", "不憤錢塘蘇小小，引郎松下結同心。"]'),
('18b8df01-9b32-498d-9bac-a846ffd84ba2','楊柳枝五首 三','牛嶠','唐','唐诗','tang','','[]','橋北橋南千萬條，恨伊張緒不相饒。',32,'全唐诗/poet.tang.37000.json','["橋北橋南千萬條，恨伊張緒不相饒。", "金羈白馬臨風望，認得羊家靜婉腰。"]'),
('6ec5727e-4722-4438-af80-5b74d4ef8a2a','楊柳枝五首 四','牛嶠','唐','唐诗','tang','','[]','狂雪隨風撲馬飛，惹煙無力被春欺。',32,'全唐诗/poet.tang.37000.json','["狂雪隨風撲馬飛，惹煙無力被春欺。", "莫交移入靈和殿，宮女三千又妬伊。"]'),
('b6de0bcf-3042-4e60-a4c8-a5a349addcaf','楊柳枝五首 五','牛嶠','唐','唐诗','tang','','[]','褭翠籠煙拂暖波，舞裙新染麴塵羅。',32,'全唐诗/poet.tang.37000.json','["褭翠籠煙拂暖波，舞裙新染麴塵羅。", "章華臺畔隋堤上，傍得春風爾許多。"]'),
('db0a1e37-c624-4b33-ad24-94398d599802','及第後宿平康里詩','鄭合','唐','唐诗','tang','','[]','春來無處不閑行，楚潤相看別有情。',32,'全唐诗/poet.tang.37000.json','["春來無處不閑行，楚潤相看別有情。", "好是五更殘酒醒，時時聞喚狀頭聲。"]'),
('83f5d2a2-8465-4c96-8cf5-1e24ddc1e90b','賀裴廷裕蜀中登第詩','李搏','唐','唐诗','tang','','[]','銅梁千里曙雲開，仙籙新從紫府來。',64,'全唐诗/poet.tang.37000.json','["銅梁千里曙雲開，仙籙新從紫府來。", "天上已張新羽翼，世間無復舊塵埃。", "嘉禎果中君平卜，賀喜須斟卓氏杯。", "應笑戎藩刀筆吏，至今泥滓曝魚鰓。"]'),
('d1dcabfb-6314-4406-a45f-4162149e5977','復謔廷裕','李搏','唐','唐诗','tang','','[]','曾隨風水化凡鱗，安上門前一字新。',32,'全唐诗/poet.tang.37000.json','["曾隨風水化凡鱗，安上門前一字新。", "聞道蜀江風景好，不知何似杏園春。"]'),
('0e5447e5-dc6e-4519-bee1-09481b758b9a','弔賈島','李克恭','唐','唐诗','tang','','[]','一一玄微縹緲成，盡吟方便爽神情。',64,'全唐诗/poet.tang.37000.json','["一一玄微縹緲成，盡吟方便爽神情。", "宣宗謫去爲閑事，韓愈知來已振名。", "海底也應搜得淨，月輪常被翫教傾。", "如何未隔四十載，不遇論量向此生。"]'),
('5bbdfa76-fd12-449f-963f-d99ff6c24bec','君山','程賀','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5199\u5c71", "\u60f3\u8c61", "\u63cf\u5199\u5c71"]','曾游方外見麻姑，說道君山此本無。',32,'全唐诗/poet.tang.37000.json','["曾游方外見麻姑，說道君山此本無。", "云是崑崙山頂石，海風吹落洞庭湖。"]'),
('ab1178b9-4801-40c5-a563-b9114e399f0e','東歸詩','盧尚卿','唐','唐诗','tang','','[]','九重丹詔下塵埃，深鎖文闈罷選才。',64,'全唐诗/poet.tang.37000.json','["九重丹詔下塵埃，深鎖文闈罷選才。", "桂樹放教遮月長，杏園終待隔年開。", "自從玉帳論兵後，不許金門諫獵來。", "今日灞陵橋上過，路人應笑臘前迴。"]'),
('a3094805-6555-451f-a470-cc323adbcc47','題玉芝雙奉院','顧在鎔','唐','唐诗','tang','','[]','入門如洞府，花木與時稀。',48,'全唐诗/poet.tang.37000.json','["入門如洞府，花木與時稀。", "夜坐山當戶，秋吟葉滿衣。", "犬隨童子出，鳥避俗人飛。", "至藥應將熟，年年火氣微。"]'),
('5c03b5b7-c53d-4da6-90d2-4552f40a24e8','宿麻平驛','顧在鎔','唐','唐诗','tang','','[]','及到怡情處，暫忘登陟勞。',48,'全唐诗/poet.tang.37000.json','["及到怡情處，暫忘登陟勞。", "青山看不厭，明月坐來高。", "犬爲孤村吠，猨因冷木號。", "微吟還獨酌，多興憶同袍。"]'),
('8051063e-2f72-4ec8-b708-5fe6e91796d4','題光福上方塔','顧在鎔','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蒼島孤生白浪中，倚天高塔勢翻空。',64,'全唐诗/poet.tang.37000.json','["蒼島孤生白浪中，倚天高塔勢翻空。", "煙凝遠岫列寒翠，霜染疎林墮碎紅。", "汀沼或栖彭澤雁，樓臺深貯洞庭風。", "六時金磬落何處，偏傍蘆葦驚釣翁。"]'),
('7d9187f6-5ce1-4d0d-8c64-89a78062aefe','枯木詩辭召命作','翁洮','唐','唐诗','tang','','[]','枯木傍溪崖，由來歲月賒。',48,'全唐诗/poet.tang.37000.json','["枯木傍溪崖，由來歲月賒。", "有根盤水石，無葉接煙霞。", "二月苔爲色，三冬雪作花。", "不因星使至，誰識是靈槎。"]'),
('0f55ae53-5d28-4ed4-903f-722e4a8f3d2f','贈進士王雄','翁洮','唐','唐诗','tang','','[]','河清海晏少波濤，幾載垂鉤不得鰲。',64,'全唐诗/poet.tang.37000.json','["河清海晏少波濤，幾載垂鉤不得鰲。", "空向人間修諫草，又來江上詠離騷。", "笳吹古堞邊聲遠，嶽倚晴空楚色高。", "何事明廷有徐庶，總教三徑臥蓬蒿。"]'),
('8586f5d9-1996-4180-b4ad-1c5ff27b6f31','漁者','翁洮','唐','唐诗','tang','','[]','一葉飄然任浪吹，雨蓑煙笠肯忘機。',64,'全唐诗/poet.tang.37000.json','["一葉飄然任浪吹，雨蓑煙笠肯忘機。", "只貪濁水張羅衆，却笑清流把釣稀。", "葦岸夜依明月宿，柴門晴櫂白雲歸。", "到頭得喪終須達，誰道漁樵有是非。"]'),
('331c965b-59bc-4aa1-9d92-ffeae5363c43','上子男壽昌宰','翁洮','唐','唐诗','tang','','[]','陶公爲政卓潘齊，入縣看花柳滿堤。',64,'全唐诗/poet.tang.37000.json','["陶公爲政卓潘齊，入縣看花柳滿堤。", "百里江山聊展驥，九臯雲月怪驅雞。", "高樓野色迎襟袖，比屋歌聲遠鼓鼙。", "只恐攀轅留不住，明時霄漢有丹梯。"]'),
('51845837-bc79-4637-83ab-3b1b01b1c439','贈方干先生','翁洮','唐','唐诗','tang','','[]','由來箕踞任天真，別有詩名出世塵。',64,'全唐诗/poet.tang.37000.json','["由來箕踞任天真，別有詩名出世塵。", "不愛春宮分桂樹，欲教天子枉蒲輪。", "城頭鼙鼓三聲曉，島外湖山一簇春。", "獨向若耶溪上住，誰知不是釣鰲人。"]'),
('f5f8aec8-f9c4-42c3-9231-a2bcaac4bfc6','贈進士李德新接海棠梨','翁洮','唐','唐诗','tang','','[]','蜀人猶說種難成，何事江東見接生。',64,'全唐诗/poet.tang.37000.json','["蜀人猶說種難成，何事江東見接生。", "席上若微桃李伴，花中堪作牡丹兄。", "高軒日午爭濃豔，小徑風移旋落英。", "一種呈妍今得地，劒峯梨嶺謾縱橫。"]'),
('7ed1a442-e3f4-4e4e-90e0-5d0a486d411f','春日題航頭橋','翁洮','唐','唐诗','tang','','[]','故園橋上絕埃塵，此日凭欄興自新。',64,'全唐诗/poet.tang.37000.json','["故園橋上絕埃塵，此日凭欄興自新。", "雲影晚將仙掌曙，水光迷得武陵春。", "薜蘿煙裏高低路，楊柳風前去住人。", "莫怪馬卿題姓字，終朝雲雨化龍津。"]'),
('f3a039c3-7a33-47de-9d8a-f3588903567b','和方干題李頻莊','翁洮','唐','唐诗','tang','','[]','高情度日非無事，自是高情不覺喧。',96,'全唐诗/poet.tang.37000.json','["高情度日非無事，自是高情不覺喧。", "海氣暗蒸蓮葉沼，山光晴逗葦花村。", "吟時勝概題詩板，靜處繁華付酒尊。", "閑伴白雲收桂子，每尋流水斸桐孫。", "猶憑律呂傳心曲，豈慮星霜到鬢根。", "多少清風歸此地，十年虛打五侯門。"]'),
('a6adad82-5424-4c5f-be8c-b633dc7e97d5','葦藂','翁洮','唐','唐诗','tang','','[]','得地自成藂，那因種植功。',48,'全唐诗/poet.tang.37000.json','["得地自成藂，那因種植功。", "有花皆吐雪，無韻不含風。", "倒影翹沙鳥，幽根立水蟲。", "蕭蕭寒雨夜，江漢思無窮。"]'),
('ed8d28d3-de97-4fce-a400-ec9e614e439f','春','翁洮','唐','唐诗','tang','','[]','漠漠煙花處處通，游人南北思無窮。',64,'全唐诗/poet.tang.37000.json','["漠漠煙花處處通，游人南北思無窮。", "林間鳥奏笙簧月，野外花含錦繡風。", "鸑抱雲霞朝鳳闕，魚翻波浪化龍宮。", "此時誰羨神仙客，車馬悠揚九陌中。"]'),
('2ce6a1a5-02fe-466a-ac43-a51527287265','夏','翁洮','唐','唐诗','tang','','[]','觸目皆因長養功，浮生何處問窮通？',64,'全唐诗/poet.tang.37000.json','["觸目皆因長養功，浮生何處問窮通？", "柳長北闕絲千縷，雲簇南山火萬籠。", "大野煙塵飄赫日，高樓簾幕逗薰風。", "身心已在喧闐處，惟羨滄浪把釣翁。"]'),
('9d188839-d47a-4360-abe1-d55bca5d58ce','秋','翁洮','唐','唐诗','tang','','[]','宋玉高吟思萬重，澄澄寰宇振金風。',64,'全唐诗/poet.tang.37000.json','["宋玉高吟思萬重，澄澄寰宇振金風。", "雲閑日月浮虛白，木落山川疊碎紅。", "寥泬鴈多宮漏永，河渠煙歛塞天空。", "侯門處處槐花□，獻賦何時遇至公。"]'),
('c2ff1d77-9e5f-43de-8784-aa75a6593df9','冬','翁洮','唐','唐诗','tang','','[]','寂寂棲心向杳冥，苦吟寒律句偏清。',64,'全唐诗/poet.tang.37000.json','["寂寂棲心向杳冥，苦吟寒律句偏清。", "雲凝止水魚龍蟄，雪點遙峰草木榮。", "迥夜爐飜埃燼色，天河冰輾轆轤聲。", "歸飛未得東風力，魂斷三山九萬程。"]'),
('9c1728cc-0e6c-4d66-a1e2-883b1d75033f','過洞庭','李嶼','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','浩渺注橫流，千潭合萬湫。',120,'全唐诗/poet.tang.37000.json','["浩渺注橫流，千潭合萬湫。", "半洪侵楚翼，一汊屬吳頭。", "動軸當新霽，漫空正仲秋。", "勢翻荆口迮，聲擁岳陽浮。", "遠脈滋衡岳，微涼散橘州。", "星辰連影動，嵐翠逐隅收。", "漸落分行鴈，旋添趁伴舟。", "昇騰人莫測，安穩路何憂。", "氣與塵中別，言堪象外搜。", "此身如麤了，來把一竿休。"]'),
('6c9a41be-b656-4039-9c12-ce4831a89af2','嚴塘經亂書事 一','鄭啓','唐','唐诗','tang','','[]','塵生宮闕霧濛濛，萬騎龍飛幸蜀中。',64,'全唐诗/poet.tang.37000.json','["塵生宮闕霧濛濛，萬騎龍飛幸蜀中。", "在野傅巖君不夢，乘軒衛懿鶴何功。", "雖知四海同盟久，未合中原武備空。", "星落夜原妖氣滿，漢家麟閣待英雄。"]'),
('71a1b07a-9d7b-4836-827b-c8bca9b632fa','嚴塘經亂書事 二','鄭啓','唐','唐诗','tang','','[]','梁園皓色月如珪，清景傷時一慘悽。',64,'全唐诗/poet.tang.37000.json','["梁園皓色月如珪，清景傷時一慘悽。", "未見山前歸牧馬，猶聞江上帶征鞞。", "鯤爲魚隊潛鱗困，鶴處雞羣病翅低。", "正是四郊多壘日，波濤早晚靜鯨鯢。"]'),
('89b95f3e-8e85-4fda-adbd-d1117b6965cb','鄧表山','鄭啓','唐','唐诗','tang','','[]','白日三清此上時，觀開山下彩雲飛。',64,'全唐诗/poet.tang.37000.json','["白日三清此上時，觀開山下彩雲飛。", "仙壇丹竈靈猶在，鶴駕清朝去不歸。", "晉末幾遷陵谷改，塵中空換子孫非。", "松花落盡無消息，半夜疎鐘徹翠微。"]'),
('22894c84-391f-4669-b30f-e217992ae08e','記知聞近過關試','韓儀','唐','唐诗','tang','','[]','短行軸了付三銓，休把新銜惱必先。',32,'全唐诗/poet.tang.37000.json','["短行軸了付三銓，休把新銜惱必先。", "今日便稱前進士，好留春色與明年。"]'),
('6a4441fd-6d97-4b68-adc6-44629320aba9','郊居','溫憲','唐','唐诗','tang','','[]','村前村後樹，寓賞有餘情。',48,'全唐诗/poet.tang.37000.json','["村前村後樹，寓賞有餘情。", "青麥路初斷，紫花田未耕。", "雉聲聞不到，山勢望猶橫。", "寂寞春風裏，吟酣信馬行。"]'),
('ae1dfd31-369e-4515-91bd-4d626927e249','杏花','溫憲','唐','唐诗','tang','','[]','團雪上晴梢，紅明映碧寥。',48,'全唐诗/poet.tang.37000.json','["團雪上晴梢，紅明映碧寥。", "店香風起夜，村白雨休朝。", "靜落猶和蒂，繁開正蔽條。", "澹然閑賞久，無以破妖嬈。"]'),
('e5dd2d18-290a-4d3d-8d07-9f098010265c','春鳩','溫憲','唐','唐诗','tang','','[]','村南微雨新，平綠淨無塵。',48,'全唐诗/poet.tang.37000.json','["村南微雨新，平綠淨無塵。", "散睡桑條暖，閑鳴屋脊春。", "遠聞和曉夢，相應在諸鄰。", "行樂花時節，追飛見亦頻。"]'),
('f0acff8f-d317-481f-9171-0e5af78fb0eb','題崇[慶]寺壁','溫憲','唐','唐诗','tang','','[]','十口溝隍待一身，半年千里絕音塵。',32,'全唐诗/poet.tang.37000.json','["十口溝隍待一身，半年千里絕音塵。", "鬢毛如雪心如死，猶作長安下第人。"]'),
('07fdd1ab-cc77-4f53-9a17-72227553dd4b','報顏標','姚巖傑','唐','唐诗','tang','','[]','爲報顏公識我麽，我心唯只與天和。',64,'全唐诗/poet.tang.37000.json','["爲報顏公識我麽，我心唯只與天和。", "眼前俗物關情少，醉後青山入意多。", "田子莫嫌彈鋏恨，甯生休唱飯牛歌。", "聖朝若爲蒼生計，也合公車到薜蘿。"]'),
('1bca184d-6c69-4b97-9a35-0f623fd24c7f','途中除夜','高蟾','唐','唐诗','tang','','[]','南北浮萍跡，年華又暗催。',48,'全唐诗/poet.tang.37000.json','["南北浮萍跡，年華又暗催。", "殘燈和臘盡，曉角帶春來。", "鬢欲漸侵雪，心仍未肯灰。", "金門舊知己，誰爲脫塵埃。"]'),
('d44d502a-a382-4cef-a1e6-f5b33cac5b96','長門怨','高蟾','唐','唐诗','tang','','[]','天上何勞萬古春，君前誰是百年人。',64,'全唐诗/poet.tang.37000.json','["天上何勞萬古春，君前誰是百年人。", "魂銷尚媿金爐燼，思起猶慚玉輦塵。", "煙翠薄情攀不得，星茫浮豔採無因。", "可憐明鏡來相向，何似恩光朝夕新。"]'),
('2197d236-c16e-4a75-a660-2c7780cb300f','秋日寄華陽山人','高蟾','唐','唐诗','tang','','[]','雲木送秋何草草，風波凝冷太星星。',64,'全唐诗/poet.tang.37000.json','["雲木送秋何草草，風波凝冷太星星。", "銀鞍公子魂俱斷，玉弩將軍涕自零。", "茅洞白龍和雨看，荆溪黃鵠帶霜聽。", "人間不見清涼事，猶向溪翁乞畫屏。"]'),
('92c0dd73-f97e-4f43-891e-a967999ad165','感事','高蟾','唐','唐诗','tang','','[]','濁河從北下，清洛向東流。',24,'全唐诗/poet.tang.37000.json','["濁河從北下，清洛向東流。", "清濁皆如此，何人不白頭。"]'),
('a2e5aab3-bbc2-4798-b0ba-b5216b876b8e','楚思','高蟾','唐','唐诗','tang','','[]','疊浪與雲急，翠蘭和意香。',24,'全唐诗/poet.tang.37000.json','["疊浪與雲急，翠蘭和意香。", "風流化爲雨，日暮下巫陽。"]'),
('aab241c1-d2c1-4b41-93de-2d0cb836ddca','雪中','高蟾','唐','唐诗','tang','','[]','金閣倚雲開，朱軒犯雪來。',24,'全唐诗/poet.tang.37000.json','["金閣倚雲開，朱軒犯雪來。", "三冬辛苦樣，天意似難栽。"]'),
('70fe0f04-4d35-45a7-a073-867a9e9637d0','道中有感','高蟾','唐','唐诗','tang','','[]','一醉六十日，一裘三十年。',24,'全唐诗/poet.tang.37000.json','["一醉六十日，一裘三十年。", "年華經幾日，日日掉征鞭。"]'),
('14fa23f3-b153-4fe8-a81c-9b2d9c03aed3','宋汴道中','高蟾','唐','唐诗','tang','','[]','平野有千里，居人無一家。',24,'全唐诗/poet.tang.37000.json','["平野有千里，居人無一家。", "甲兵年正少，日久戍天涯。"]'),
('87d581ed-c9d5-45ff-952e-7b4caf58467e','秋思','高蟾','唐','唐诗','tang','','[]','天地太蕭索，山川何渺茫。',24,'全唐诗/poet.tang.37000.json','["天地太蕭索，山川何渺茫。", "不堪星斗柄，猶把歲寒量。"]'),
('953e28d5-8c81-432f-89df-8d7cc5d8551a','即事','高蟾','唐','唐诗','tang','','[]','三年離水石，一旦隱樵漁。',24,'全唐诗/poet.tang.37000.json','["三年離水石，一旦隱樵漁。", "爲問青雲上，何人識卷舒。"]'),
('85db3f0f-f024-4c24-8b23-53933b7ad63c','漁家','高蟾','唐','唐诗','tang','','[]','野水千年在，閑花一夕空。',24,'全唐诗/poet.tang.37000.json','["野水千年在，閑花一夕空。", "近來浮世狹，何似釣船中。"]'),
('62640e8b-b6ad-4a1d-96b4-2068dbf4d54a','關中','高蟾','唐','唐诗','tang','','[]','風雨去愁晚，關河歸思涼。',24,'全唐诗/poet.tang.37000.json','["風雨去愁晚，關河歸思涼。", "西遊無紫氣，一夕九回腸。"]'),
('52b24c41-55a3-48f7-8141-ea4dd4d543fb','歸思','高蟾','唐','唐诗','tang','','[]','紫府歸期斷，芳洲別思迢。',24,'全唐诗/poet.tang.37000.json','["紫府歸期斷，芳洲別思迢。", "黃金作人世，只被歲寒消。"]'),
('e8a7617b-77d6-464c-a1f4-5f5e54a9871e','下第出春明門','高蟾','唐','唐诗','tang','','[]','曾和秋雨驅愁入，却向春風領恨回。',32,'全唐诗/poet.tang.37000.json','["曾和秋雨驅愁入，却向春風領恨回。", "深謝灞陵隄畔柳，與人頭上拂塵埃。"]'),
('ddda623c-47eb-48b7-994e-0c41299c9d6c','華清宮','高蟾','唐','唐诗','tang','','[]','何事金輿不再遊，翠鬟丹臉豈勝愁。',32,'全唐诗/poet.tang.37000.json','["何事金輿不再遊，翠鬟丹臉豈勝愁。", "重門深鎖禁鐘後，月滿驪山宮樹秋。"]'),
('4dace744-e384-4b9d-872d-74d44b45d591','秋日北固晚望二首 一','高蟾','唐','唐诗','tang','','[]','風含遠思翛翛晚，日照高情的的秋。',32,'全唐诗/poet.tang.37000.json','["風含遠思翛翛晚，日照高情的的秋。", "何事滿江惆悵水，年年無語向東流。"]');
